import Foundation

// CGRC question bank – 750 items
// Weighted to the ISC2 CGRC exam outline (effective 2024-06-15); scenario-based to match the exam style.
let BANK: [Question] = [

    // MARK: – Domain 1: Information Security Risk Management Program (16%)
    Question(id: 0, domain: 1, text: "A security engineer must select the specific controls to protect a new system. Which NIST publication is the control catalog they consult?", options: ["NIST SP 800-53", "NIST SP 800-37", "NIST SP 800-30", "NIST SP 800-60"], answer: 0, explain: "SP 800-53 is the control catalog. 800-37 is the RMF process, 800-30 is risk assessment guidance, 800-60 maps information types to impact."),
    Question(id: 1, domain: 1, text: "In governance, risk, and compliance, what does 'governance' primarily establish?", options: ["Direction, oversight, and accountability for security", "The detailed technical configuration of the security controls", "The recurring schedule for the system's vulnerability scans", "The complete list of the system's accepted residual risks"], answer: 0, explain: "Governance sets strategic direction, oversight, roles, and accountability so security/privacy align with business goals."),
    Question(id: 2, domain: 1, text: "A newly appointed federal CISO must stand up an agency-wide information security program. Which law mandates this requirement?", options: ["HIPAA", "GDPR", "FISMA", "PCI-DSS"], answer: 2, explain: "FISMA (Federal Information Security Modernization Act) mandates agency-wide information security programs."),
    Question(id: 3, domain: 1, text: "A ransomware attack encrypts an agency's case files, blocking staff from accessing them. Which CIA triad objective is MOST directly impacted?", options: ["Availability", "Confidentiality", "Integrity", "Non-repudiation"], answer: 0, explain: "Availability ensures timely, reliable access to information. Ransomware that blocks access directly attacks availability, even though confidentiality and integrity may also be threatened."),
    Question(id: 4, domain: 1, text: "An enterprise wants an IT governance and management framework developed by ISACA to align IT with business objectives. Which framework fits?", options: ["COBIT", "FedRAMP", "FIPS 199", "NIST CSF"], answer: 0, explain: "COBIT (Control Objectives for Information and Related Technology) is ISACA's IT governance framework."),
    Question(id: 6, domain: 1, text: "FedRAMP primarily governs the security authorization of:", options: ["Medical devices", "Payment card terminals", "Cloud products and services used by federal agencies", "Industrial control systems"], answer: 2, explain: "FedRAMP standardizes security assessment and authorization for cloud services used by the U.S. government."),
    Question(id: 7, domain: 1, text: "A U.S. company begins processing the personal data of customers located in the European Union. Which regulation governs protection of that data?", options: ["HIPAA", "SOX", "GLBA", "GDPR"], answer: 3, explain: "The General Data Protection Regulation (GDPR) governs personal data protection in the EU."),
    Question(id: 8, domain: 1, text: "An agency is permanently retiring a system and sanitizing its stored data. Which SDLC phase is the system in?", options: ["Disposal", "Development", "Operations & maintenance", "Design"], answer: 0, explain: "Disposal (decommissioning) covers removal from operation and sanitization/destruction of data and media."),
    Question(id: 9, domain: 1, text: "PCI-DSS applies to organizations that:", options: ["Handle protected health information", "Process, store, or transmit payment card data", "Operate cloud services for the government", "Manage classified national security systems"], answer: 1, explain: "PCI-DSS sets requirements for any entity handling cardholder data."),
    Question(id: 100, domain: 1, text: "An agency CISO is designing an organization-wide risk management strategy. According to NIST SP 800-39, risk management should be implemented at:", options: ["All three tiers: organization, mission, and system", "Only at the individual information system level itself", "Only at the mission and the business process level alone", "Only at the outer network perimeter defense layer level"], answer: 0, explain: "SP 800-39 describes a three-tiered risk management hierarchy: Tier 1 (organization), Tier 2 (mission/business process), Tier 3 (information system)."),
    Question(id: 101, domain: 1, text: "A senior manager asks why the organization should follow the NIST RMF rather than just purchasing a security product. The best response is:", options: ["The RMF is mandated for every organization by federal law", "The RMF guarantees that the organization will suffer zero breaches", "A structured, repeatable process that integrates security into the SDLC", "The RMF removes the need to perform any security control assessments at all"], answer: 2, explain: "The RMF integrates security/privacy into the SDLC, promotes risk-informed decisions, and provides structure for sustained compliance."),
    Question(id: 102, domain: 1, text: "Which NIST publication describes the overall organization-wide risk management process including framing, assessing, responding to, and monitoring risk?", options: ["SP 800-39", "SP 800-30", "SP 800-53", "SP 800-137"], answer: 0, explain: "SP 800-39 covers the multi-tiered risk management process: frame, assess, respond, monitor."),
    Question(id: 103, domain: 1, text: "The 'risk framing' component of SP 800-39 is best described as:", options: ["Conducting a detailed technical vulnerability scan of systems", "Establishing the context and strategy for managing risk", "Selecting the individual security controls for the system", "Issuing the system's ATO"], answer: 1, explain: "Risk framing establishes organizational risk assumptions, risk tolerance, and the risk management strategy before risk is assessed."),
    Question(id: 104, domain: 1, text: "A healthcare organization processes electronic protected health information (ePHI). Which law most directly governs their security requirements?", options: ["SOX", "GLBA", "HIPAA Security Rule", "FERPA"], answer: 2, explain: "The HIPAA Security Rule establishes national standards for protecting ePHI held by covered entities and their business associates."),
    Question(id: 105, domain: 1, text: "ISO/IEC 27001 is best described as:", options: ["An international standard for an Information Security Management System", "A United States federal mandate governing cloud service authorization and use", "A risk assessment methodology developed specifically for the NIST RMF framework", "A payment card industry data security standard for merchants processing card data"], answer: 0, explain: "ISO 27001 is an international standard specifying requirements for an ISMS, applicable to any organization globally."),
    Question(id: 106, domain: 1, text: "Which NIST publication provides guidance for conducting risk assessments of federal information systems?", options: ["SP 800-30", "SP 800-37", "SP 800-39", "SP 800-53A"], answer: 0, explain: "SP 800-30 provides guidance on risk assessment — identifying threats, vulnerabilities, likelihood, and impact."),
    Question(id: 107, domain: 1, text: "An organization's risk tolerance is best defined as:", options: ["The maximum number of vulnerabilities allowed per system", "The degree of risk the organization is willing to accept in pursuit of its mission", "The dollar amount set aside for security tools", "The number of incidents before escalation"], answer: 1, explain: "Risk tolerance (or risk appetite) defines how much risk an organization is willing to accept to achieve its goals."),
    Question(id: 108, domain: 1, text: "Threat sources identified in SP 800-30 include:", options: ["Only deliberate nation-state and APT-style threat actors", "Only malicious insider threats acting within the organization", "Only natural disasters and various severe weather events", "Adversarial, accidental, structural, and environmental"], answer: 3, explain: "SP 800-30 categorizes threats as adversarial (intentional), accidental (unintentional), structural (equipment failure), and environmental (natural disasters)."),
    Question(id: 109, domain: 1, text: "A Tier 2 risk management function in SP 800-39 is best described as:", options: ["Mission and business-process risk management linking strategy to systems", "Authorization of each individual information system to operate independently", "Configuration of the organization's network firewall rule sets", "Routine patching of the organization's server operating systems"], answer: 0, explain: "Tier 2 addresses mission/business process owners who translate organizational risk strategy into system-level requirements."),
    Question(id: 110, domain: 1, text: "Which component of the risk management process involves determining what to do about identified risk?", options: ["Risk response", "Risk framing", "Risk assessment", "Risk monitoring"], answer: 0, explain: "Risk response (SP 800-39) involves selecting and implementing courses of action to address identified risks."),
    Question(id: 111, domain: 1, text: "An organization wants to tailor its security program to align with the NIST Cybersecurity Framework. The CSF core Functions are:", options: ["Govern, Identify, Protect, Detect, Respond, and Recover", "Identify, Protect, Detect, Respond, and Recover", "Prepare, Categorize, Select, Implement, Assess, Authorize, Monitor", "Plan, Do, Check, Act"], answer: 0, explain: "NIST CSF 2.0 (February 2024) added the GOVERN function to the original five (Identify, Protect, Detect, Respond, Recover) — six core Functions in total that organize cybersecurity outcomes."),
    Question(id: 112, domain: 1, text: "Supply chain risk management (SCRM) in the context of the RMF is most concerned with:", options: ["Optimizing shipping and logistics for hardware procurement", "Negotiating the lowest price from suppliers", "Risks from hardware, software, and services acquired from external providers", "Standardizing employee onboarding procedures"], answer: 2, explain: "SCRM addresses risks introduced by components and services from external suppliers throughout the supply chain."),
    Question(id: 113, domain: 1, text: "A privacy impact assessment (PIA) is most useful for:", options: ["Analyzing the total cost of a planned system upgrade project", "Serving as a complete replacement for the security assessment", "Setting the expiration date attached to the system's ATO", "Identifying privacy risks when a system processes PII"], answer: 3, explain: "A PIA identifies and mitigates privacy risks associated with collecting or processing PII, per OMB Circular A-130 and privacy frameworks."),
    Question(id: 114, domain: 1, text: "Under FISMA, who has primary responsibility for ensuring an agency-wide information security program?", options: ["The agency head and CIO, with the CISO operating daily", "The authorizing official, exclusively and alone, for everything", "The individual system administrator who maintains the servers", "Each individual end user of the systems"], answer: 0, explain: "FISMA places agency-wide security program responsibility on the agency head (Secretary/Administrator), delegated to the CIO, with the CISO executing operationally."),

    // MARK: – Domain 2: Scope of the Information System (11%)
    Question(id: 10, domain: 2, text: "FIPS 199 is used to:", options: ["Select specific controls", "Categorize information systems by impact level", "Authorize a system to operate", "Assess control effectiveness"], answer: 1, explain: "FIPS 199 establishes security categorization (low/moderate/high) based on impact to CIA."),
    Question(id: 11, domain: 2, text: "When categorizing a system under FIPS 199, the overall impact level is determined by:", options: ["The average of the three CIA impact values", "The lowest of the CIA impact values", "The highest of the CIA impact values (high-water mark)", "The availability value only"], answer: 2, explain: "FIPS 199 uses the high-water mark: the system's impact level equals the highest impact among C, I, and A."),
    Question(id: 12, domain: 2, text: "During categorization, a system owner needs to map the system's information types to provisional impact levels. Which NIST publication provides this mapping?", options: ["SP 800-53", "SP 800-137", "SP 800-18", "SP 800-60"], answer: 3, explain: "SP 800-60 provides guidance for mapping information types to security categories/impact levels."),
    Question(id: 13, domain: 2, text: "Defining the authorization boundary of a system primarily determines:", options: ["What is included within the scope of the system being assessed and authorized", "The contractual payment terms with the cloud service provider", "The encryption algorithm used for data at rest", "The patch cadence for the operating system"], answer: 0, explain: "The authorization boundary scopes the components, data, and interconnections covered by the assessment and authorization decision."),
    Question(id: 15, domain: 2, text: "An AO requests the document that captures the system's name, purpose, functionality, and authorization boundary. Which document is provided?", options: ["POA&M", "Assessment report", "System description / System Security Plan", "Risk response plan"], answer: 2, explain: "The system description (often within the SSP) documents name, purpose, functionality, and boundary."),
    Question(id: 120, domain: 2, text: "A system owner is unsure whether a third-party SaaS component should be inside or outside the authorization boundary. The best guidance is:", options: ["Always exclude every third-party service from the boundary", "Check whether it stores, processes, or transmits data or provides security", "Include every internet-connected component in the boundary", "Exclude anything that happens to be managed by an external third-party vendor"], answer: 1, explain: "The authorization boundary should include components that store, process, transmit information or provide security functions critical to the system's operation."),
    Question(id: 121, domain: 2, text: "A system is categorized HIGH for confidentiality, MODERATE for integrity, and LOW for availability. The overall FIPS 199 impact level is:", options: ["Moderate", "High", "Low", "A weighted average of the three"], answer: 1, explain: "FIPS 199 uses the high-water mark principle — the overall categorization is the highest value across all three objectives, which is HIGH."),
    Question(id: 122, domain: 2, text: "An interconnection between two federal systems requires:", options: ["Only a verbal agreement", "A new ATO for both systems from scratch", "An Interconnection Security Agreement (ISA) and MOU/MOA", "No additional documentation"], answer: 2, explain: "System interconnections are governed by an Interconnection Security Agreement (ISA) and a Memorandum of Understanding/Agreement (MOU/MOA)."),
    Question(id: 123, domain: 2, text: "The information system owner is responsible for:", options: ["Accepting residual risk on behalf of the organization", "Conducting the independent security assessment", "Establishing organization-wide risk tolerance", "Developing, operating, maintaining, and disposing of the system"], answer: 3, explain: "The system owner is responsible for the system throughout its lifecycle: development, operation, maintenance, and disposal."),
    Question(id: 124, domain: 2, text: "Registering an information system before beginning the RMF process is important because:", options: ["It automatically grants the system its authorization to operate", "It records the system and gives leadership visibility", "It serves as a full replacement for the System Security Plan", "It is required only for classified national security systems"], answer: 1, explain: "System registration ensures the system is captured in organizational portfolios, assigned roles, and visible to risk management decision-makers."),
    Question(id: 125, domain: 2, text: "Which RMF step involves identifying the authorization boundary and documenting the system description?", options: ["Categorize", "Prepare", "Select", "Authorize"], answer: 1, explain: "The Prepare step (added in SP 800-37 Rev. 2) includes establishing the authorization boundary, registering the system, and documenting system descriptions."),
    Question(id: 126, domain: 2, text: "A mission owner wants to understand what specific information the system handles to ensure appropriate protections. The primary document consulted is:", options: ["The POA&M", "The authorization decision memo", "The data flow diagram and SSP system description", "The contingency plan"], answer: 2, explain: "Data flow diagrams and the SSP system description document what information types are processed, stored, and transmitted."),

    // MARK: – Domain 3: Selection and Approval of Security/Privacy Controls (15%)
    Question(id: 17, domain: 3, text: "Before tailoring, a moderate-impact system starts from a standard, predefined group of controls matched to its impact level. This starting group is called a:", options: ["A finalized and fully signed authorization decision document", "A documented list of all the system's accepted residual risks", "An incident response runbook", "A predefined starting set of controls for that impact level"], answer: 3, explain: "Baselines (low/moderate/high in SP 800-53B) are predefined starting control sets tailored to the system."),
    Question(id: 18, domain: 3, text: "Which action would make a control-tailoring decision invalid?", options: ["Ignoring the authorizing official's documented risk tolerance", "Applying an approved overlay", "Adding a compensating control with justification", "Scoping out a control that is not applicable to the environment"], answer: 0, explain: "Tailoring must reflect organizational risk tolerance. Ignoring the AO's documented risk guidance invalidates the tailoring decision."),
    Question(id: 19, domain: 3, text: "A community of federal cloud systems shares a common, tailored control specification beyond the standard baseline. This specification is called an:", options: ["A documented diagram of the entire system's network architecture layout", "A formal report produced from a recent penetration test engagement", "A control specification tailored for a community or environment", "A category of network firewall rule"], answer: 2, explain: "Overlays provide a tailored set of controls for specific communities of interest, technologies, or environments."),
    Question(id: 20, domain: 3, text: "Inherited (common) controls are:", options: ["Controls another entity manages and many systems reuse", "Controls that are unique to one single application and nowhere else", "Controls that simply cannot be assessed by any assessor", "Controls that are considered always entirely optional to apply"], answer: 0, explain: "Common/inherited controls are provided by a separate entity (e.g., the enterprise) and inherited by many systems."),
    Question(id: 21, domain: 3, text: "A system team cannot implement a baseline control as written, so they deploy an alternate that provides equivalent protection. This alternate is a:", options: ["An indication that no risk exists for this requirement at all", "A signal that the system should be fully decommissioned now", "A note that the AO is currently unavailable", "A compensating control providing equivalent protection"], answer: 3, explain: "Compensating controls provide comparable protection when a baseline control is not feasible."),
    Question(id: 22, domain: 3, text: "A system owner must record which controls were selected and how each will be implemented. Which document captures this?", options: ["System Security Plan (SSP)", "Penetration test report", "Memorandum of Understanding", "Contingency plan"], answer: 0, explain: "The SSP documents selected controls, implementation approach, and responsibilities."),
    Question(id: 23, domain: 3, text: "Stakeholder agreement on control allocation is important because:", options: ["It identifies which controls can be retired to reduce cost", "It establishes who is responsible for implementing and maintaining each control", "It determines the sequence of the penetration test", "It selects the SIEM product the organization will buy"], answer: 1, explain: "Allocation assigns responsibility for each control to system, common, or hybrid providers with stakeholder concurrence."),
    Question(id: 130, domain: 3, text: "A system security officer is selecting controls for a moderate-impact system. The starting point should be:", options: ["The high baseline from SP 800-53B, then scoped down", "Only the controls required by HIPAA", "Any controls the team prefers", "The moderate baseline from SP 800-53B, then tailored to the system"], answer: 3, explain: "SP 800-53B provides low, moderate, and high baselines. A moderate-impact system starts with the moderate baseline and tailors it."),
    Question(id: 131, domain: 3, text: "When scoping a control baseline, which of the following is a valid reason to exclude a control?", options: ["The implementation team simply finds the control inconvenient to put in place", "The control is not applicable to the system's environment or technology", "The authorizing official has not yet personally reviewed the selected control", "The vendor disagrees with the control"], answer: 1, explain: "Scoping removes controls that are not applicable to the operational environment, technology, or mission — e.g., wireless controls on a wired-only system."),
    Question(id: 132, domain: 3, text: "A hybrid control is one that:", options: ["A control that is always optional for the system to apply", "A control that is purely technical in nature", "Implemented partly by the system and partly inherited", "A control that requires no documentation"], answer: 2, explain: "Hybrid controls have both a system-specific component and an inherited (common) component — responsibility is split."),
    Question(id: 133, domain: 3, text: "In NIST SP 800-53 Revision 5, privacy controls are located in:", options: ["A standalone privacy publication separate from SP 800-53", "The FIPS 200 minimum security requirements document", "The integrated catalog, including the PT family", "The SP 800-137 continuous monitoring guidance document"], answer: 2, explain: "SP 800-53 Rev. 5 eliminated the Rev. 4 Appendix J and integrated privacy controls throughout the main catalog, including the dedicated PT (Personally Identifiable Information Processing and Transparency) family."),
    Question(id: 134, domain: 3, text: "Which action would be an improper way to tailor a control baseline?", options: ["Applying an approved overlay", "Assigning organization-defined parameters", "Supplementing the baseline with additional controls", "Removing a baseline control with no documented justification"], answer: 3, explain: "Any removal of a baseline control requires documented justification. Removing a control with no justification is not an acceptable tailoring action."),
    Question(id: 135, domain: 3, text: "FIPS 200 establishes:", options: ["The official list of all the NIST-approved cryptographic algorithms", "Minimum security requirements based on the impact level", "The defined sequence of the Risk Management Framework steps", "Each agency's individual risk tolerance"], answer: 1, explain: "FIPS 200 sets minimum security requirements across 17 control families, mapped to the impact levels established by FIPS 199."),
    Question(id: 136, domain: 3, text: "An organization-defined parameter (ODP) in SP 800-53 allows:", options: ["The organization to set specific control values", "The authorizing official to skip controls entirely", "The vendor to override the federal requirements outright", "Any value at all without any review"], answer: 0, explain: "ODPs are placeholders in control statements that organizations fill in with specific values consistent with their risk tolerance and operational needs."),
    Question(id: 137, domain: 3, text: "A FedRAMP overlay is applied to a cloud service provider's baseline. This overlay:", options: ["It completely replaces the entire SP 800-53 control catalog", "It adjusts controls for the cloud and federal requirements", "It is entirely optional for every cloud service provider to apply", "It applies only to classified national security systems alone"], answer: 1, explain: "The FedRAMP overlay tailors SP 800-53 controls specifically for cloud environments serving federal agencies."),

    // MARK: – Domain 4: Implementation of Security/Privacy Controls (16%)
    Question(id: 25, domain: 4, text: "A system protects data using hardware and software encryption mechanisms. A control implemented through such mechanisms is classified as which type?", options: ["Implemented through policies and procedures by people", "Always inherited", "Never assessable", "Implemented through hardware/software/firmware mechanisms"], answer: 3, explain: "Technical controls are implemented via technology mechanisms; management and operational controls are people/process oriented."),
    Question(id: 26, domain: 4, text: "An enterprise implements a single audit-logging service that dozens of systems rely on without rebuilding it. This is an example of a control that:", options: ["Is implemented once and inherited by multiple systems", "Must be reimplemented per system", "Cannot be documented", "Is the same as a compensating control"], answer: 0, explain: "Common controls are implemented at an enterprise level and inherited, reducing duplicate effort."),
    Question(id: 27, domain: 4, text: "During implementation, control implementations should be consistent with:", options: ["The most recently released product version", "Compliance requirements and the documented control design", "The fastest option to deploy regardless of design", "The implementing engineer's personal preference"], answer: 1, explain: "Implementation must align with compliance requirements and the control design captured in the SSP."),
    Question(id: 28, domain: 4, text: "A governance team is identifying which of its safeguards are management controls. Which of the following qualifies?", options: ["Firewall ruleset", "Antivirus signature updates", "Risk assessment policy and security planning", "Disk encryption"], answer: 2, explain: "Management controls focus on risk management and oversight, e.g., policies, planning, and risk assessment."),
    Question(id: 29, domain: 4, text: "When a baseline control cannot be implemented as written, the appropriate action is to:", options: ["Quietly skip the control and move on without notice", "Use a compensating control and document why", "Decommission the entire information system at once", "Arbitrarily lower the system's overall impact level"], answer: 1, explain: "Document and implement a compensating control with justification rather than leaving a gap undocumented."),
    Question(id: 30, domain: 4, text: "An implementation strategy should account for:", options: ["Resourcing, funding, timeline, and expected control effectiveness", "The deployment timeline alone, without resource considerations", "Only the procurement budget for security tools", "The system's planned decommissioning date"], answer: 0, explain: "A sound implementation strategy considers resources, funding, schedule, and the expected effectiveness of the controls being deployed."),
    Question(id: 140, domain: 4, text: "A system team is implementing an access control policy. The SSP states that multi-factor authentication is required, but the system's legacy architecture cannot support MFA. The BEST course of action is:", options: ["Silently skip the MFA requirement and just continue operating the system", "Upgrade the system's underlying architecture without any authorization at all", "Remove MFA from the SSP without approval", "Document an exception, add a compensating control, and accept via AO"], answer: 3, explain: "When a control cannot be implemented as specified, document an exception, provide a compensating control, and route the residual risk to the AO for acceptance."),
    Question(id: 141, domain: 4, text: "An operational control is BEST described as:", options: ["Hardware or software mechanisms that are built into the system", "Controls that are always managed by the wider enterprise", "Controls carried out mainly by people", "Exactly the same thing as an ordinary technical control"], answer: 2, explain: "Operational controls are process-oriented and executed by people — e.g., physical security, incident response procedures, media protection."),
    Question(id: 142, domain: 4, text: "Which activity best supports consistent, repeatable control implementation across an enterprise?", options: ["Letting each team implement controls on its own", "Buying different products for every single system", "Delaying until after authorization", "Enterprise-wide SOPs and common controls"], answer: 3, explain: "Enterprise SOPs and common control programs promote consistency, reduce duplication, and streamline assessments."),
    Question(id: 143, domain: 4, text: "During implementation, updating the SSP to reflect actual control implementations is important because:", options: ["The System Security Plan is entirely optional documentation", "It removes the need for any independent security assessment", "It automatically issues the ATO", "Assessors and the AO rely on it to see how controls work"], answer: 3, explain: "The SSP is the primary artifact for assessors and the AO; it must reflect actual, current implementations to support credible assessment and authorization."),
    Question(id: 144, domain: 4, text: "A developer is building a new web application for a federal agency. When in the SDLC should security controls be integrated?", options: ["Only after deployment", "Only during the testing phase", "Throughout the SDLC, beginning at the design phase", "After the initial ATO is issued"], answer: 2, explain: "SP 800-37 Rev. 2 emphasizes integrating security and privacy into every phase of the SDLC, not just at deployment."),
    Question(id: 145, domain: 4, text: "Configuration management during implementation ensures:", options: ["Users can install any software", "Vendors control all configuration decisions", "Backups are unnecessary", "Systems are configured consistently and changes are tracked"], answer: 3, explain: "Configuration management (e.g., baselines, change control) ensures systems are consistently hardened and all changes are authorized and tracked."),
    Question(id: 146, domain: 4, text: "Physical and environmental controls (e.g., locks, badge readers, HVAC) are classified as:", options: ["Operational controls", "Technical controls", "Management controls", "Privacy controls only"], answer: 0, explain: "Physical and environmental protections are operational controls — they are implemented and managed by people and physical safeguards."),
    Question(id: 147, domain: 4, text: "A system owner discovers that a vendor has deployed software on the system that was not in the approved baseline. The FIRST step should be:", options: ["Immediately shut down the entire system until the rogue software is removed", "Silently accept the software and continue operations", "Assess the software's risk and report it via change management and IR", "Remove it at once without any documentation"], answer: 2, explain: "Unauthorized software is first assessed for risk, then handled through change management and potentially incident response — both actions are documented."),

    // MARK: – Domain 5: Assessment/Audit of Security/Privacy Controls (15%)
    Question(id: 32, domain: 5, text: "An assessor plans to review documents, question staff, and exercise controls. These activities map to which three NIST assessment methods?", options: ["Scan, patch, report", "Plan, do, check", "Interview, examine, test", "Avoid, accept, transfer"], answer: 2, explain: "SP 800-53A defines examine, interview, and test as the assessment methods."),
    Question(id: 33, domain: 5, text: "After an assessment identifies weaknesses, the team must track each one with a remediation plan and timeline. Which document is used?", options: ["Document the weaknesses and the plan to fix them", "Authorize the information system permanently going forward", "Serve as a full replacement for the System Security Plan", "Conduct a round of penetration tests on the system"], answer: 0, explain: "The POA&M tracks identified deficiencies, remediation actions, resources, and milestones."),
    Question(id: 34, domain: 5, text: "An organization deploys additional controls to reduce the likelihood and impact of an identified risk. Which risk response is this?", options: ["Mitigate", "Accept", "Avoid", "Transfer"], answer: 0, explain: "Mitigation reduces risk via controls. Accept = tolerate; Avoid = stop the activity; Transfer/Share = shift to a third party."),
    Question(id: 35, domain: 5, text: "Transferring (sharing) a risk is typically accomplished by:", options: ["Ignoring it", "Buying insurance or using a third party/contract", "Patching the system", "Decommissioning the system"], answer: 1, explain: "Risk transfer/sharing shifts financial or operational risk, e.g., via insurance or outsourcing."),
    Question(id: 36, domain: 5, text: "Residual risk is:", options: ["Risk before any controls are applied", "Risk that has been eliminated", "Risk remaining after controls and responses are applied", "Risk that the AO never sees"], answer: 2, explain: "Residual risk is what remains after mitigations; the AO accepts it as part of authorization."),
    Question(id: 37, domain: 5, text: "An agency engages an independent 3PAO rather than its own staff to assess a system. Why does this independence matter?", options: ["It substantially reduces the assessment's objectivity overall", "It boosts the credibility and objectivity of results", "It removes the need to collect any supporting evidence", "It replaces the AO entirely"], answer: 1, explain: "Assessor independence improves objectivity and the trustworthiness of the assessment findings."),
    Question(id: 38, domain: 5, text: "Which artifact records preliminary findings and risks discovered during the assessment?", options: ["The Initial/Security Assessment Report (SAR)", "The system decommissioning plan", "A configuration change request", "The system contingency plan"], answer: 0, explain: "The Security Assessment Report (SAR) documents assessment findings, including preliminary and final results."),
    Question(id: 39, domain: 5, text: "Reassessing non-compliant findings after corrective action is applied is intended to:", options: ["Skip the AO", "Validate that the deficiency has been remediated", "Increase residual risk", "Avoid documentation"], answer: 1, explain: "Reassessment verifies corrective actions effectively addressed the finding before final reporting."),
    Question(id: 40, domain: 5, text: "Penetration testing, vulnerability scanning, and control testing fall under which assessment method?", options: ["Interview", "Examine", "Test", "Authorize"], answer: 2, explain: "These are 'test' methods that exercise controls to produce evidence of effectiveness."),
    Question(id: 150, domain: 5, text: "An assessor is reviewing audit logs to verify that a control is working as intended. This is an example of which assessment method?", options: ["Examine", "Interview", "Test", "Authorize"], answer: 0, explain: "Reviewing documents, artifacts, and records (including logs) is the 'examine' method per SP 800-53A."),
    Question(id: 151, domain: 5, text: "An assessor interviews the system administrator about the patch management process. This is an example of which SP 800-53A assessment method?", options: ["Examine", "Interview", "Test", "Authorize"], answer: 1, explain: "Conducting discussions with individuals to gather information about controls is the 'interview' method per SP 800-53A."),
    Question(id: 152, domain: 5, text: "A finding in a SAR is rated 'high' severity. The system owner should FIRST:", options: ["Ignore it until the next assessment", "Immediately shut down the system", "Document it in the POA&M with a remediation plan and timeline", "Notify the public"], answer: 2, explain: "High findings must be documented in the POA&M with a remediation plan; the AO will evaluate whether residual risk is acceptable."),
    Question(id: 153, domain: 5, text: "Which risk assessment step involves identifying the likelihood that a threat will exploit a vulnerability?", options: ["Risk framing", "Threat identification", "Impact analysis", "Likelihood determination"], answer: 3, explain: "Per SP 800-30, likelihood determination estimates the probability that a given threat source will exploit a vulnerability."),
    Question(id: 154, domain: 5, text: "According to NIST SP 800-30, the overall level of a risk is determined by:", options: ["Combining the likelihood of a threat event occurring with its potential impact", "Counting the total number of vulnerabilities on the system", "Multiplying the number of assets by the number of controls", "The age of the system's most recent authorization"], answer: 0, explain: "SP 800-30 Rev. 1 defines risk as a function of the likelihood that a threat event occurs and the magnitude of the resulting impact, not a simple count of vulnerabilities or assets."),
    Question(id: 155, domain: 5, text: "A 3PAO (Third Party Assessment Organization) in FedRAMP is analogous to which role in the federal RMF?", options: ["Authorizing Official", "Independent assessor / Security Control Assessor", "System Owner", "Common Control Provider"], answer: 1, explain: "A 3PAO performs the independent assessment of cloud services under FedRAMP, equivalent to the Security Control Assessor role in the standard RMF."),
    Question(id: 157, domain: 5, text: "A risk response of 'avoid' means:", options: ["Accepting the risk with no action", "Transferring liability to a third party", "Reducing likelihood through controls", "Eliminating the risk by stopping the activity that creates it"], answer: 3, explain: "Risk avoidance eliminates the risk by not engaging in the activity — for example, not deploying a high-risk application."),
    Question(id: 158, domain: 5, text: "Which document should be updated throughout the assessment process as weaknesses are identified?", options: ["The Plan of Action and Milestones (POA&M)", "The signed authorization decision memo", "The system's network topology diagram", "The organization's annual budget"], answer: 0, explain: "The POA&M is a living document updated throughout the assessment to track each weakness, its severity, owner, and remediation timeline."),

    // MARK: – Domain 6: Authorization/Approval of Information System (10%)
    Question(id: 42, domain: 6, text: "After assessment, a senior official must formally accept the residual risk and decide whether the system may operate. Which role makes this decision?", options: ["System administrator", "Authorizing Official (AO)", "End user", "Help desk"], answer: 1, explain: "The Authorizing Official accepts residual risk and grants the Authorization to Operate."),
    Question(id: 43, domain: 6, text: "An AO signs a decision that permits a system to operate and formally accepts its residual risk. This decision fundamentally represents:", options: ["A technical configuration applied to the system", "A routine vulnerability scan of the whole system", "A commercial contract signed with the system vendor", "A senior official's formal acceptance of risk"], answer: 3, explain: "The ATO is the AO's formal, risk-based decision to accept residual risk and permit operation."),
    Question(id: 44, domain: 6, text: "The package submitted to support an authorization decision typically includes:", options: ["The SSP alone", "The network diagram and vendor contract only", "The penetration test report and training records only", "The SSP, SAR, and POA&M"], answer: 3, explain: "The authorization package generally contains the SSP, the assessment report (SAR), and the POA&M."),
    Question(id: 45, domain: 6, text: "Determining the system risk posture requires:", options: ["Risk acceptance criteria and residual risk, agreed by stakeholders", "Completely disregarding all of the system's remaining residual risk", "Removing the AO from the process", "Skipping the documentation step"], answer: 0, explain: "Risk posture combines acceptance criteria, residual risk determination, and stakeholder agreement on treatment."),
    Question(id: 46, domain: 6, text: "If residual risk exceeds the AO's risk tolerance, a likely outcome is:", options: ["Automatic full ATO", "Denial of authorization or additional remediation required", "Immediate decommissioning regardless", "No action"], answer: 1, explain: "When risk is too high, the AO may deny authorization or require further remediation before approval."),
    Question(id: 47, domain: 6, text: "Formal notification of the authorization decision should be:", options: ["Communicated verbally with no record retained", "Sent only to the system vendor", "Documented and shared with relevant stakeholders", "Withheld until the next reauthorization cycle"], answer: 2, explain: "The decision is formally documented and communicated to stakeholders responsible for the system."),
    Question(id: 48, domain: 6, text: "A common control provider's authorization package supports:", options: ["Eliminating the need for any security assessment", "Bypassing the AO's risk acceptance", "A way to avoid documenting controls", "Inheritance of those controls by other systems"], answer: 3, explain: "Authorizing common controls allows other systems to inherit and rely on them with documented assurance."),
    Question(id: 160, domain: 6, text: "An Authorizing Official Designated Representative (AODR) can:", options: ["Formally sign the system's ATO for the AO without any restriction", "Permanently replace the designated authorizing official entirely", "Review packages and advise, but not sign the final ATO", "Issue ATOs without reviewing the SAR"], answer: 2, explain: "The AODR assists the AO but cannot make the final authorization decision — that responsibility rests with the AO."),
    Question(id: 161, domain: 6, text: "An Interim Authorization to Test (IATT) is appropriate when:", options: ["A fully authorized system needs to be patched and updated", "The AO wishes to grant a permanent, indefinite authorization", "An unauthorized system needs limited operational testing", "The system has already passed every one of its assessments"], answer: 2, explain: "An IATT permits limited operation of an unauthorized system for testing purposes, with defined constraints and duration."),
    Question(id: 162, domain: 6, text: "When reviewing the authorization package, the AO is primarily evaluating:", options: ["Whether the residual risk is acceptable to the mission", "The commercial vendor's overall reputation in the industry", "The formatting and overall completeness of the documentation", "Whether the system used any open-source software anywhere"], answer: 0, explain: "The AO's core responsibility is to determine whether the residual risk documented in the SSP, SAR, and POA&M is acceptable."),
    Question(id: 163, domain: 6, text: "A denial of authorization (DATO) means:", options: ["The system received an ATO with several attached conditions", "The AO found risk too high; the system can't operate", "The system's security assessment has not begun yet at all", "The SSP is still incomplete"], answer: 1, explain: "A DATO is the AO's decision that residual risk is too high to permit operation — the system must not operate until risks are addressed."),
    Question(id: 164, domain: 6, text: "As of the 2024 FedRAMP modernization, cloud service authorization works like this:", options: ["One 'FedRAMP Authorized' designation, with the FedRAMP Board governing", "Two separate authorization tiers: a JAB P-ATO and a separate agency ATO", "Vendor self-certification with no federal government review at all", "A permanent authorization that never requires any monitoring"], answer: 0, explain: "The FedRAMP Authorization Act and the 2024 modernization replaced the Joint Authorization Board (JAB) with the FedRAMP Board and retired the JAB P-ATO — consolidating to a single 'FedRAMP Authorized' designation issued through an agency sponsor."),

    // MARK: – Domain 7: Continuous Monitoring (17%)
    Question(id: 49, domain: 7, text: "Continuous monitoring (ConMon) guidance is provided primarily by:", options: ["FIPS 199", "NIST SP 800-137", "SP 800-60", "SP 800-18"], answer: 1, explain: "SP 800-137 covers Information Security Continuous Monitoring (ISCM)."),
    Question(id: 50, domain: 7, text: "A Change Control Board (CCB) is responsible for:", options: ["Operating the organization's help desk", "Performing penetration tests on production systems", "Reviewing and approving proposed system changes", "Conducting the annual security awareness training"], answer: 2, explain: "The CCB evaluates, approves, and tracks changes, weighing impacts on risk and compliance."),
    Question(id: 51, domain: 7, text: "Before deploying an approved change to production, a best practice is to:", options: ["Deploy directly to production with no maintenance window", "Skip regression testing to meet the deadline", "Disable audit logging during the deployment", "Have a tested rollback plan in case the change fails"], answer: 3, explain: "Changes should be deployed with a tested rollback plan so the system can be recovered if the change causes problems."),
    Question(id: 52, domain: 7, text: "An organization runs continuous monitoring after its system is authorized. What is the main purpose of this ongoing activity?", options: ["Maintain awareness of security posture and risk over time", "Replace the initial authorization", "Eliminate the need for controls", "Reduce documentation to zero"], answer: 0, explain: "ConMon sustains real-time awareness of security/privacy posture so risk decisions stay current."),
    Question(id: 53, domain: 7, text: "When legal, regulatory, or supplier requirements change, the monitoring strategy should be:", options: ["Left unchanged", "Revised to reflect the new requirements", "Deleted", "Ignored until the next ATO"], answer: 1, explain: "Monitoring strategies must be revised as legal, regulatory, supplier, and security/privacy requirements evolve."),
    Question(id: 54, domain: 7, text: "Proper system decommissioning includes:", options: ["Leaving the system running indefinitely", "Skipping stakeholder review", "Removing the system from operations and retaining/sharing documentation", "Destroying all records immediately without retention"], answer: 2, explain: "Decommissioning reviews requirements with stakeholders, removes the system, and retains required documentation."),
    Question(id: 55, domain: 7, text: "Ongoing security awareness and training during compliance maintenance should be:", options: ["Performed only once ever", "Optional and undocumented", "Replaced by the SAR", "Performed, documented, and retained"], answer: 3, explain: "Recurring training (incident response, contingency, annual security/privacy) must be performed and documented."),
    Question(id: 56, domain: 7, text: "An ATO that is maintained through continuous monitoring rather than fixed reauthorization dates is known as:", options: ["Ongoing authorization", "Denial of authorization", "Interim authorization to test", "Provisional decommissioning"], answer: 0, explain: "Ongoing authorization leverages robust ConMon so risk decisions are made continuously rather than periodically."),
    Question(id: 170, domain: 7, text: "A system undergoes a significant change (new database added). According to the RMF, the FIRST action should be:", options: ["Deploy the change immediately without any review at all", "Immediately request a brand-new full security assessment", "Notify only the system's commercial vendor of the change", "Assess the security impact via change management"], answer: 3, explain: "Significant changes require a security impact analysis through the change management process before and after deployment."),
    Question(id: 171, domain: 7, text: "Key metrics used in an ISCM program are called:", options: ["Security metrics or performance measures", "Authorization thresholds", "POA&M entries", "Overlay specifications"], answer: 0, explain: "SP 800-137 emphasizes selecting measurable security metrics and performance indicators to track security posture over time."),
    Question(id: 172, domain: 7, text: "An organization is developing its ISCM strategy per SP 800-137. Which element should the strategy define?", options: ["Metrics, monitoring frequencies, and the controls subject to ongoing assessment", "The system's initial FIPS 199 categorization decision", "The contractual payment milestones for the monitoring-tool vendor", "The individual remediation steps for every historical POA&M item"], answer: 0, explain: "SP 800-137 requires the ISCM strategy to define metrics, monitoring frequencies, the controls monitored, tools, and reporting cadence to sustain situational awareness."),
    Question(id: 173, domain: 7, text: "Vulnerability scanning as a continuous monitoring activity helps the organization:", options: ["Serve as a full replacement for the formal security assessment", "Automatically remediate every discovered vulnerability for you", "Detect new vulnerabilities from patches or config changes", "Eliminate the system's POA&M"], answer: 2, explain: "Regular vulnerability scanning identifies new exposures continuously, informing risk posture and driving POA&M updates."),
    Question(id: 174, domain: 7, text: "A significant change triggers re-authorization when:", options: ["Whenever any minor patch is applied to the system", "Only when it is specifically mandated by federal law", "Whenever the system's vendor happens to suggest it", "It adds new risk beyond what the AO accepted"], answer: 3, explain: "Significant changes that materially alter the risk posture may require the AO to revisit and potentially update the authorization decision."),
    Question(id: 175, domain: 7, text: "Ongoing authorization differs from periodic reauthorization primarily because:", options: ["It requires substantially fewer security controls overall", "The authorizing official is removed from the process entirely", "It uses continuous monitoring to keep risk awareness current", "It applies only to systems categorized as low impact"], answer: 2, explain: "Ongoing authorization replaces point-in-time reauthorization with continuous monitoring, keeping risk decisions current in near real-time."),
    Question(id: 176, domain: 7, text: "Media sanitization and disposal is governed primarily by:", options: ["FIPS 199", "NIST SP 800-88", "SP 800-30", "SP 800-60"], answer: 1, explain: "SP 800-88 provides guidelines for media sanitization — clearing, purging, and destroying media before disposal."),
    Question(id: 177, domain: 7, text: "During decommissioning, personally identifiable information (PII) must be:", options: ["Disposed of per privacy laws and retention schedules", "Archived in plain text so it is available for future use", "Transferred freely to any other interested external party", "Kept on the system indefinitely"], answer: 0, explain: "PII disposal must comply with legal retention requirements and applicable privacy laws, and must be properly sanitized or destroyed."),
    Question(id: 178, domain: 7, text: "A system owner notices that a control that was previously assessed as 'satisfied' is now failing due to a configuration drift. The BEST response is:", options: ["Simply wait until the next regularly scheduled full assessment", "Log it in the POA&M, remediate, and notify the AO if needed", "Remove the control from the SSP", "Ignore it while the system runs normally"], answer: 1, explain: "Control failures discovered during ConMon must be documented, remediated, and reported to the AO when they materially affect the authorization risk posture."),
    Question(id: 179, domain: 7, text: "Automated tools used in continuous monitoring (e.g., SIEM, vulnerability scanners) primarily support which ISCM objective?", options: ["Replacing human judgment in the authorization process", "Eliminating the need for the organization's policies", "Timely automated data collection for awareness", "Fully automating all of the POA&M remediation work"], answer: 2, explain: "Automation in ISCM enables timely, efficient data collection and reporting that keeps situational awareness current — but it supplements, not replaces, human judgment."),

    // MARK: – Additional items: Roles, Sanitization, ATU, Reciprocity, SP 800-70/128/34/115

    // Domain 1 – Roles & foundations
    Question(id: 200, domain: 1, text: "The U.S. Department of Defense Five Pillars of Information Assurance include confidentiality, integrity, and availability PLUS:", options: ["Accountability and auditability", "Authenticity and non-repudiation", "Authorization and auditing", "Resilience and redundancy"], answer: 1, explain: "DoD's Five Pillars of IA add authenticity and non-repudiation to the classic CIA triad."),
    Question(id: 201, domain: 1, text: "The Risk Executive Function is responsible for:", options: ["Implementing all of the technical security controls on individual systems", "Conducting the organization's annual security control assessment", "Issuing the authorization to operate for each information system", "Aligning system risk decisions with organization-wide risk tolerance"], answer: 3, explain: "The Risk Executive Function provides an organization-wide perspective on risk, ensuring individual system risk decisions are consistent with overall mission goals and risk tolerance (SP 800-37)."),
    Question(id: 202, domain: 1, text: "An Information Owner (IO) is best described as:", options: ["The official with authority over specific information and its controls", "The contracted vendor that originally developed and delivered the system software", "The independent assessor who tests whether the system's security controls are effective", "The system administrator responsible for maintaining the production database daily"], answer: 0, explain: "The Information Owner has authority over specific information and sets controls for its generation, collection, processing, dissemination, and disposal."),
    Question(id: 203, domain: 1, text: "The Information Systems Security Officer (ISSO) is primarily responsible for:", options: ["Making the final system authorization decision for operation", "Independently assessing each of the system's many controls", "Setting org-wide risk tolerance", "Managing the system's security and assembling the package"], answer: 3, explain: "The ISSO manages day-to-day security of the system, assembles the authorization package, and serves as the point of contact for the Security Control Assessor."),
    Question(id: 204, domain: 1, text: "A Common Control Provider (CCP) is responsible for:", options: ["Developing, implementing, assessing, and monitoring common controls", "Authorizing each of the organization's systems independently of others", "Conducting all penetration tests on behalf of the authorizing official", "Setting the organization's risk tolerance"], answer: 0, explain: "The CCP owns the lifecycle of common (inherited) controls and ensures their continued effectiveness for all systems that inherit them."),
    Question(id: 205, domain: 1, text: "Reciprocity in the RMF context means:", options: ["Two separate systems sharing the very same authorizing official across the agency", "Dual authorization being required before any system change can be deployed", "Mutual penetration-testing agreements established between the organizations", "Organizations accept each other's assessments to reuse the work"], answer: 3, explain: "Reciprocity allows organizations to accept and leverage existing security assessments from other organizations, reducing duplicative effort and cost."),
    Question(id: 206, domain: 1, text: "Which current NIST publication provides guidance on engineering security into the system development life cycle?", options: ["SP 800-30 (risk assessment)", "SP 800-137 (continuous monitoring)", "SP 800-88 (media sanitization)", "SP 800-160 Vol. 1 (systems security engineering)"], answer: 3, explain: "SP 800-160 Vol. 1 (Systems Security Engineering) provides current guidance on integrating security throughout the SDLC. It superseded the now-withdrawn SP 800-64."),
    Question(id: 208, domain: 1, text: "The Privacy Architect role is responsible for:", options: ["Embedding privacy needs into the architecture", "Approving the system's overall authorization to operate", "Performing the system's independent security assessment", "Managing the system's full Plan of Action and Milestones"], answer: 0, explain: "The Privacy Architect ensures privacy protection requirements are incorporated into all levels of enterprise architecture, including reference models and information system designs."),

    // Domain 4 – Configuration management (SP 800-70 / SP 800-128)
    Question(id: 210, domain: 4, text: "NIST SP 800-70 provides guidance on:", options: ["A formal risk assessment methodology for federal systems overall", "The National Checklist Program of security config checklists", "Detailed guidance for building a continuous monitoring strategy", "Media sanitization methods"], answer: 1, explain: "SP 800-70 Rev. 4 covers the National Checklist Program, providing guidelines for using security configuration checklists such as STIGs and CIS Benchmarks."),
    Question(id: 211, domain: 4, text: "Security Technical Implementation Guides (STIGs) and CIS Benchmarks are examples of:", options: ["Security configuration checklists used to harden systems", "Completed system authorization packages submitted for review", "Detailed risk assessment reports produced for each system", "Overlay control specifications"], answer: 0, explain: "STIGs and CIS Benchmarks are security configuration checklists referenced in SP 800-70 for establishing secure baseline configurations."),
    Question(id: 212, domain: 4, text: "NIST SP 800-128 provides guidance on:", options: ["Conducting privacy impact assessments across systems", "Security-focused configuration management of systems", "Media sanitization and secure media disposal procedures", "Contingency planning and disaster recovery operations"], answer: 1, explain: "SP 800-128 covers security-focused configuration management, including CM planning, controls (CM-1 through CM-9), and maintaining secure configurations throughout the system lifecycle."),
    Question(id: 213, domain: 4, text: "The United States Government Configuration Baseline (USGCB) is:", options: ["A legal mandate for civilian agencies to use specific hardware", "A set of standardized secure configuration settings for government IT products", "A risk assessment framework", "A continuous monitoring tool"], answer: 1, explain: "The USGCB provides standardized, government-wide secure configuration settings for common IT products used in federal agencies."),
    Question(id: 214, domain: 4, text: "A Configuration Management Plan (CM Plan) should describe:", options: ["Roles, responsibilities, policies, and procedures for configuration", "Only the recurring patch deployment schedule", "Only the software licensing agreements in force", "Only the documented physical network topology and cabling diagram for the site"], answer: 0, explain: "A CM Plan comprehensively covers roles, responsibilities, policies, and procedures governing configuration management throughout the system lifecycle."),
    Question(id: 215, domain: 4, text: "A baseline configuration is best described as:", options: ["Always the latest release provided by the system's vendor", "An informal running list of the software that is currently installed on it", "A documented specification changeable only through change control", "The authorizing official's formal authorization decision letter"], answer: 2, explain: "A baseline configuration is a formally agreed-upon, documented specification that can only be changed through the change control process."),

    // Domain 5 – Assessment methods (SP 800-115)
    Question(id: 221, domain: 5, text: "An organization wants to verify its controls are working before the formal assessment. The BEST approach is:", options: ["Submit the full authorization package without doing any testing at all", "Skip internal testing entirely to save time", "Ask the vendor to certify the controls", "Run internal testing with SP 800-115 techniques to find gaps first"], answer: 3, explain: "SP 800-115 techniques allow organizations to self-assess and identify control gaps before the formal independent assessment."),
    Question(id: 222, domain: 5, text: "Which set correctly lists the three assessment methods defined in NIST SP 800-53A?", options: ["Test, Inspect, Evaluate", "Track, Identify, Escalate", "Examine, Interview, Test", "Threat, Impact, Exposure"], answer: 2, explain: "SP 800-53A defines three assessment methods: Examine (review artifacts), Interview (question personnel), and Test (exercise controls). The other options are not NIST assessment methods."),

    // Domain 6 – Authorization to Use (ATU)
    Question(id: 230, domain: 6, text: "An Authorization to Use (ATU) differs from an ATO in that:", options: ["An ATU authorizes use of another org's already-authorized system", "An ATU is issued directly by the commercial vendor that built the system", "An ATU requires a full, independent security assessment before issuance", "An ATU applies only to cloud-hosted systems"], answer: 0, explain: "An ATU allows an organization to authorize use of a system already authorized by another organization, leveraging the existing authorization package without a full reassessment — similar to reciprocity."),
    Question(id: 231, domain: 6, text: "Risk sharing, as a risk treatment option in NIST SP 800-39, involves:", options: ["Eliminating the risk entirely by ending the activity", "Reducing the likelihood through extra technical controls", "Accepting the risk with no action", "Shifting part of the risk to another party"], answer: 3, explain: "Risk sharing (or transfer) moves part of the risk burden to a third party. The other options describe avoidance, acceptance, and mitigation respectively."),

    // Domain 7 – Sanitization & decommissioning (SP 800-88)
    Question(id: 240, domain: 7, text: "The 'Clear' method of media sanitization described in SP 800-88 means:", options: ["Physically destroying the storage media so that it can never be reused", "Logical overwriting that blocks simple, non-invasive data recovery", "Degaussing the media with a strong magnetic field", "Encrypting the media in place and discarding the key"], answer: 1, explain: "Clear applies logical techniques — such as overwriting with new values — to sanitize user-addressable storage, protecting against simple non-invasive recovery attempts."),
    Question(id: 241, domain: 7, text: "The 'Purge' method of media sanitization is distinguished from 'Clear' because:", options: ["Purge renders data unrecoverable even with laboratory techniques", "Purge relies exclusively on software-based overwriting tools and utilities", "Purge is applicable only to printed paper records and microfiche media", "Purge is considered the least secure of the available sanitization methods"], answer: 0, explain: "Purge provides a higher level of sanitization than Clear — it renders data unrecoverable even with advanced laboratory techniques (e.g., degaussing, secure erase for SSDs)."),
    Question(id: 242, domain: 7, text: "The 'Destroy' method of media sanitization means:", options: ["Overwrite the stored data three separate times in place", "Encrypt the media in place and then simply discard the key", "Render the media unusable so no recovery is possible", "Apply a full seven-pass Department of Defense data wipe"], answer: 2, explain: "Destroy renders the media physically unusable — through incineration, shredding, or disintegration — making data recovery impossible."),
    Question(id: 243, domain: 7, text: "When decommissioning a system that processed Moderate-impact data, which sanitization method is generally the minimum recommended by SP 800-88?", options: ["Purge (or Destroy for high-risk situations)", "Clear only", "No sanitization required", "Encrypt then Clear"], answer: 0, explain: "SP 800-88 generally recommends Purge (or Destroy) for Moderate and High impact data to ensure state-of-the-art lab techniques cannot recover information."),
    Question(id: 244, domain: 7, text: "Supply chain risk monitoring activities in the ConMon phase include:", options: ["Reviewing only the organization's own internal system audit logs", "Only assessing vendor contracts annually", "Reviewing threat reports and advisories for supply-chain risk", "Monitoring only the production network"], answer: 2, explain: "RMF Monitor-step guidance (SP 800-37, SP 800-161) requires actively monitoring supply chain risks through cyber threat intelligence, agency advisories, and open-source reporting."),
    Question(id: 245, domain: 7, text: "NIST SP 800-34 provides guidance on:", options: ["Media sanitization", "Security-focused configuration management", "Contingency planning for federal information systems", "Risk assessment methodology"], answer: 2, explain: "SP 800-34 (Contingency Planning Guide) assists organizations in developing Information System Contingency Plans (ISCPs) covering backup, recovery, and continuity of operations."),
    Question(id: 246, domain: 7, text: "An Information System Contingency Plan (ISCP) addresses:", options: ["How to authorize and field a brand-new information system", "How to select all the controls for a security baseline", "Responding to disruptions and restoring operations", "How to conduct a complete and full privacy impact assessment"], answer: 2, explain: "An ISCP (per SP 800-34) documents procedures for responding to system disruptions — including backup, recovery, and reconstitution — to maintain mission continuity."),
    Question(id: 247, domain: 7, text: "After a cyber event, the ConMon phase requires:", options: ["Wait until the next scheduled assessment to document it", "Automatically revoke the system's ATO without AO review", "Restrict the lessons-learned review to the IT team only", "Coordinate the response and apply lessons learned"], answer: 3, explain: "SP 800-137 and the RMF Monitor step require active incident response coordination and incorporating lessons learned into updated documentation, strategies, and monitoring tactics."),
    Question(id: 248, domain: 7, text: "Keeping designated officials updated about the ongoing risk posture supports which RMF activity?", options: ["Initial system categorization based on the impact to confidentiality and integrity", "Continuous authorization — keeping the AO's risk awareness current for decisions", "Selection of the appropriate security control baseline for the system's category", "Initial registration of the system in the inventory"], answer: 1, explain: "Domain 7.6 requires regularly updating designated officials (including the AO) on the current risk posture to support ongoing/continuous authorization decisions."),

    // MARK: – Domain 2 expansion (Scope)
    Question(id: 300, domain: 2, text: "A system owner is told to 'register' the system before starting the RMF. What does registration accomplish?", options: ["It automatically issues the authorization to operate for the registered system", "It records the system in inventories, assigns roles, and informs leadership", "It serves as a replacement for the SSP", "It categorizes the system's impact level"], answer: 1, explain: "System registration (RMF Prepare step) places the system in organizational portfolios, assigns roles like AO and ISSO, and ensures leadership awareness before work begins."),
    Question(id: 301, domain: 2, text: "A cloud system inherits physical security controls from the data center provider. The data center's controls exist:", options: ["Inside the system's authorization boundary, assessed by the system team", "In the system's POA&M as an open finding", "In a separate vendor licensing agreement only", "Outside the system's authorization boundary, documented as inherited common controls"], answer: 3, explain: "Controls provided by an external entity such as a data center fall outside the system's authorization boundary and are documented as inherited common controls."),
    Question(id: 302, domain: 2, text: "When conducting a security categorization, who is responsible for approving the final categorization?", options: ["The system owner, with AO and senior-official concurrence", "The independent security control assessor assigned to the system", "The commercial vendor that originally supplied the system software", "The IT help desk"], answer: 0, explain: "The system owner drives the categorization, but the final result requires concurrence from the AO and senior agency officials such as the CISO."),
    Question(id: 303, domain: 2, text: "A system processes law enforcement sensitive data (high confidentiality) and financial transaction records (moderate integrity, low availability). The overall FIPS 199 category is:", options: ["Moderate", "High", "Low", "Cannot be determined without more data"], answer: 1, explain: "High-water mark: the highest impact value across all information types and security objectives determines the system's overall impact level — HIGH confidentiality drives a HIGH system categorization."),
    Question(id: 304, domain: 2, text: "Which document type formally defines data flows between a system and its external interfaces?", options: ["POA&M", "Risk register", "Data flow diagram within the SSP", "Authorization memo"], answer: 2, explain: "Data flow diagrams capture how data moves between system components and external interfaces; they are typically part of the SSP system description."),
    Question(id: 305, domain: 2, text: "A senior official asks why the authorization boundary matters. The BEST answer is:", options: ["It defines what's in scope for protection and authorization", "It identifies precisely which staff need security clearances", "It establishes the entire system's network IP addressing scheme", "It sets the data backup frequency"], answer: 0, explain: "The authorization boundary defines what components, connections, and data fall under the AO's risk acceptance. Without a clear boundary, the scope of protection and responsibility is undefined."),
    Question(id: 306, domain: 2, text: "NIST SP 800-60 Volume 2 provides:", options: ["A catalog of assessment procedures used to evaluate each selected security control", "The mandatory security control baselines for low, moderate, and high", "Information type descriptions with provisional impact values for government data", "High-level risk framing and organizational risk tolerance guidance"], answer: 2, explain: "SP 800-60 Vol. 2 is the companion catalog that lists specific information types (e.g., financial management, law enforcement) with their provisional impact ratings."),
    Question(id: 307, domain: 2, text: "A system owner wants to exclude a low-impact subsystem from the authorization boundary to reduce assessment scope. This action:", options: ["Is always strictly prohibited under all RMF scoping guidance", "Automatically lowers the parent system's overall FIPS 199 impact level", "Requires no documentation or justification whatsoever", "Allowed if separately authorized or non-security, once documented"], answer: 3, explain: "Scoping the boundary is valid when a subsystem has its own authorization or no impact on the parent system's security — but exclusions must be documented and justified."),
    Question(id: 308, domain: 2, text: "Which RMF role is specifically assigned at the system level and has day-to-day responsibility for security?", options: ["Authorizing Official", "Risk Executive", "Information System Security Officer (ISSO)", "Common Control Provider"], answer: 2, explain: "The ISSO is assigned at the system level and handles day-to-day security operations, control monitoring, and assembly of the authorization package."),
    Question(id: 309, domain: 2, text: "An agency acquires a COTS product. Determining whether it falls inside or outside the authorization boundary depends primarily on:", options: ["Whether the product's vendor already holds a FedRAMP authorization", "Whether it handles system data or performs security functions", "The purchase price of the product", "The age of the product"], answer: 1, explain: "Any component that handles system data or performs security functions is a candidate for inclusion within the authorization boundary, regardless of whether it is COTS."),
    Question(id: 310, domain: 2, text: "A privacy threshold analysis (PTA) is used to:", options: ["Serve as a replacement for the security categorization", "Authorize the information system to begin operating", "Decide whether a full PIA is required", "Select the privacy controls for the system to use"], answer: 2, explain: "A Privacy Threshold Analysis screens whether a system processes PII — if it does, a full Privacy Impact Assessment (PIA) is typically required."),

    // MARK: – Domain 3 expansion (Control Selection)
    Question(id: 320, domain: 3, text: "An organization operates industrial control systems (ICS). When selecting controls, they should consider:", options: ["Use only the SP 800-53 moderate baseline entirely unchanged", "Apply no controls at all, since these ICS systems are exempt", "Only the vendor-recommended controls", "Apply the ICS overlay or SP 800-82 to tailor the controls"], answer: 3, explain: "ICS/OT environments have unique constraints (availability priority, real-time operation); SP 800-82 and ICS overlays help tailor SP 800-53 controls appropriately."),
    Question(id: 321, domain: 3, text: "A security plan must be reviewed and approved before the assessment. Who typically approves the SSP?", options: ["The independent assessor approves it for the owner", "The owner submits it; the AO approves", "The ISSO signs off on it entirely unilaterally", "The commercial system vendor formally approves it"], answer: 1, explain: "The system owner develops the SSP; the AO (or AODR) reviews and approves it as part of ensuring the system is ready for assessment and authorization."),
    Question(id: 322, domain: 3, text: "A control implementation is described as 'planned' in the SSP. This means:", options: ["The control is fully operational", "The control has been waived", "The control is inherited", "The control has not yet been implemented but is scheduled"], answer: 3, explain: "Implementation status in the SSP includes: implemented, partially implemented, planned (scheduled but not yet done), or not applicable."),
    Question(id: 323, domain: 3, text: "When an organization selects additional controls beyond the baseline to address specific threats, these are called:", options: ["Supplementary controls or control enhancements", "Compensating controls", "Inherited controls", "Overlapping controls"], answer: 0, explain: "Organizations may supplement the baseline with additional controls or enhancements to address threats or risks not adequately covered by the standard baseline."),
    Question(id: 324, domain: 3, text: "An Information Security Management System (ISMS) defined by ISO 27001 is most analogous to which NIST concept?", options: ["A single individual system's System Security Plan document and its appendices", "An organization-wide risk management program of policies and controls", "A single security control baseline that is applied to one system only", "A continuous monitoring tool"], answer: 1, explain: "ISO 27001's ISMS is a comprehensive management system for information security — conceptually analogous to the NIST organization-level (Tier 1) security program under SP 800-39."),
    Question(id: 325, domain: 3, text: "Which document defines the minimum security requirements across 17 security control families for federal systems?", options: ["SP 800-53", "SP 800-37", "FIPS 200", "SP 800-30"], answer: 2, explain: "FIPS 200 establishes minimum security requirements across 17 families (e.g., AC, AU, IA) that federal systems must meet, with the specific controls defined in SP 800-53."),
    Question(id: 326, domain: 3, text: "A control that is implemented partly by the enterprise (common portion) and partly by the system team (system-specific portion) is classified as:", options: ["A compensating control", "An inherited control", "A scoped control", "A hybrid control"], answer: 3, explain: "Hybrid controls split responsibility between a common control provider and the system — both portions must be documented and assessed."),
    Question(id: 327, domain: 3, text: "The purpose of reviewing and approving the security plan as part of control selection is to:", options: ["Completely eliminate the need for any later security control assessment", "Grant the system's full authorization to operate automatically up front", "Satisfy only the security program's documentation requirement fully", "Ensure controls are appropriate and agreed before building"], answer: 3, explain: "Security plan review and approval ensures all stakeholders agree on what controls will be implemented before resources are committed — catching gaps early reduces costly rework."),
    Question(id: 328, domain: 3, text: "An organization discovers that a baseline control is not cost-effective to implement. Which tailoring action is most appropriate?", options: ["Quietly remove the control from the selected control set entirely", "Lower the system's impact level so the control is not required", "Use a compensating control, document why, and route to the AO", "Ask the vendor to implement it for free"], answer: 2, explain: "When cost-effectiveness prevents implementing a control as specified, a compensating control with documented justification must be presented to the AO — not silently removed."),
    Question(id: 329, domain: 3, text: "Which family of controls in SP 800-53 addresses audit and accountability?", options: ["AC (Access Control)", "CA (Assessment, Authorization, and Monitoring)", "AU (Audit and Accountability)", "CM (Configuration Management)"], answer: 2, explain: "The AU family covers requirements for generating, protecting, reviewing, and retaining audit records to support accountability."),
    Question(id: 330, domain: 3, text: "Program management controls (PM family in SP 800-53) are unique because:", options: ["They apply only to systems that are categorized as low impact overall", "They entirely replace all of the other control families", "They are organization-level controls governing the whole program", "They are optional for federal agencies to implement"], answer: 2, explain: "PM controls operate at the organization level — covering the security/privacy program, risk management strategy, and enterprise architecture — rather than individual systems."),
    Question(id: 331, domain: 3, text: "A continuous control monitoring strategy developed during control selection should define:", options: ["Metrics, frequency, tools, reporting, and roles for compliance", "Only the recurring schedule planned for the system's penetration tests", "Only the system's annual review date", "Only the AO's contact information"], answer: 0, explain: "A robust ConMon strategy covers what to monitor, how often, with what tools, who is responsible, and how findings are reported — all defined before implementation begins."),
    Question(id: 332, domain: 3, text: "Privacy controls in SP 800-53 Rev. 5 are:", options: ["Contained in a separate publication only", "Integrated throughout the main control catalog alongside security controls", "Optional for all federal systems", "Only applicable to systems with HIGH privacy impact"], answer: 1, explain: "SP 800-53 Rev. 5 fully integrates privacy controls into the main catalog, recognizing that security and privacy protections are complementary."),

    // MARK: – Domain 4 expansion (Implementation)
    Question(id: 340, domain: 4, text: "A system team is implementing the IA-2 (Identification and Authentication) control. The SSP states MFA is required for all privileged accounts. An auditor finds one privileged account using only a password. This is:", options: ["Acceptable, as long as the password is complex", "Not a concern until the next ATO cycle comes", "Normal for any legacy accounts", "A control gap that must go in the POA&M"], answer: 3, explain: "Any deviation from the documented control implementation is a finding. It must be captured in the POA&M with a remediation plan and timeline."),
    Question(id: 341, domain: 4, text: "Which activity ensures that security controls are incorporated during software development rather than bolted on afterward?", options: ["Build security into the SDLC design phase", "Doing the security testing only at the final deployment stage", "Purchasing a separate security tool after the system is deployed", "Conducting the security assessment after the system goes live"], answer: 0, explain: "Security by Design — integrating security requirements into design and development — is far more effective and less costly than adding security after a system is built."),
    Question(id: 342, domain: 4, text: "Coordinating with a Common Control Provider during implementation is important because:", options: ["The common control provider must also implement system-specific controls", "The common control provider is the one that issues the system's ATO", "The common control provider performs the system's security assessment", "The team must understand inherited controls to document them"], answer: 3, explain: "System teams must document inherited controls accurately in the SSP; this requires close coordination with the CCP to understand implementation details and evidence."),
    Question(id: 343, domain: 4, text: "A system stores sensitive data on removable media. Which SP 800-53 control family primarily addresses this?", options: ["AC (Access Control)", "MP (Media Protection)", "PE (Physical and Environmental Protection)", "CM (Configuration Management)"], answer: 1, explain: "The MP family covers media protection — including marking, storage, transport, sanitization, and disposal of removable media containing sensitive information."),
    Question(id: 344, domain: 4, text: "Least privilege means:", options: ["The minimum access needed to do the job", "Every single user gets read-only access to data", "All of the privileged accounts are shared widely", "Access is granted strictly based on staff seniority"], answer: 0, explain: "Least privilege limits user and process access rights to only what is necessary — reducing the attack surface and limiting damage from compromised accounts."),
    Question(id: 345, domain: 4, text: "Separation of duties as a control is designed to:", options: ["Speed up the system's overall transaction processing speed", "Stop one person from being able to commit and hide fraud", "Reduce the total number of user accounts active on the system", "Replace multi-factor authentication"], answer: 1, explain: "Separation of duties divides critical functions across multiple people — no individual can complete a sensitive transaction alone, reducing insider threat risk."),
    Question(id: 346, domain: 4, text: "A gap analysis during control implementation is used to:", options: ["Issue the system's formal authorization to operate to the system owner", "Serve as a full replacement for the entire independent assessment", "Compare implemented controls to planned ones to find what's left", "Determine the system's impact level"], answer: 2, explain: "A gap analysis compares the current implementation state against the SSP's intended implementation to identify remaining work before assessment."),
    Question(id: 347, domain: 4, text: "During implementation, the team discovers that the vendor-provided application cannot log access events. The BEST response is:", options: ["Silently accept the logging limitation and proceed with deployment as planned", "Remove the entire AU audit control family from the SSP to resolve the discrepancy", "Delay the system's deployment indefinitely until the vendor adds the logging feature", "Add a compensating control, note it in the SSP, log the gap in the POA&M"], answer: 3, explain: "When a control cannot be met natively, a compensating control that achieves the same security objective must be documented. The gap and compensating control go into the SSP and POA&M."),
    Question(id: 348, domain: 4, text: "Training and awareness (AT family in SP 800-53) is classified as which type of control?", options: ["Technical", "Management", "Operational", "Privacy"], answer: 2, explain: "Training and awareness is an operational control — it is implemented by people through programs and procedures rather than technology."),
    Question(id: 349, domain: 4, text: "An organization implements a SIEM to collect and correlate security logs. This primarily supports which security objective during operations?", options: ["The initial system impact categorization process", "Audit, accountability, and anomaly detection", "The selection of the security control baseline", "Compiling the authorization package"], answer: 1, explain: "A SIEM aggregates and analyzes logs to support the AU (Audit and Accountability) family and serves as a key tool in continuous monitoring for anomaly detection."),
    Question(id: 350, domain: 4, text: "When obtaining and documenting implementation details from physical security staff, this is important because:", options: ["Physical and environmental controls are entirely optional", "It removes the need to ever conduct a physical site visit", "PE controls are part of the set and go in the SSP", "Physical controls are always common and need no documentation"], answer: 2, explain: "PE controls — badge access, cameras, environmental monitoring — are part of the security baseline and must be documented with implementation details from the responsible organizational entity."),
    Question(id: 351, domain: 4, text: "A system is migrating to a new data center. Which action is MOST important from a security perspective before the migration?", options: ["Notify all of the system's end users by email well beforehand", "Simply update the system's network IP addresses and proceed", "Migrate, then notify the AO afterward", "Run a security impact analysis, update the SSP, use the CCB"], answer: 3, explain: "A data center migration is a significant change — it requires a security impact analysis, SSP updates, CCB approval, and potentially AO notification before proceeding."),

    // MARK: – Domain 5 expansion (Assessment)
    Question(id: 360, domain: 5, text: "Before beginning an assessment, the assessor should review which document to understand the intended control implementations?", options: ["The POA&M only", "The authorization decision memo", "The System Security Plan (SSP)", "The vendor's product documentation"], answer: 2, explain: "The SSP is the primary input to the assessment plan — it documents what controls are implemented and how, which the assessor uses to design test procedures."),
    Question(id: 361, domain: 5, text: "An assessor finds a control that is 'partially implemented.' This finding should be:", options: ["Counted and recorded as fully satisfied overall", "Ignored if the partial implementation seems reasonable", "Reported only to the system administrator informally", "Documented as a weakness in the SAR and POA&M"], answer: 3, explain: "Partially implemented controls are findings — the unimplemented portion represents a gap that must be documented in the SAR and tracked in the POA&M."),
    Question(id: 362, domain: 5, text: "An assessment finds 12 high findings, 20 moderate findings, and 5 low findings. When prioritizing remediation, the team should address:", options: ["High findings first, as they represent the greatest risk to the system", "Low findings first (quickest wins)", "All findings simultaneously regardless of severity", "Only findings the AO specifically requests"], answer: 0, explain: "Risk-based prioritization directs resources to the highest-severity findings first — high findings pose the greatest risk and must be addressed before authorization or as conditions of the ATO."),
    Question(id: 363, domain: 5, text: "A risk response of 'accept' is appropriate when:", options: ["The risk is far too high for the organization to ever reasonably accept", "The corresponding finding has not yet been formally documented anywhere", "The risk is within tolerance and mitigation costs exceed the benefit", "No other risk response option is available to the organization at all"], answer: 2, explain: "Risk acceptance is a valid response when residual risk falls within organizational tolerance — but it must be formally documented and approved by the AO, not assumed."),
    Question(id: 364, domain: 5, text: "ISO/IEC 27005 is primarily focused on:", options: ["Defining minimum security requirements for federal systems", "Technical testing procedures", "Information security risk management processes aligned with ISO 27001", "Media sanitization"], answer: 2, explain: "ISO 27005 provides guidelines for information security risk management, supporting the implementation of an ISMS per ISO 27001."),
    Question(id: 365, domain: 5, text: "During an assessment, the assessor interviews the ISSO about patch management. The ISSO cannot provide evidence that patches are applied within the required timeframe. This indicates:", options: ["The ISSO needs more training only", "No finding is needed if patches were applied eventually", "The control is satisfied if patches are planned", "The control may not be implemented correctly — a finding should be documented"], answer: 3, explain: "Lack of evidence of timely patch application indicates the control is at minimum partially implemented or not operating as intended — this is a finding regardless of intent."),
    Question(id: 366, domain: 5, text: "Which NIST publication provides detailed procedures for assessing SP 800-53 controls?", options: ["SP 800-53A", "SP 800-30", "SP 800-137", "SP 800-39"], answer: 0, explain: "SP 800-53A Rev. 5 provides assessment procedures for each SP 800-53 control, specifying what to examine, who to interview, and what to test."),
    Question(id: 367, domain: 5, text: "The final Security Assessment Report (SAR) should include:", options: ["Only the high-severity findings that were discovered", "Only the findings the system owner agrees with fully", "All findings, with evidence and risk levels", "Only findings from automated scans"], answer: 2, explain: "The SAR must be a complete, objective record of all findings — the AO uses the full SAR to make the authorization decision, not a filtered subset."),
    Question(id: 368, domain: 5, text: "During a NIST SP 800-30 risk assessment, identifying threat sources, threat events, vulnerabilities, and likely impacts is done in order to:", options: ["Characterize risk to prioritize controls", "List only the known CVEs that affect the system", "Serve as a full replacement for the vulnerability scan", "Assign a specific dollar value to every single asset"], answer: 0, explain: "SP 800-30 Rev. 1 frames risk assessment around threat sources, threat events, vulnerabilities, likelihood, and impact to characterize risk and prioritize control decisions, not merely catalog CVEs."),
    Question(id: 369, domain: 5, text: "An organization receives a new cybersecurity advisory about a zero-day vulnerability affecting software used in one of its systems. The FIRST action under the RMF is:", options: ["Wait for the vendor to release a patch before taking any further action", "Notify the affected users and then take no further action on the matter", "Immediately shut the system down", "Assess the vulnerability's impact and whether the risk posture changed"], answer: 3, explain: "A new zero-day requires an immediate security impact analysis — if it materially changes the risk posture, the AO must be notified and the POA&M updated even before a patch is available."),
    Question(id: 370, domain: 5, text: "Vulnerability scanning differs from penetration testing in that:", options: ["Scanning exploits weaknesses; pen testing does not at all", "Scanning finds weaknesses; pen testing exploits them", "They are exactly the same activity under two different names", "Pen testing is fully automated; scanning is manual"], answer: 1, explain: "Vulnerability scans identify potential vulnerabilities; penetration tests go further by attempting to exploit them to demonstrate actual impact and attack paths."),
    Question(id: 371, domain: 5, text: "A Plan of Action and Milestones (POA&M) entry should include:", options: ["The weakness, point of contact, resources, completion date, and milestones", "Only the name of the finding", "Only the estimated remediation cost", "Only the system owner's handwritten signature and printed name on the official form"], answer: 0, explain: "A complete POA&M entry captures the weakness, responsible party, required resources, milestones, and scheduled completion so leadership can track remediation progress."),

    // MARK: – Domain 6 expansion (Authorization)
    Question(id: 380, domain: 6, text: "The authorization decision is based on the AO reviewing which three core documents?", options: ["SSP, network diagram, and vendor contract", "POA&M, penetration test report, and org chart", "SSP, SAR, and POA&M", "SAR, budget, and training records"], answer: 2, explain: "The authorization package minimally includes the SSP (control implementation), SAR (assessment results), and POA&M (weakness remediation plan). The AO reviews all three."),
    Question(id: 381, domain: 6, text: "A system receives an ATO with conditions. This means:", options: ["The authorization to operate has effectively been denied", "Every single one of the controls is fully satisfied now", "The system can operate indefinitely with no further review", "Operation is allowed, with required fixes by a deadline"], answer: 3, explain: "An ATO with conditions (sometimes called a conditional ATO) permits operation while requiring the system owner to remediate specified findings within an agreed timeframe."),
    Question(id: 382, domain: 6, text: "What is the primary difference between risk tolerance and residual risk?", options: ["Tolerance is the acceptable level; residual is what remains", "They are essentially the same underlying risk concept overall", "Residual risk is defined before controls", "Tolerance applies only to high-impact systems"], answer: 0, explain: "The AO compares residual risk (what remains after controls) against organizational risk tolerance (the threshold of acceptable risk) to make the authorization decision."),
    Question(id: 383, domain: 6, text: "After the 2024 FedRAMP changes, a cloud service provider becomes authorized:", options: ["Only through a JAB Provisional ATO, exactly as it worked before", "Through an agency sponsor, as 'FedRAMP Authorized'", "By self-certifying against the published FedRAMP baseline", "Automatically, as soon as it holds any SOC 2 report"], answer: 1, explain: "With the JAB and its P-ATO retired in 2024, every CSP now pursues a single 'FedRAMP Authorized' designation through an agency sponsor, under FedRAMP Board governance."),
    Question(id: 384, domain: 6, text: "The AO's authorization decision letter should document:", options: ["The decision, its terms and conditions, expiration, and accepted risk", "Only the authorizing official's printed name and handwritten signature line", "Only the date the ATO was granted", "Only the system name and its owner"], answer: 0, explain: "The authorization decision letter formally communicates the decision (ATO, DATO, or ATO with conditions), any special terms or restrictions, and the basis for risk acceptance."),
    Question(id: 385, domain: 6, text: "The concept of 'ongoing authorization' requires:", options: ["A full, independent system reassessment performed every three years without fail", "A robust continuous monitoring program keeping the AO's awareness current", "No monitoring at all once the initial ATO is granted", "Congressional approval for each authorization cycle"], answer: 1, explain: "Ongoing authorization replaces periodic reauthorization with continuous monitoring that feeds current security posture data to the AO, enabling real-time risk-based decisions."),
    Question(id: 387, domain: 6, text: "An AO wants to grant authorization but is concerned about one high finding in the POA&M. The BEST course of action is:", options: ["Grant a full ATO and simply ignore the high finding", "Grant an ATO with conditions to fix the finding", "Issue a DATO until the high finding is fully resolved", "Ask the assessor to downgrade the severity of the finding"], answer: 1, explain: "An ATO with conditions allows operation while requiring remediation — balancing mission need against security risk. A DATO is appropriate when risk is truly unacceptable."),

    // MARK: – Domain 7 expansion (Continuous Monitoring)
    Question(id: 390, domain: 7, text: "An organization's risk register is updated during ConMon when:", options: ["Only during the formally scheduled annual risk management review cycle", "New risks emerge or existing risks change from incidents or changes", "Only when the authorizing official specifically requests a register update", "Only when a brand-new authorization to operate is issued for the system"], answer: 1, explain: "The risk register is a living document — it must be updated whenever new risks emerge or existing risks materially change to maintain accurate situational awareness."),
    Question(id: 391, domain: 7, text: "A system experiences a data breach. Under the RMF, the response team should:", options: ["Patch the affected systems and move on without documenting anything at all", "Wait until the next annual assessment to document the entire breach event fully", "Activate the IR plan, coordinate, document lessons, and assess the impact", "Notify only the system owner of the breach"], answer: 2, explain: "A breach triggers the incident response plan, requires stakeholder coordination, and must result in documentation of lessons learned and an assessment of whether the breach materially changes the authorization risk posture."),
    Question(id: 392, domain: 7, text: "Configuration drift refers to:", options: ["Planned, approved changes to the system's architecture over time", "Uncontrolled changes that drift from the secure baseline", "The natural physical aging of the system's hardware components", "Routine, scheduled firmware updates applied to the system"], answer: 1, explain: "Configuration drift occurs when systems gradually deviate from their approved secure baseline — often through unauthorized changes, unapproved patches, or neglected configurations."),
    Question(id: 393, domain: 7, text: "NIST SP 800-137 describes three ISCM tiers. These are:", options: ["Low, Moderate, and High", "Organization, Mission/Business Process, and System", "Prepare, Categorize, and Monitor", "Plan, Do, and Check"], answer: 1, explain: "SP 800-137 aligns ISCM with the SP 800-39 three-tier model: Tier 1 (organization), Tier 2 (mission/business process), and Tier 3 (information system)."),
    Question(id: 394, domain: 7, text: "An organization automates vulnerability scanning on a weekly basis. This supports which ISCM principle?", options: ["Reducing the overall need for continuous monitoring", "Frequent data collection for situational awareness", "Serving as a full replacement for the annual assessment", "Eliminating the system's Plan of Action and Milestones"], answer: 1, explain: "Automation and frequent scanning intervals provide near-real-time data on the system's security posture — a core goal of ISCM per SP 800-137."),
    Question(id: 395, domain: 7, text: "When a regulatory requirement changes (e.g., a new OMB memorandum), the organization should:", options: ["Ignore the regulatory change until the next ATO renewal", "Wait for the next full NIST publication cycle to update it", "Review and update the monitoring strategy and controls", "Only update the SSP's title page"], answer: 2, explain: "Legal and regulatory changes drive updates to the monitoring strategy, control implementations, and SSP — ignoring them creates compliance gaps and authorization risk."),
    Question(id: 396, domain: 7, text: "Which metric is MOST useful for measuring the effectiveness of a patch management control during ConMon?", options: ["The total number of users who completed training during the period", "The number of network firewalls currently deployed", "Mean time to patch (MTTP) from release to deployment", "The system's cumulative total uptime over the year"], answer: 2, explain: "MTTP directly measures how quickly the organization closes known vulnerabilities — a concrete, actionable metric for the patch management control's effectiveness."),
    Question(id: 397, domain: 7, text: "Lessons learned from a security incident should be incorporated into:", options: ["The agency's external public communications plan only", "Only the following year's organization-wide security awareness training plan", "The system's physical network diagram and nothing else", "Updated IR procedures, the ConMon strategy, and control implementations"], answer: 3, explain: "Lessons learned close the feedback loop by improving incident response procedures, tightening control implementations, and refining the monitoring strategy to prevent recurrence."),

    // MARK: – SP 800-18: System Security Plan development (Domain 2 / 3)
    Question(id: 400, domain: 2, text: "NIST SP 800-18 Rev. 1 provides guidance on:", options: ["Conducting formal risk assessments of systems", "Media sanitization and secure disposal procedures", "Continuous monitoring metrics", "Developing security plans (SSPs) for systems"], answer: 3, explain: "SP 800-18 guides system owners through the process of developing, documenting, and maintaining an SSP — the primary document describing system controls and the authorization boundary."),
    Question(id: 401, domain: 2, text: "According to SP 800-18, who is responsible for developing and maintaining the System Security Plan?", options: ["The independent Security Control Assessor for it", "The agency's Authorizing Official for the system", "The Information System Owner, with ISSO help", "The agency's Chief Information Officer himself directly"], answer: 2, explain: "SP 800-18 places SSP development responsibility on the Information System Owner, typically with day-to-day support from the ISSO."),
    Question(id: 402, domain: 3, text: "The System Security Plan (SSP) serves as the primary input to all of the following EXCEPT:", options: ["The hiring plan for new employees", "The security assessment", "The authorization decision", "The POA&M"], answer: 0, explain: "The SSP drives the assessment plan, informs the AO's authorization decision, and is the baseline against which POA&M weaknesses are measured — it has no role in HR hiring."),
    Question(id: 403, domain: 3, text: "When a control is documented as 'not applicable' in the SSP, the system owner must:", options: ["Provide a justification for why the control does not apply", "Leave the corresponding SSP field completely blank for the assessor", "Obtain formal congressional approval first", "Remove the control from the SSP entirely"], answer: 0, explain: "Every 'not applicable' determination requires documented justification — assessors and the AO must be able to verify the scoping rationale."),

    // MARK: – SP 800-122: PII Protection (Domain 1 / 2 / 5)
    Question(id: 410, domain: 1, text: "NIST SP 800-122 defines Personally Identifiable Information (PII) as:", options: ["Any information that can identify an individual, alone or with linkable data", "Only Social Security Numbers together with the individual's financial account data", "Only data stored within official government-operated databases and record systems", "Only biometric identifiers such as fingerprints"], answer: 0, explain: "SP 800-122 broadly defines PII as any information that alone or in combination can identify a specific individual — including name, SSN, date of birth, address, biometrics, and more."),
    Question(id: 411, domain: 1, text: "De-identification of PII means:", options: ["Encrypting the PII at rest using the AES-256 algorithm everywhere", "Archiving all of the PII inside a separate secure database system", "Transferring the PII to a third party", "Removing or obscuring data so it can't identify an individual"], answer: 3, explain: "De-identification removes or alters PII elements so the data cannot reasonably be used to identify an individual — reducing privacy risk while potentially retaining analytical value."),
    Question(id: 412, domain: 2, text: "When determining a PII confidentiality impact level under SP 800-122, which factor is considered?", options: ["The age of the records combined with the encryption algorithm currently applied", "Identifiability, quantity, field sensitivity, context, and potential harms", "Only the total volume of records held by the system", "Only whether encryption is currently in use"], answer: 1, explain: "SP 800-122 uses multiple factors to assess PII confidentiality impact: identifiability, quantity, sensitivity of fields, context, and the potential harms (embarrassment, discrimination, financial loss) from a breach."),
    Question(id: 413, domain: 5, text: "A system breach exposes 10,000 records containing names and Social Security Numbers. Under SP 800-122, the FIRST priority is:", options: ["Immediately notify the news media and issue a public statement about the breach", "Archive all of the exposed records to preserve them for a later forensic investigation", "Assess scope, notify affected individuals and authorities, and remediate", "Upgrade the system's encryption algorithm to a stronger FIPS-approved cipher suite"], answer: 2, explain: "SP 800-122 and OMB guidance require rapid breach response: contain, assess scope, notify affected individuals and oversight bodies, and remediate — in that order."),

    // MARK: – GDPR (Domain 1)
    Question(id: 420, domain: 1, text: "Under GDPR, a 'data controller' is:", options: ["Any employee who handles data", "A supervisory authority that enforces GDPR", "The entity that determines the purposes and means of processing personal data", "A cloud provider that stores data on behalf of a client"], answer: 2, explain: "The data controller decides WHY and HOW personal data is processed. The data processor acts on the controller's behalf."),
    Question(id: 421, domain: 1, text: "Under GDPR, a 'data processor' is:", options: ["An entity processing data for the controller", "The individual whose personal data is processed", "The national data protection supervisory authority", "Any organization subject to GDPR"], answer: 0, explain: "A data processor handles personal data only as instructed by the controller — e.g., a cloud vendor storing a client's customer data. Processors have specific GDPR obligations."),
    Question(id: 422, domain: 1, text: "GDPR requires organizations to report a personal data breach to the supervisory authority within:", options: ["Within exactly 24 hours of the breach first occurring", "Within 72 hours of becoming aware (if feasible)", "Within 7 full calendar days of the breach happening", "Within 30 full calendar days of becoming aware of it"], answer: 1, explain: "GDPR Article 33 requires breach notification to the competent supervisory authority within 72 hours of becoming aware, unless the breach is unlikely to result in risk to individuals."),
    Question(id: 423, domain: 1, text: "Which of the following is NOT one of GDPR's six lawful bases for processing personal data?", options: ["Consent", "Commercial advantage", "Legitimate interests", "Legal obligation"], answer: 1, explain: "GDPR Article 6 lists six lawful bases: consent, contract, legal obligation, vital interests, public task, and legitimate interests. Commercial advantage alone is not a lawful basis."),
    Question(id: 424, domain: 1, text: "A GDPR Data Protection Impact Assessment (DPIA) is required when processing:", options: ["Any processing of personal data at all, of absolutely any kind", "Only the data of EU citizens located outside of the EU", "Only the data that is processed by the public authorities", "Processing likely to be high-risk to rights"], answer: 3, explain: "GDPR Article 35 requires a DPIA when processing is likely to result in high risk — examples include large-scale systematic monitoring, processing special category data at scale, or automated decision-making with significant effects."),
    Question(id: 425, domain: 1, text: "GDPR's 'right to erasure' (right to be forgotten) allows individuals to:", options: ["Delete any data about themselves at any time with no exceptions", "Erase data from all third-party systems globally", "Override legal obligations to retain data", "Request deletion of their data in specific circumstances"], answer: 3, explain: "Article 17 grants the right to erasure in specific circumstances — but it is not absolute. Exceptions apply when processing is required for legal obligations, public interest, or legal claims. Such as when consent is withdrawn or data is no longer necessary."),
    Question(id: 426, domain: 1, text: "GDPR's principle of 'data minimization' requires that personal data be:", options: ["Encrypted at absolutely all times without exception", "Stored indefinitely for any kind of possible future use", "Shared freely with authorized partners", "Adequate, relevant, and limited to what's needed"], answer: 3, explain: "Data minimization (Article 5(1)(c)) requires collecting only the minimum personal data necessary for the specified, explicit, and legitimate purpose."),
    Question(id: 427, domain: 1, text: "Under GDPR, 'Privacy by Design and by Default' (Article 25) requires:", options: ["Adding the necessary privacy controls only after the system is fully deployed", "Obtaining explicit consent for every processing activity", "Conducting a DPIA for every single system", "Technical and organizational measures embedding data protection by default"], answer: 3, explain: "Article 25 mandates that data protection be embedded into systems and processes from the outset (by design) and that the most privacy-protective settings be the default (by default)."),
    Question(id: 428, domain: 1, text: "A U.S. company transfers personal data of EU residents to its U.S. headquarters. Under GDPR, this transfer requires:", options: ["No safeguards, because US transfers are always permitted", "Only a basic data processing agreement between the parties", "An approved transfer mechanism such as SCCs, adequacy, or BCRs", "Only encryption of the personal data while it is in transit over the network"], answer: 2, explain: "GDPR Chapter V restricts transfers to third countries without adequate protection. Approved mechanisms include EC adequacy decisions, Standard Contractual Clauses (SCCs), or Binding Corporate Rules."),
    Question(id: 429, domain: 1, text: "GDPR's 'right to data portability' (Article 20) gives individuals the right to:", options: ["Delete all of their personal data from any system", "Receive their data in a portable format and send it to another controller", "Access every single piece of personal data that an organization holds about them", "Object to all forms of automated decision processing"], answer: 1, explain: "Article 20 allows data subjects to receive their data in a portable format and transmit it to another controller — promoting switching and interoperability."),

    // MARK: – ISO 27001 / ISMS (Domain 1 / 3)
    Question(id: 430, domain: 1, text: "The ISO 27001 Plan-Do-Check-Act (PDCA) cycle maps to which ISMS activities?", options: ["Plan=establish ISMS, Do=implement/operate, Check=monitor/review, Act=maintain/improve", "Plan=select controls, Do=assess, Check=authorize, Act=monitor", "Plan=risk assess, Do=patch, Check=audit, Act=decommission", "Plan=categorize, Do=select, Check=implement, Act=assess"], answer: 0, explain: "ISO 27001 applies the PDCA model: Plan (establish context, risk assessment, objectives), Do (implement controls), Check (monitor, measure, audit), Act (corrective/continual improvement)."),
    Question(id: 431, domain: 1, text: "The Statement of Applicability (SoA) in ISO 27001 is:", options: ["A document of which Annex A controls apply", "A list of all the employees with security access", "The ISMS certification audit final report document", "The organization's overall enterprise risk register"], answer: 0, explain: "The SoA is a mandatory ISO 27001 document that lists all controls from Annex A, states whether each is applied, and justifies any exclusions — it links risk treatment decisions to control implementation."),
    Question(id: 432, domain: 1, text: "ISO 27001 Annex A provides:", options: ["A certification checklist", "Mandatory controls that must all be implemented without exception", "A reference set of information security controls that can be selected during risk treatment", "A prescriptive technical configuration guide"], answer: 2, explain: "Annex A is a normative reference of control objectives and controls. Organizations select applicable controls based on their risk assessment — not all controls must be implemented."),
    Question(id: 433, domain: 1, text: "For ISO 27001 certification, an organization undergoes a two-stage audit. Stage 1 is:", options: ["An on-site assessment of control effectiveness", "A documentation review of the ISMS design", "A penetration test of the organization's systems", "A financial audit of the budget"], answer: 1, explain: "Stage 1 (documentation/readiness review) checks that the ISMS documentation is complete and the organization is ready for implementation assessment. Stage 2 then verifies actual implementation."),
    Question(id: 434, domain: 3, text: "ISO 27002 provides:", options: ["Requirements an organization must meet for certification", "A legally binding data protection framework to follow", "A formal risk assessment methodology for systems", "Guidance for implementing Annex A controls"], answer: 3, explain: "ISO 27002 is a guidance document — it elaborates on how to implement the controls listed in ISO 27001 Annex A, but it is not certifiable on its own."),
    Question(id: 435, domain: 1, text: "ISO 31000 provides a framework for:", options: ["Selection of information security controls for systems and nothing else", "Compliance with the EU GDPR", "General risk-management principles for any organization and risk", "An IT audit methodology"], answer: 2, explain: "ISO 31000 is a generic risk management standard — its principles and framework apply to all types of risk across any organization or sector, not just information security."),

    // MARK: – Policy Hierarchy (Domain 1 / 4)
    Question(id: 440, domain: 1, text: "In the security policy hierarchy, which document is MOST authoritative?", options: ["Procedure", "Standard", "Policy", "Guideline"], answer: 2, explain: "Policies are the highest-level, management-approved documents that state organizational intent and requirements. Standards, procedures, and guidelines flow from policies."),
    Question(id: 441, domain: 1, text: "A security standard differs from a security policy in that a standard:", options: ["Mandatory, measurable requirements supporting the policy", "It needs management approval, whereas policies do not need it", "It is entirely optional and purely advisory in its overall nature", "It applies only to the organization's technical staff members"], answer: 0, explain: "Standards define specific, measurable requirements derived from policies — e.g., 'passwords must be at least 12 characters.' They are mandatory, unlike guidelines."),
    Question(id: 442, domain: 1, text: "A security procedure provides:", options: ["High-level strategic direction from senior management", "Optional best-practice recommendations to consider", "Step-by-step instructions to carry out a task", "Specific mandatory config values"], answer: 2, explain: "Procedures are step-by-step instructions (how-to documents) that implement policies and standards — they tell users exactly what to do in a given situation."),
    Question(id: 443, domain: 1, text: "A security guideline is BEST described as:", options: ["A mandatory requirement that is enforceable through policy", "A detailed step-by-step operational instruction to follow", "A binding legal regulation", "A recommended, advisory practice offering flexibility"], answer: 3, explain: "Guidelines are advisory — they offer recommended practices that are not mandatory, allowing discretion where rigid standards would be impractical."),
    Question(id: 444, domain: 1, text: "A policy exception process is important because:", options: ["It is a formal, documented, risk-accepted way to deviate temporarily", "It permanently removes the underlying policy requirement from the program", "It allows essentially anyone to bypass the required security controls", "It removes the need for any compensating controls during the deviation"], answer: 0, explain: "Policy exceptions must be formally requested, justified, risk-assessed, and approved — creating an audit trail. They are time-limited and require compensating controls where feasible."),

    // MARK: – IT Auditing (Domain 5)
    Question(id: 450, domain: 5, text: "A compliance audit in the IT security context verifies that:", options: ["The organization's systems are profitable", "The network is performing at optimal speed", "Users are generally satisfied with the IT services that are being provided", "Controls are implemented and operating per laws, regulations, and policy"], answer: 3, explain: "Compliance audits test whether an organization meets specified requirements — laws, regulations (FISMA, HIPAA), and internal policies — making them central to the CGRC domain."),
    Question(id: 451, domain: 5, text: "Audit independence is important because:", options: ["An independent auditor is free of biasing conflicts", "Audit findings should always come from internal staff members", "It reduces the overall cost of the audit", "Independent auditors need no evidence"], answer: 0, explain: "Assessor/auditor independence is fundamental to objective findings — an assessor who also implements or manages controls cannot objectively assess their own work."),
    Question(id: 452, domain: 5, text: "During an IT audit, the auditor uses sampling because:", options: ["It is explicitly required by FISMA", "Sampling is less accurate than full testing", "Testing everything is impractical; a representative sample suffices", "Sampling removes any need to review the supporting documentation at all"], answer: 2, explain: "Audit sampling selects a representative subset of transactions or records to test — if the sample shows the control is operating effectively, the auditor can reasonably conclude it applies to the population."),
    Question(id: 453, domain: 5, text: "Audit evidence must be:", options: ["Sufficient, reliable, relevant, and useful", "Only ever digital and fully automated in nature", "Provided only by the system owner personally themselves", "Kept strictly confidential away from the AO"], answer: 0, explain: "The quality of audit evidence is measured by its sufficiency (enough to support the conclusion), reliability (trustworthy source), relevance (directly related to the objective), and usefulness."),
    Question(id: 454, domain: 5, text: "Which type of audit tests whether controls are not only in place but actually reducing risk in practice?", options: ["Compliance audit", "Financial audit", "Physical security audit", "Operational effectiveness audit"], answer: 3, explain: "An operational effectiveness audit goes beyond checking whether a control exists (design/compliance) to verify it is actually operating as intended and achieving its risk-reduction goal."),
    Question(id: 455, domain: 5, text: "An audit finding that a control exists in policy but is not practiced by staff is an example of:", options: ["A control operating effectiveness deficiency", "A control design deficiency", "A compliance audit exemption", "A satisfactory finding"], answer: 0, explain: "When the control design is adequate but staff are not following it, the deficiency is in operating effectiveness — the control exists on paper but not in practice."),

    // MARK: – Enterprise Cyber Risk Management Program (Domain 1)
    Question(id: 460, domain: 1, text: "Integrating cybersecurity risk into Enterprise Risk Management (ERM) is important because:", options: ["Cyber risk is one of many enterprise risks ERM weighs consistently with the rest", "It lets the organization transfer all of its cyber risk to an outside insurance carrier", "It satisfies the NIST RMF requirement to authorize each system before operation", "It removes the need to perform any separate system-level risk assessment"], answer: 0, explain: "Cyber risk does not exist in isolation — ERM integration ensures that cyber risks are measured alongside financial, operational, and strategic risks so leadership can make informed, holistic decisions."),
    Question(id: 461, domain: 1, text: "A risk appetite statement at the board level is MOST useful for:", options: ["Defining the specific firewall rules that govern the production network perimeter", "Setting the individual access levels granted to each user account across the enterprise", "Replacing the system-level authorization process", "Communicating how much risk the organization will accept to meet its objectives"], answer: 3, explain: "A board-level risk appetite statement sets the tone for the entire organization's risk culture — all risk management decisions, including system authorizations, should be consistent with it."),
    Question(id: 462, domain: 1, text: "Key Risk Indicators (KRIs) in a cyber risk program are:", options: ["Metrics measuring only the outcome of past incidents", "Forward-looking signals of rising risk exposure", "Exactly the same thing as Key Performance Indicators", "Only applicable to financial risk"], answer: 1, explain: "KRIs are predictive signals — e.g., increasing unpatched critical vulnerabilities or rising phishing click rates — that warn of growing risk before it materializes into an incident."),
    Question(id: 463, domain: 1, text: "An organization's security program is considered risk-based when:", options: ["It implements every single available security control fully", "Controls are prioritized by risk to mission-critical assets", "It always spends the maximum possible security budget allowed", "It complies with all regulations regardless of risk"], answer: 1, explain: "A risk-based program focuses limited resources where they reduce the greatest risk — not on achieving compliance for its own sake or maximizing control coverage indiscriminately."),

    // MARK: – SP 800-53 Control Families deep-cut (Domain 3 / 4)
    Question(id: 470, domain: 3, text: "The SA (System and Services Acquisition) control family in SP 800-53 addresses:", options: ["Building security and privacy requirements into acquisitions and the SDLC", "Management of individual user accounts", "Detection, analysis, and handling of security incident response procedures", "Protection of media throughout its lifecycle"], answer: 0, explain: "The SA family ensures that security and privacy requirements are built into procurement, contracts, and the SDLC — covering developer security requirements, supply chain, and acquisition policies."),
    Question(id: 471, domain: 3, text: "The SR (Supply Chain Risk Management) control family was added to SP 800-53 Rev. 5 to address:", options: ["Physical security of the server rooms that house the organization's hardware", "Risks from hardware, software, and services acquired via the supply chain", "Social-engineering risks that target the organization's employees and contractors", "Internal software developer insider threats only"], answer: 1, explain: "The SR family (new in Rev. 5) provides controls for managing supply chain risks — vetting suppliers, protecting against tampering, and maintaining supply chain integrity."),
    Question(id: 472, domain: 4, text: "The RA (Risk Assessment) control family requires organizations to:", options: ["Conduct risk assessments only at the system's initial authorization", "Periodically assess risk, including scanning, threat intel, and updates", "Delegate all of the risk assessment work entirely to the independent assessor", "Conduct risk assessments only when specifically requested by the AO"], answer: 1, explain: "The RA family requires ongoing risk assessment activities — periodic reviews, vulnerability scanning (RA-5), and updating risk assessments based on new threats and changes."),
    Question(id: 473, domain: 4, text: "The IR (Incident Response) control family ensures organizations:", options: ["The complete prevention of all security incidents ever", "Reporting incidents only to outside law enforcement", "A capability to handle incidents end to end", "Incident response only for the classified systems"], answer: 2, explain: "The IR family covers the full incident response lifecycle: planning, training, testing, detection, analysis, containment, eradication, recovery, and post-incident review."),
    Question(id: 474, domain: 4, text: "The CA (Assessment, Authorization, and Monitoring) control family includes controls for:", options: ["Only the access control policy and its procedures", "Physical access control to the facilities and the server rooms within them only", "Assessments, authorization, monitoring, pen testing, and interconnections", "Only the network perimeter and boundary controls"], answer: 2, explain: "The CA family covers the assessment and authorization process itself — including control assessments (CA-2), authorization (CA-6), penetration testing (CA-8), continuous monitoring (CA-7), and system interconnections (CA-3)."),

    // MARK: – Scenario: Cross-domain integrative questions
    Question(id: 480, domain: 1, text: "A CISO presents the board with a report showing that 40% of critical systems have high-risk findings open beyond 90 days. From an enterprise risk perspective, this indicates:", options: ["That the security team is performing its remediation duties very effectively indeed", "Merely a documentation problem with no real impact", "A systemic risk-management failure needing executive attention and resources", "An acceptable baseline for large enterprises"], answer: 2, explain: "Systemic overdue high-risk POA&M items signal that the risk management program is not functioning effectively — this is a board-level concern requiring resource prioritization and executive accountability."),
    Question(id: 481, domain: 5, text: "A system undergoes its first formal assessment. The assessor is the same person who helped design the controls. This situation:", options: ["Is acceptable because the person knows the system best", "Is required by NIST for efficiency", "Only matters for high-impact systems", "Violates assessor independence"], answer: 3, explain: "Assessor independence is a core requirement. Someone who designed or implemented controls cannot objectively assess their own work — the assessment loses credibility and objectivity. The assessor has a conflict of interest and cannot objectively evaluate controls they helped design."),
    Question(id: 483, domain: 7, text: "An organization's ConMon program generates weekly vulnerability scan results but no one reviews them. This is BEST described as:", options: ["An effective and fully automated continuous monitoring program", "Acceptable as long as a quarterly review happens later", "Normal for any large organization", "A gap — collecting data without review adds no value"], answer: 3, explain: "ConMon is only effective when data is collected AND acted upon. Unreviewed scan results mean the organization has no actual situational awareness despite the appearance of monitoring."),

    // MARK: – Batch 2: Domain 1 expansion (+59)
    Question(id: 500, domain: 1, text: "The NIST Privacy Framework (2020) core functions are:", options: ["Frame, Assess, Respond, Monitor", "Identify, Protect, Detect, Respond, Recover", "Identify-P, Govern-P, Control-P, Communicate-P, Protect-P", "Plan, Do, Check, Act"], answer: 2, explain: "The NIST Privacy Framework core consists of five functions: Identify-P, Govern-P, Control-P, Communicate-P, and Protect-P — parallel to but distinct from the Cybersecurity Framework."),
    Question(id: 501, domain: 1, text: "OMB Circular A-130 requires federal agencies to:", options: ["Integrate privacy and security and report to OMB yearly", "Purchase only software that is made in the United States", "Conduct monthly penetration tests", "Use only FedRAMP-authorized cloud"], answer: 0, explain: "OMB Circular A-130 (Managing Federal Information as a Strategic Resource) establishes policy for planning, budgeting, governance, acquisition, and management of federal information, including privacy and security integration."),
    Question(id: 502, domain: 1, text: "The Gramm-Leach-Bliley Act (GLBA) primarily applies to:", options: ["Healthcare providers and their associated business partners", "Federal government agencies and absolutely nobody else at all", "Financial institutions handling consumers' nonpublic data", "Educational institutions and all of their student record systems"], answer: 2, explain: "GLBA requires financial institutions (banks, insurers, securities firms) to protect the privacy and security of consumer financial information through Safeguards Rule requirements."),
    Question(id: 503, domain: 1, text: "FERPA (Family Educational Rights and Privacy Act) protects:", options: ["Financial records of taxpayers", "Education records and the privacy rights of students", "Medical records of patients", "Criminal history records"], answer: 1, explain: "FERPA governs access to and disclosure of educational records, giving parents (and eligible students) rights to inspect, amend, and control disclosure of education records."),
    Question(id: 504, domain: 1, text: "Sarbanes-Oxley (SOX) Section 404 requires:", options: ["All companies everywhere to adopt the full NIST control set", "Public companies to assess financial controls", "Healthcare companies to encrypt all of their patient data", "Federal agencies to conduct annual enterprise risk assessments"], answer: 1, explain: "SOX Section 404 mandates management assessment and external auditor attestation of internal controls over financial reporting — driving IT controls around data integrity and audit trails."),
    Question(id: 505, domain: 1, text: "Executive Order 14028 (Improving the Nation's Cybersecurity, 2021) directed federal agencies to:", options: ["Stop using all commercial cloud services across the entire federal government", "Classify every piece of government data as high impact under the FIPS 199 standard", "Replace all of the agency's remaining legacy systems within a strict 90-day window", "Adopt Zero Trust, secure the software supply chain, and improve detection"], answer: 3, explain: "EO 14028 directed agencies to adopt Zero Trust principles, improve software supply chain security, deploy endpoint detection/response, and enhance government-wide cyber incident sharing."),
    Question(id: 506, domain: 1, text: "Zero Trust Architecture is based on the principle:", options: ["Trust all internal network traffic by default always", "Block every external connection to the network outright", "Trust verified users permanently after first login", "Never trust, always verify every request"], answer: 3, explain: "Zero Trust eliminates the concept of implicit trust based on network location. Every access request is continuously verified based on identity, device health, and context."),
    Question(id: 507, domain: 1, text: "The NIST Cybersecurity Framework (CSF) Tiers describe:", options: ["The system impact levels of Low, Moderate, and High overall", "Cyber risk-management maturity, from Partial to Adaptive", "The total number of security controls that are implemented", "The required assessment frequency"], answer: 1, explain: "CSF Tiers (1–4) characterize the rigor and sophistication of an organization's cybersecurity risk management practices — from informal/reactive (Tier 1) to agile and risk-informed (Tier 4)."),
    Question(id: 508, domain: 1, text: "A CSF Profile represents:", options: ["A vendor's product security certification", "The result of a recent penetration test", "A single system's assigned FIPS 199 security category and impact levels", "The organization's current and target posture aligned to its mission"], answer: 3, explain: "A CSF Profile maps the organization's selected outcomes from the CSF Core to its business requirements, risk tolerance, and resources — current profile vs. target profile drives prioritized improvement."),
    Question(id: 509, domain: 1, text: "The Senior Agency Information Security Officer (SAISO), also called the CISO, is responsible for:", options: ["Making the individual authorization-to-operate decisions for systems", "Assessing each of the individual controls", "Approving all of the user accounts", "Carrying out the CIO's security duties as the primary liaison"], answer: 3, explain: "The SAISO/CISO implements the agency's information security program under the CIO, coordinates with the AO and system owners, and serves as the primary point of contact for security matters."),
    Question(id: 510, domain: 1, text: "A Privacy Officer (or Chief Privacy Officer) is primarily responsible for:", options: ["Ensuring information activities comply with privacy law and managing risk", "Authorizing each of the organization's information systems to operate fully", "Selecting the system's security controls", "Conducting the organization's penetration tests"], answer: 0, explain: "The Privacy Officer oversees privacy compliance, conducts PIAs, manages privacy risk, and ensures the organization's data collection and processing practices align with legal requirements."),
    Question(id: 511, domain: 1, text: "Threat intelligence sharing between government agencies is encouraged primarily to:", options: ["Reduce each individual agency's annual budget", "Replace each organization's own risk assessments", "Let organizations share emerging-threat knowledge for collective defense", "Satisfy the annual FISMA reporting requirements and absolutely nothing else"], answer: 2, explain: "Sharing threat intelligence (indicators of compromise, TTPs, vulnerabilities) enables organizations to detect and respond to threats faster — a core principle behind ISACs and the CISA framework."),
    Question(id: 512, domain: 1, text: "COPPA (Children's Online Privacy Protection Act) governs:", options: ["Collecting data from children under 13 online", "The overall security of payment card transaction data", "The privacy of personal medical health records", "Data retention for federal agencies"], answer: 0, explain: "COPPA requires verifiable parental consent before collecting, using, or disclosing personal information from children under 13, and mandates privacy policies and data security measures."),
    Question(id: 513, domain: 1, text: "A risk register is BEST described as:", options: ["A running log of all the user access events occurring on the system", "An appendix that is attached to the System Security Plan document", "A record of risks with likelihood, impact, and owner", "A chronological list of all the security incidents that have occurred"], answer: 2, explain: "The risk register is a living document that tracks all identified risks, their assessment (likelihood × impact), risk responses, residual risk, and ownership — a key artifact for ongoing risk management."),
    Question(id: 514, domain: 1, text: "The concept of 'defense in depth' means:", options: ["Deploying just one single, highly capable security control", "Defending only the outer network perimeter of the system", "Layered controls so one failure won't break the system", "Using encryption as the only protection"], answer: 2, explain: "Defense in depth employs multiple overlapping security layers (perimeter, network, host, application, data) so an attacker must defeat multiple controls — reducing the likelihood of a complete compromise."),
    Question(id: 515, domain: 1, text: "Which framework maps cybersecurity activities to business drivers and helps organizations communicate cybersecurity risk to executives?", options: ["NIST SP 800-53", "NIST Cybersecurity Framework (CSF)", "FIPS 199", "SP 800-30"], answer: 1, explain: "The NIST CSF uses business-friendly language to connect security activities to organizational goals, making it suitable for executive-level communication and cross-sector adoption."),
    Question(id: 516, domain: 1, text: "The concept of 'least functionality' in system security means:", options: ["Configure the system to provide only the functions its mission requires", "Always selecting the cheapest available server hardware for the system build", "Allowing each user account only a minimum number of failed login attempts", "Limiting how many security controls are selected"], answer: 0, explain: "Least functionality (SP 800-53 CM-7) requires disabling unused ports, protocols, functions, and services — reducing attack surface by ensuring systems do only what is needed."),
    Question(id: 517, domain: 1, text: "An organization's information security program must align with its:", options: ["The organization's signed vendor contracts and nothing else", "The stated preferences of the IT department's staff members", "Only the findings from the organization's most recent audit", "The mission, goals, and risk tolerance"], answer: 3, explain: "Security programs must serve organizational missions — controls, investments, and priorities should reflect what the organization is trying to achieve and how much risk it is willing to accept."),
    Question(id: 518, domain: 1, text: "Which NIST publication specifically addresses managing information security risk at the organizational level?", options: ["SP 800-39", "SP 800-53", "SP 800-37", "SP 800-30"], answer: 0, explain: "SP 800-39 addresses risk management at all three tiers — organization, mission/business process, and system — with a focus on the organizational (Tier 1) risk management strategy."),
    Question(id: 519, domain: 1, text: "The Federal Information Security Modernization Act (FISMA) 2014 updated FISMA 2002 primarily to:", options: ["Eliminate the Risk Management Framework requirement", "Strengthen DHS's role and incident reporting", "Mandate the broad use of commercial cloud services", "Require quarterly audits of all federal systems"], answer: 1, explain: "FISMA 2014 enhanced DHS's operational cybersecurity authorities, improved federal incident response coordination, and strengthened OMB oversight of agency security programs."),
    Question(id: 520, domain: 1, text: "A business impact analysis (BIA) identifies:", options: ["The full list of security controls that the system must implement to comply", "Critical business functions, their dependencies, and disruption impacts", "Only the financial losses resulting from incidents", "The organization's overall risk tolerance"], answer: 1, explain: "A BIA determines which functions are most critical, what resources they depend on, and what the impact of disruption would be — essential input for contingency planning and recovery prioritization."),
    Question(id: 521, domain: 1, text: "A maximum tolerable downtime (MTD) is:", options: ["The longest a process can be down before unacceptable harm", "The time it takes to restore a system after a failure occurs", "The recovery time objective that is defined for the system overall", "The required backup frequency"], answer: 0, explain: "MTD (also called Maximum Tolerable Period of Disruption — MTPD) defines the absolute limit of acceptable downtime before the disruption causes mission-critical harm — it drives the RTO and RPO targets."),
    Question(id: 522, domain: 1, text: "Recovery Time Objective (RTO) is:", options: ["The maximum acceptable amount of data loss, measured in time", "The amount of time between consecutive system backups", "The time to detect an incident", "How fast a system must be restored after disruption"], answer: 3, explain: "RTO specifies how quickly a system must be restored after a disruption. It must be less than the MTD and drives decisions about backup infrastructure, failover capability, and recovery procedures."),
    Question(id: 523, domain: 1, text: "Recovery Point Objective (RPO) defines:", options: ["How quickly systems must be restored", "The maximum acceptable amount of data loss measured in time", "The minimum system uptime percentage", "The frequency of security assessments"], answer: 1, explain: "RPO defines the point in time to which data must be recovered — if RPO is 4 hours, backups must occur at least every 4 hours so no more than 4 hours of data is lost in a disruption."),
    Question(id: 524, domain: 1, text: "Which role in the RMF is accountable for the mission/business process and defines the security requirements that systems must meet?", options: ["System Owner", "Security Control Assessor", "Mission/Business Owner", "Common Control Provider"], answer: 2, explain: "Mission/Business Owners (Tier 2) are responsible for the mission and business processes the system supports — they define requirements and resource needs that flow down to system owners."),
    Question(id: 525, domain: 1, text: "A System Owner who discovers their system is processing data beyond its original authorization should:", options: ["Just continue operations since the data is already there", "Delete the data immediately without telling the AO", "Report it, update the SSP, and maybe recategorize", "Simply wait until the next annual system review cycle"], answer: 2, explain: "Processing data beyond the original authorization scope may change the system's impact level and risk posture — the SSP must be updated and the AO notified to maintain a valid authorization."),
    Question(id: 526, domain: 1, text: "Which of the following BEST describes the relationship between the RMF and the SDLC?", options: ["They are separate, fully independent processes", "RMF steps are integrated across all SDLC phases, start to disposal", "The RMF entirely replaces the SDLC process", "All SDLC security activities happen only after the ATO has been granted"], answer: 1, explain: "SP 800-37 Rev. 2 explicitly maps RMF tasks to SDLC phases — security is not bolted on at the end but integrated continuously from system design through decommissioning."),
    Question(id: 527, domain: 1, text: "Which statutory requirement mandates that agencies conduct risk-based, cost-effective information security programs?", options: ["HIPAA Security Rule", "FISMA", "SOX Section 404", "PCI-DSS"], answer: 1, explain: "FISMA mandates risk-based, cost-effective information security programs for federal agencies — establishing the legislative foundation for the NIST RMF."),
    Question(id: 529, domain: 1, text: "An organization uses a shared responsibility model with a cloud provider. This means:", options: ["The cloud provider alone is responsible for all of the security", "The customer has no security obligations of any kind whatsoever", "Shared responsibility removes any need to obtain a system ATO", "Security duties are split between provider and customer"], answer: 3, explain: "In cloud shared responsibility models (e.g., IaaS, PaaS, SaaS), the provider secures the underlying infrastructure while the customer remains responsible for data, identities, configurations, and applications at their layer."),
    Question(id: 530, domain: 1, text: "A Chief Risk Officer (CRO) in an organization is most directly responsible for:", options: ["Approving the individual authorization-to-operate for each system", "Implementing all of the organization's technical security controls", "Overseeing enterprise-wide risk management and advising leaders", "Conducting the security assessments"], answer: 2, explain: "The CRO leads enterprise risk management — identifying, measuring, and managing all categories of risk (financial, operational, cyber) to inform strategic decision-making."),
    Question(id: 531, domain: 1, text: "The concept of 'inherent risk' is best defined as:", options: ["The risk that exists before any controls", "The risk remaining after controls are applied", "The specific risk the AO formally accepts", "Risk transferred to a third party"], answer: 0, explain: "Inherent risk is the raw, unmitigated risk — the exposure that would exist if no controls were in place. It provides the baseline for evaluating how much controls reduce risk."),
    Question(id: 532, domain: 1, text: "Which of the following is an example of a qualitative risk assessment approach?", options: ["Calculating annual loss expectancy (ALE) in dollars", "Quantifying exposure factor as a percentage", "Rating risks as High/Medium/Low using expert judgment and descriptive scales", "Computing single loss expectancy (SLE)"], answer: 2, explain: "Qualitative risk assessments use descriptive scales (High/Medium/Low, Red/Yellow/Green) and expert judgment rather than precise financial calculations — faster and more practical when data is limited."),
    Question(id: 534, domain: 1, text: "A vulnerability is BEST defined as:", options: ["A threat actor with the intent to harm the system", "A weakness a threat source could exploit", "The potential damage from a successful attack", "A single missing security patch on the system"], answer: 1, explain: "A vulnerability is a flaw or weakness — in code, configuration, process, or design — that a threat source could exploit to cause harm. Vulnerabilities alone don't cause harm without a threat to exploit them."),
    Question(id: 535, domain: 1, text: "A threat is BEST defined as:", options: ["A weakness in a system that a threat source is able to exploit", "The residual risk that remains after controls have been applied", "The likelihood that a particular vulnerability will actually be exploited by a capable adversary", "Any circumstance or event with the potential to adversely impact organizational operations"], answer: 3, explain: "A threat is the potential for a threat source (adversary, nature, accident) to exercise a specific threat event (exploit, disaster, error) against a vulnerable system."),
    Question(id: 537, domain: 1, text: "Information assurance (IA) extends information security by also addressing:", options: ["Only the confidentiality, integrity, and availability triad itself", "Only the encryption of data at rest and in transit", "Only the access control of system resources", "Authenticity and non-repudiation, on top of the CIA triad"], answer: 3, explain: "IA (as defined by the DoD Five Pillars) extends the CIA triad by adding authenticity (verifying origin/identity) and non-repudiation (preventing denial of actions taken)."),
    Question(id: 538, domain: 1, text: "An organization's risk management strategy should be documented in:", options: ["An organization-level strategy reflecting Tier 1 decisions", "The System Security Plan written for each individual system", "Within each individual system's Plan of Action and Milestones", "The security assessment report"], answer: 0, explain: "Per SP 800-39, the organization (Tier 1) risk management strategy documents risk framing assumptions, risk tolerance, risk response strategy, and monitoring approach — used by all lower tiers."),
    Question(id: 539, domain: 1, text: "Which of the following is NOT a component of the risk management process defined in SP 800-39?", options: ["Frame risk", "Implement risk", "Assess risk", "Monitor risk"], answer: 1, explain: "SP 800-39 defines four risk management components: Frame, Assess, Respond, and Monitor. 'Implement risk' is not one of them — implementation refers to controls, which falls under the RMF's Implement step."),
    Question(id: 540, domain: 1, text: "The principle of 'need to know' in information security means:", options: ["All of the employees should know the security policies", "Access is limited to those who need it for their job", "Security events must reach all staff members", "System owners must know all control details"], answer: 1, explain: "Need-to-know limits information access to individuals who require it for their specific duties — reducing insider threat risk and limiting the blast radius of compromised accounts."),
    Question(id: 541, domain: 1, text: "A system that processes both classified and unclassified data would be subject to:", options: ["Only the standard FISMA requirements", "Only the FIPS 199 categorization process", "The higher requirements, including CNSS policies for classified data", "No special requirements beyond the standard FISMA process at all whatsoever"], answer: 2, explain: "Systems processing national security information are subject to Committee on National Security Systems (CNSS) policies (e.g., CNSSI 1253) rather than or in addition to NIST FIPS 199 and SP 800-53."),
    Question(id: 542, domain: 1, text: "CNSSI 1253 is the classified system equivalent of:", options: ["SP 800-30 risk assessment guidance applied to classified national security systems", "FIPS 199 and SP 800-53 combined", "FIPS 200 minimum security requirements as adopted for the intelligence community", "The NIST Cybersecurity Framework profiles tailored for federal civilian agencies"], answer: 1, explain: "CNSSI 1253 provides security categorization and control selection guidance for National Security Systems (NSS), serving the same purpose as FIPS 199 + SP 800-53 for non-NSS federal systems."),
    Question(id: 543, domain: 1, text: "The Privacy Act of 1974 applies to:", options: ["Federal agencies handling personal information in systems of records", "All United States companies that handle any kind of personal data at all", "Only healthcare organizations and their providers", "Only banks and other financial institutions"], answer: 0, explain: "The Privacy Act governs federal agency collection and handling of personal information maintained in 'systems of records' — requiring agencies to publish System of Records Notices (SORNs)."),
    Question(id: 544, domain: 1, text: "A System of Records Notice (SORN) is published by federal agencies to:", options: ["Formally authorize the underlying system for operation under the agency's RMF process", "Notify the public what PII the agency collects, why, and how it is protected", "Document how each required security control has been implemented in the system", "Publicly announce that the system is being decommissioned"], answer: 1, explain: "SORNs are published in the Federal Register as required by the Privacy Act — they describe the system of records, the PII collected, its purpose, routine uses, and safeguards."),
    Question(id: 545, domain: 1, text: "Which risk response strategy is MOST aligned with an organization's decision to stop offering an online service because the cyber risk is too high?", options: ["Mitigate", "Transfer", "Accept", "Avoid"], answer: 3, explain: "Avoiding the risk by discontinuing the risky activity entirely is risk avoidance — the most complete form of risk response, eliminating the risk source."),
    Question(id: 546, domain: 1, text: "An organization purchases cyber insurance. This is an example of which risk response?", options: ["Transfer/Share", "Avoidance", "Mitigation", "Acceptance"], answer: 0, explain: "Cyber insurance transfers financial risk to the insurer — the organization still faces operational and reputational risks, but the financial exposure is shared with the insurance provider."),
    Question(id: 547, domain: 1, text: "When documenting a risk acceptance decision, which element is most critical to include?", options: ["The system administrator's written approval of the acceptance decision", "The commercial vendor's formal written acknowledgment of the residual risk", "The AO's signature, the risk accepted, justification, and conditions", "Only the system's FIPS 199 security categorization and overall impact levels"], answer: 2, explain: "Risk acceptance must be formally documented with the accepting official's identity, what risk is being accepted, the justification, and any conditions — creating accountability and an audit trail."),
    Question(id: 548, domain: 1, text: "A mature risk management program is characterized by:", options: ["Applying the identical set of controls to every system regardless of its risk", "Risk-informed, repeatable, improving, and aligned with strategy", "Achieving an absolute zero level of residual risk", "Eliminating every threat source facing the organization"], answer: 1, explain: "Maturity in risk management means decisions are consistently risk-based, processes are repeatable and documented, and the program continuously improves based on lessons learned and changing threats."),
    Question(id: 549, domain: 1, text: "Which of the following is the PRIMARY reason organizations implement security controls?", options: ["To satisfy the organization's external audit requirements", "To comply with the terms of the vendor agreements", "To minimize the organization's overall IT costs", "To reduce risk to an acceptable level"], answer: 3, explain: "Controls exist to reduce risk — not merely to satisfy auditors or check compliance boxes. Risk reduction aligned to the organization's mission and risk tolerance is the fundamental purpose."),
    Question(id: 550, domain: 1, text: "Personally Identifiable Information (PII) that is publicly available (e.g., name in a phone book) still requires protection when:", options: ["It is never required to be protected if it is public", "When combined or used in a privacy-risky context", "Only when it is stored inside a government database", "Only when it is processed by an outside third party"], answer: 1, explain: "Even publicly available PII can become sensitive when combined with other data (the 'mosaic effect') or used in a context the individual would not reasonably expect — contextual integrity matters."),
    Question(id: 551, domain: 1, text: "The 'mosaic effect' in privacy means:", options: ["Using colorful dashboards for the organization's risk reporting", "Encrypting the data in several independent protective layers", "Combining harmless data can reveal sensitive information", "Splitting data across many databases"], answer: 2, explain: "The mosaic effect describes how aggregating multiple low-sensitivity data elements can produce a high-sensitivity picture of an individual — justifying controls even on individually benign data."),
    Question(id: 552, domain: 1, text: "ISO/IEC 27005 provides guidance on:", options: ["The ISMS certification audit procedures and its steps", "Technical control implementation specifics and details", "Data breach notification timelines", "Information security risk management processes"], answer: 3, explain: "ISO 27005 supports the risk management requirements of ISO 27001 by providing detailed guidance on risk identification, analysis, evaluation, treatment, and monitoring."),
    Question(id: 553, domain: 1, text: "A Memorandum of Understanding (MOU) between two agencies for a shared system defines:", options: ["The technical configuration of the shared system", "The authorization to operate for the shared system", "The agreed terms, responsibilities, and expectations between the parties", "The complete security control baseline that is selected for the shared system"], answer: 2, explain: "MOUs (and MOAs — Memoranda of Agreement) document the mutual understanding between parties sharing systems or services, including roles, responsibilities, security requirements, and terms of the arrangement."),
    Question(id: 554, domain: 1, text: "Which concept describes the process of ensuring that only authorized modifications are made to information, and those modifications are accurate?", options: ["Integrity", "Confidentiality", "Availability", "Non-repudiation"], answer: 0, explain: "Integrity ensures information is accurate, complete, and protected from unauthorized modification — encompassing both data integrity (accuracy) and system integrity (unaltered processing)."),
    Question(id: 555, domain: 1, text: "The role of the senior accountable official for risk management (SAORM) in federal agencies is to:", options: ["Ensure the organization-wide risk management program is effective and aligned", "Approve the individual authorization to operate for each system in the inventory", "Conduct the hands-on security control assessments", "Manage the organization's IT helpdesk operations"], answer: 0, explain: "The SAORM (typically a Deputy Secretary or equivalent) provides senior leadership accountability for the risk management program, ensuring organizational risk posture is communicated to and understood by the highest levels."),
    Question(id: 556, domain: 1, text: "A threat actor's capability, intent, and opportunity together determine:", options: ["The likelihood an event is initiated and succeeds", "The information system's overall FIPS 199 impact level", "The total number of security controls that are needed", "The system's documented authorization boundary scope"], answer: 0, explain: "Per SP 800-30, threat likelihood considers both the probability a threat source initiates an event (based on capability, intent, and opportunity) and the probability the event succeeds given existing controls."),
    Question(id: 557, domain: 1, text: "Which of the following BEST describes a 'control gap'?", options: ["A network segment that has no firewall in front", "A requirement no implemented control addresses", "A difference between two versions of the SSP document", "A finding rated as low severity"], answer: 1, explain: "A control gap occurs when a security or privacy requirement has no corresponding implemented control — representing a direct, unmitigated exposure that must be addressed."),
    Question(id: 558, domain: 1, text: "An organization identifies a new threat to its systems mid-authorization cycle. The BEST action is:", options: ["Assess its impact and notify the AO if risk changed", "Wait until the next authorization cycle to address the threat", "Immediately revoke the system's authorization to operate", "Add the threat to the next scheduled annual risk assessment"], answer: 0, explain: "Risk management is continuous — newly identified threats must be assessed immediately. If they materially change the authorized risk posture, the AO must be notified so the authorization decision can be revisited."),

    // MARK: – Batch 2: Domain 2 expansion (+54)
    Question(id: 560, domain: 2, text: "Which of the following information types would most likely drive a HIGH confidentiality impact rating under FIPS 199?", options: ["Publicly available budget documents", "Classified law enforcement investigative information", "General IT help desk records", "Published press releases"], answer: 1, explain: "Law enforcement investigative information is highly sensitive — unauthorized disclosure could endanger lives, compromise investigations, and reveal sensitive sources and methods — driving a HIGH confidentiality rating."),
    Question(id: 561, domain: 2, text: "For a system processing financial transaction data, which security objective is most likely rated HIGH under FIPS 199?", options: ["Confidentiality of the financial data, only by itself", "Availability of the financial system, only by itself", "All three objectives are always rated HIGH for finance", "Integrity — bad transactions cause serious harm"], answer: 3, explain: "Financial systems typically require HIGH integrity — corrupted or unauthorized modifications to financial records have severe operational and legal consequences. Other objectives depend on the specific system."),
    Question(id: 562, domain: 2, text: "A federal website that only publishes public information would most likely be categorized as:", options: ["High, simply because the whole system is internet-facing", "Moderate automatically for every single internet-facing system", "Low — impacts are limited for already-public information", "High for availability since it serves the public"], answer: 2, explain: "A public information website has low confidentiality impact (data is already public), low to moderate integrity impact, and potentially low availability impact — likely an overall LOW categorization."),
    Question(id: 563, domain: 2, text: "Which FIPS 199 impact level applies when unauthorized disclosure could be expected to have a severe or catastrophic adverse effect?", options: ["High", "Low", "Moderate", "Critical"], answer: 0, explain: "FIPS 199 defines HIGH impact as: loss of CIA could be expected to have a severe or catastrophic adverse effect on organizational operations, assets, individuals, or national interests."),
    Question(id: 564, domain: 2, text: "A system's security category is expressed as:", options: ["Just a single number on a scale running from 1 to 10", "Low, Moderate, or High only, as one single value", "SC = {(C, impact), (I, impact), (A, impact)}", "A percentage of controls done"], answer: 2, explain: "FIPS 199 expresses security category as: SC system = {(confidentiality, impact-value), (integrity, impact-value), (availability, impact-value)} where each impact value is Low, Moderate, or High."),
    Question(id: 565, domain: 2, text: "When a system owner disagrees with the provisional impact level from SP 800-60 for a specific information type, they may:", options: ["Adjust it up or down, with AO concurrence", "Must accept the SP 800-60 values with no change at all", "Only ever adjust the impact level in the upward direction", "Request congressional approval to change the level"], answer: 0, explain: "SP 800-60 provides provisional (starting point) impact values. System owners may adjust them — up or down — based on system-specific factors, with justification and AO concurrence."),
    Question(id: 566, domain: 2, text: "Determining the authorization boundary for a mobile application that accesses a backend federal database requires including:", options: ["Only the mobile application's client-side source code and compiled binaries", "The app, its APIs, and the backend unless separately authorized", "Only the backend federal database that stores the sensitive information", "Only the underlying network infrastructure connecting the app to the backend"], answer: 1, explain: "The authorization boundary must capture all components involved in processing sensitive data — including the app, APIs, and backend services — unless backend components are separately authorized and the interconnection is formally documented."),
    Question(id: 567, domain: 2, text: "A subsystem is excluded from the authorization boundary when:", options: ["It is simply too complex for the assessor to assess fully", "The system owner simply happens to prefer a smaller boundary", "It is managed by a vendor", "It is separately authorized and the link is documented"], answer: 3, explain: "Subsystems may be excluded from a system's boundary only if they are separately authorized (have their own ATO) and the interconnection between them is formally governed by an ISA and MOU."),
    Question(id: 568, domain: 2, text: "A system processes three types of information: HR records (moderate/moderate/low), financial data (moderate/high/moderate), and public website content (low/low/low). The overall system categorization is:", options: ["Moderate/Moderate/Low", "Moderate/High/Moderate", "High/High/High", "Low/Low/Low"], answer: 1, explain: "Apply the high-water mark to each security objective independently across all information types: Confidentiality=Moderate, Integrity=High (financial), Availability=Moderate (financial). Overall = HIGH (driven by integrity)."),
    Question(id: 569, domain: 2, text: "The Prepare step of SP 800-37 Rev. 2 was added to:", options: ["Replace the Categorize step", "Replace continuous monitoring", "Ensure essential activities are completed before the rest of the RMF", "Authorize common controls before system authorization"], answer: 2, explain: "The Prepare step (new in Rev. 2) covers organizational and system-level preparation activities that improve the efficiency and effectiveness of subsequent RMF steps. Including assigning roles, establishing the risk management strategy, and defining the authorization boundary."),
    Question(id: 575, domain: 2, text: "Which of the following is NOT a valid reason to adjust a system's FIPS 199 categorization upward from a provisional value?", options: ["The AO prefers a higher categorization to be conservative", "The system operates in a high-threat environment", "The information type is more sensitive in context than the provisional value suggests", "An aggregate of low-impact information types creates sensitivity when combined"], answer: 0, explain: "Categorization must be based on actual impact analysis — not AO preference. Adjustments require documented justification based on system-specific factors, not administrative conservatism."),
    Question(id: 576, domain: 2, text: "A federal system that directly supports emergency response operations would likely have which availability impact?", options: ["Low — the responders can fall back on plenty of other methods", "High — an outage could be catastrophic to life-safety", "Moderate — a reasonable amount of delay is acceptable here", "Low — it depends on user count"], answer: 1, explain: "Emergency response systems that directly support life-safety operations typically warrant HIGH availability — loss of access during an emergency could have catastrophic consequences."),
    Question(id: 577, domain: 2, text: "When documenting the system description in the SSP, which element is NOT typically required?", options: ["System name and identifier", "System purpose and functionality", "Stakeholder salary information", "Authorization boundary description"], answer: 2, explain: "The SSP system description covers name, identifier, purpose, functionality, boundary, interconnections, and data processed — personnel compensation has no place in security documentation."),
    Question(id: 578, domain: 2, text: "A system that processes, stores, or transmits cardholder data must also comply with:", options: ["Only FISMA requirements", "Only HIPAA", "Only GDPR if EU cards are involved", "PCI-DSS in addition to applicable federal requirements"], answer: 3, explain: "Processing cardholder data triggers PCI-DSS compliance regardless of other applicable frameworks — organizations may need to satisfy both FISMA and PCI-DSS simultaneously."),
    Question(id: 579, domain: 2, text: "Interconnected systems require an Interconnection Security Agreement (ISA) because:", options: ["It removes the need for each system to hold its own ATO", "It is required only for classified systems", "It documents the controls and terms for exchanged data", "It authorizes the link without review"], answer: 2, explain: "ISAs document the technical and security requirements for data sharing between systems — ensuring both sides understand what data crosses the connection and what controls govern the interface."),
    Question(id: 580, domain: 2, text: "Which RMF role is responsible for ensuring the system is categorized correctly?", options: ["The independent Security Control Assessor for the system", "The Common Control Provider", "The help desk manager", "The System Owner, with AO and mission-owner concurrence"], answer: 3, explain: "The System Owner leads the categorization effort, but the result requires concurrence from the AO and mission/business owners to ensure the categorization reflects actual mission impact."),
    Question(id: 581, domain: 2, text: "A high-impact system requires which control baseline as its starting point?", options: ["Low baseline", "Moderate baseline", "High baseline from SP 800-53B", "Any baseline selected by the system owner"], answer: 2, explain: "SP 800-53B provides three baselines — Low, Moderate, and High — matched to FIPS 199 impact levels. A HIGH-impact system starts with the HIGH baseline and tailors from there."),
    Question(id: 582, domain: 2, text: "Privacy impact assessments (PIAs) are required for federal systems when:", options: ["Whenever any new information technology system is deployed by the agency", "Only when the EU General Data Protection Regulation is determined to apply", "When a system collects or maintains information in identifiable form", "Only when the system is rated HIGH impact"], answer: 2, explain: "The E-Government Act of 2002 and OMB Circular A-130 require PIAs for federal IT systems that collect or process PII — enabling identification and mitigation of privacy risks before deployment."),
    Question(id: 583, domain: 2, text: "A system is being expanded to include a new module that processes sensitive health data. The system owner should FIRST:", options: ["Immediately implement the additional security controls for the health data", "Issue a brand-new authorization to operate for the system from scratch", "Notify all of the system's users of the change", "Assess whether the new data changes the impact level or privacy risk"], answer: 3, explain: "Adding new information types may change the FIPS 199 categorization, applicable controls, and privacy risk — a security impact analysis must precede implementation changes."),
    Question(id: 584, domain: 2, text: "Which document formally establishes a system in the organization's IT inventory and begins the RMF process?", options: ["The ATO memo", "The system registration record", "The POA&M", "The SAR"], answer: 1, explain: "System registration (Prepare step) formally records the system in organizational inventories, assigns roles, and establishes the starting point for all subsequent RMF activities."),
    Question(id: 585, domain: 2, text: "An organization operates a SaaS application hosted entirely by a vendor with FedRAMP authorization. The agency's authorization boundary would typically include:", options: ["Everything the vendor manages", "Nothing — FedRAMP covers the entire boundary", "The agency's configurations, data, and user access within the SaaS", "Only the network connection to the SaaS"], answer: 2, explain: "With a FedRAMP-authorized SaaS, the vendor's ATO covers the cloud infrastructure; the agency still owns its data, configurations, and user management — these form the agency's portion of the boundary. Leveraging the vendor's FedRAMP ATO for the underlying infrastructure."),
    Question(id: 586, domain: 2, text: "A system that only stores backup copies of data (not actively processing it) would typically have which primary security concern?", options: ["Very high availability requirements for the backup system", "Only the physical security of the storage media itself", "No security requirements at all because it stays offline", "Confidentiality, integrity, and recoverability of data"], answer: 3, explain: "Backup systems must protect the confidentiality and integrity of stored data and ensure recoverability — even offline backups require access controls, encryption, and integrity verification."),
    Question(id: 587, domain: 2, text: "The term 'external system' in the RMF context refers to:", options: ["Any system that is managed by a foreign government", "Any system that is connected at all to the public internet anywhere", "Only commercial cloud services and nothing else", "A system outside the organization's control that it connects to"], answer: 3, explain: "External systems are those the organization does not own or operate — third-party systems, partner agency systems, or cloud services. Connections to external systems require formal documentation and risk assessment."),
    Question(id: 588, domain: 2, text: "A one-way data transfer (data diode) between two systems requires:", options: ["Document the data types and controls at both ends", "No security documentation at all, since data flows one way", "An ISA covering only the data-receiving system's side", "An ATO covering only the data-transmitting system's side"], answer: 0, explain: "Even one-way connections must be documented — the sending system's boundary includes the data diode, and both systems' SSPs must address the connection and the data types involved."),
    Question(id: 589, domain: 2, text: "Which of the following BEST describes the purpose of the RMF's Categorize step?", options: ["Select and tailor the appropriate baseline of security controls for the system to implement", "Assess whether the implemented controls are operating effectively", "Authorize the system to operate and accept its risk", "Determine the potential impact if confidentiality, integrity, or availability is lost"], answer: 3, explain: "The Categorize step (Task C-2) uses FIPS 199 and SP 800-60 to establish the security category — which then drives all subsequent control selection and baseline decisions."),
    Question(id: 590, domain: 2, text: "The information owner's role during categorization is to:", options: ["Conduct the formal independent security assessment of the system", "Advise on the sensitivity of the information types", "Make the final authorization-to-operate decision for the system", "Select the security control baseline for the system to use"], answer: 1, explain: "Information Owners are authoritative sources for how sensitive their information is — their input is essential to correctly categorizing information types during the FIPS 199 process."),
    Question(id: 591, domain: 2, text: "An agency system processes aggregate statistics derived from individual records but contains no direct PII. Privacy risk considerations:", options: ["No, simply because the system contains no direct PII at all", "Yes — aggregated data can still allow re-identification", "They apply only if the data is later released to the public", "Only if over 1,000 records are involved"], answer: 1, explain: "Aggregated data can enable re-identification even without direct PII identifiers — the mosaic effect means privacy risk analysis is required even for apparently de-identified or statistical data."),
    Question(id: 592, domain: 2, text: "A system that runs on shared infrastructure (e.g., a government data center) may inherit which type of controls?", options: ["No controls — shared infrastructure offers no inheritance", "Physical and environmental controls from the data center as common controls", "All security controls automatically", "Only network controls"], answer: 1, explain: "Government data centers typically provide common physical, environmental, and infrastructure controls that tenant systems inherit — reducing duplication and documented in the data center's common control authorization package."),
    Question(id: 593, domain: 2, text: "When must a system's security categorization be revisited?", options: ["Only at initial authorization, since impact levels are then fixed for the system's life", "After significant system changes, new information types, or environment shifts", "Strictly every ten years, regardless of any changes to the system or its environment", "Only when the AO specifically asks for it"], answer: 1, explain: "Categorization is not static — it must be reviewed when significant changes occur to the system, its data, or its environment that could alter the impact levels established at initial authorization."),
    Question(id: 594, domain: 2, text: "Which approach to defining the authorization boundary is preferred for cloud systems under FedRAMP?", options: ["Draw the authorization boundary as narrowly as possible to minimize assessment cost and scope", "Clearly document all cloud components, services, and customer responsibilities in scope", "Exclude all vendor-managed infrastructure from the documented boundary", "Include only the customer-visible application layer in the boundary"], answer: 1, explain: "FedRAMP requires comprehensive boundary documentation for cloud systems — all infrastructure, platform, and application components within scope must be identified, along with the division of customer vs. provider responsibility."),
    Question(id: 595, domain: 2, text: "An organization implements a microservices architecture. For authorization boundary purposes, the BEST approach is:", options: ["Draw one boundary around all microservices forming the application", "Authorize each individual microservice separately regardless of relationships", "Exclude the microservices since they are only software", "Use only the backend database boundary"], answer: 0, explain: "Microservices that collectively implement a single application function should typically share an authorization boundary — separately authorizing tightly coupled microservices creates unnecessary fragmentation."),
    Question(id: 596, domain: 2, text: "The RMF Prepare step at the system level includes which activity?", options: ["Granting the system's final authorization to operate up front", "Conducting the full independent security control assessment", "Selecting the control baseline", "A mission focus analysis and identifying key stakeholders"], answer: 3, explain: "System-level Prepare activities include identifying the system's mission/business context, stakeholders, security and privacy requirements, and conducting a system-level risk assessment to inform subsequent RMF steps."),
    Question(id: 597, domain: 2, text: "A privacy plan (distinct from the SSP) documents:", options: ["The complete network architecture diagram of the underlying system", "The selected privacy controls and how they manage privacy risk", "The financial budget allocated for the year's privacy activities", "The full list of every user who has access to PII in the system"], answer: 1, explain: "OMB Circular A-130 and SP 800-37 Rev. 2 require a Privacy Plan that documents selected privacy controls, their implementation, and the methodologies for assessing their effectiveness — analogous to the SSP but privacy-focused."),
    Question(id: 598, domain: 2, text: "A system has a mission-critical availability requirement. During categorization, the availability impact should be determined by:", options: ["The worst-case adverse effect on operations if availability is lost", "The total number of users who currently access the system on each day", "The historical uptime record of the system", "The availability guarantees in the vendor's SLA"], answer: 0, explain: "FIPS 199 availability impact is based on the worst-case adverse effect of losing availability — not on user counts or historical uptime. Systems supporting critical missions often warrant HIGH availability."),
    Question(id: 599, domain: 2, text: "An external assessment team discovers that the system boundary documentation in the SSP is incomplete and missing several cloud components. The BEST action is:", options: ["Stop the assessment until the boundary documentation is corrected", "Accept the finding and update the boundary documentation after authorization", "Assess only the documented components and note the gap", "Request the AO waive the documentation requirement"], answer: 0, explain: "An incomplete boundary definition means the assessment scope is undefined — controls for undocumented components cannot be assessed, and an authorization based on incomplete documentation would not be valid. An accurate SSP is a prerequisite for a valid assessment."),
    Question(id: 600, domain: 2, text: "Which of the following is an example of a logical boundary within an information system?", options: ["A locked and access-controlled server room door at the site", "A staffed physical security guard post at the entrance", "A VLAN that isolates sensitive system components", "Physical cable locks securing the servers in the rack"], answer: 2, explain: "Logical boundaries use network segmentation, VLANs, firewalls, and access controls to define security perimeters within a system — complementing physical boundaries."),
    Question(id: 601, domain: 2, text: "For a HIGH-impact system, the depth and rigor of the security assessment should be:", options: ["Greater — more intensive procedures and higher assurance", "Exactly the same as it would be for any LOW-impact system", "Less, since HIGH systems already have many controls in place", "Whatever the assessor personally prefers"], answer: 0, explain: "SP 800-53A scales assessment rigor to system impact level — HIGH-impact systems require more extensive examination, testing, and interviewing to provide sufficient assurance."),
    Question(id: 602, domain: 2, text: "A new regulation requires a government agency to classify a previously unclassified information type as sensitive. This change should trigger:", options: ["A review of all systems processing that information type", "No action at all until the next scheduled system authorization cycle", "An immediate shutdown of every system that touches the information type", "Only a policy document update, with no changes to any system"], answer: 0, explain: "Regulatory changes that elevate the sensitivity of information types processed by existing systems may require recategorization, control baseline adjustments, and potentially a new authorization."),
    Question(id: 603, domain: 2, text: "An organization wants to reduce the scope of its authorization boundary to simplify assessment. Which of the following is an acceptable approach?", options: ["Remove separately authorized components with documented links", "Just declare a smaller boundary without any documentation whatsoever", "Exclude all of the cloud components that are hosted by third parties", "Remove low-risk components informally"], answer: 0, explain: "Boundary reduction is only valid when excluded components have their own authorizations and the interconnections are formally governed. Arbitrary exclusions without proper authorization create unmanaged risk."),
    Question(id: 604, domain: 2, text: "The concept of 'tiered risk management' in SP 800-39 applies to system categorization because:", options: ["Each system is categorized on its own with no organizational context", "The tiers apply only to classified systems", "Tier 1 decisions fully override FIPS 199", "Categorization must reflect the higher-tier risk strategy"], answer: 3, explain: "Tier 1 (organization) establishes risk tolerance and strategy; Tier 2 (mission/business) defines what information systems must protect; Tier 3 (system) categorization must be consistent with these higher-tier decisions."),
    Question(id: 605, domain: 2, text: "A system processes information at multiple sensitivity levels. The overall system categorization reflects:", options: ["The lowest sensitivity level to simplify controls", "An average of all sensitivity levels", "The highest sensitivity level across all information types (high-water mark)", "The sensitivity level most commonly found in the system"], answer: 2, explain: "When a system processes mixed-sensitivity data, the high-water mark ensures the entire system is protected at the level required by the most sensitive information it contains."),
    Question(id: 606, domain: 2, text: "Operational technology (OT) systems (e.g., industrial control systems) may have different availability priorities because:", options: ["OT systems never process sensitive information", "OT systems are exempt from FIPS 199", "OT systems always have LOW confidentiality requirements", "Physical processes controlled by OT systems may be safety-critical"], answer: 3, explain: "OT/ICS systems controlling physical processes (power grids, water treatment, manufacturing) often prioritize availability above all else — downtime can cause physical harm, making HIGH availability common. Loss of availability can have immediate physical harm consequences."),
    Question(id: 607, domain: 2, text: "A cloud service provider's FedRAMP authorization boundary includes:", options: ["Only the physical data center facility building itself", "All cloud components within the authorization scope", "Only the customer-facing application interfaces shown", "Only components directly managed by federal employees"], answer: 1, explain: "The FedRAMP authorization boundary for a CSP encompasses all components within scope of the FedRAMP package — documented in the CSP's SSP, including data centers, platforms, APIs, and support systems."),
    Question(id: 608, domain: 2, text: "When a system owner cannot determine whether a component falls inside or outside the authorization boundary, the SAFEST approach is:", options: ["Exclude it to keep the boundary small", "Include it within the boundary and document it", "Ask the vendor to decide", "Leave the boundary undefined for that component"], answer: 1, explain: "When in doubt, including a component within the boundary ensures it receives appropriate security attention. Exclusions require positive confirmation of separate authorization — ambiguity defaults to inclusion. If later found to be separately authorized, it can be moved outside with proper documentation."),
    Question(id: 609, domain: 2, text: "A system description in the SSP should include all of the following EXCEPT:", options: ["System name, acronym, and unique identifier", "System purpose and function", "Detailed salary information of system administrators", "System operational status and authorization boundary"], answer: 2, explain: "The SSP system description captures operational and security-relevant information — personal compensation data is irrelevant and should not be included in security documentation."),
    Question(id: 610, domain: 2, text: "The security categorization process must be completed:", options: ["After the control selection step has been completely finished and reviewed", "During the security control assessment phase", "Before control selection — it determines which baseline to use", "After the authorization to operate is granted"], answer: 2, explain: "Categorize is Step 2 of the RMF (after Prepare) and must precede Select (Step 3) — the impact level from FIPS 199 determines the appropriate SP 800-53B baseline to use as a starting point."),
    Question(id: 611, domain: 2, text: "A system owner argues that their MODERATE-impact system should use LOW baseline controls to save resources. The appropriate response is:", options: ["Allow it, since the system owner has authority over controls", "Allow it, but only with the authorizing official's approval", "Reject it — the impact level sets the minimum baseline", "Allow it if the system currently has no known vulnerabilities"], answer: 2, explain: "FIPS 200 and SP 800-53B require that baseline selection match the FIPS 199 impact level. Using a lower baseline than warranted leaves mandatory minimum security requirements unmet."),
    Question(id: 612, domain: 2, text: "An organization processes aggregate health statistics for public health research — no individual identifiers are retained. The BEST privacy categorization approach is:", options: ["No privacy controls are needed because no PII is present", "Apply HIGH privacy controls automatically for all health data", "Check if re-identification is possible, then act", "Apply MODERATE controls regardless of any de-identification"], answer: 2, explain: "Even de-identified health statistics may be re-identifiable through combination with other datasets. A proper privacy risk assessment determines whether controls are needed — not a blanket assumption."),
    Question(id: 613, domain: 2, text: "An organization uses the E-Authentication Guidance (OMB M-04-04 / NIST SP 800-63) to determine:", options: ["The system's overall FIPS 199 impact levels", "The assurance level needed for authentication based on transaction risk", "Which specific cryptographic algorithms the system will be required to use", "The system's documented authorization boundary"], answer: 1, explain: "OMB M-04-04 and NIST SP 800-63 provide a risk-based framework for determining the Identity Assurance Level (IAL), Authenticator Assurance Level (AAL), and Federation Assurance Level (FAL) needed for digital authentication."),

    // MARK: – Batch 3: Domain 3 expansion (+78 control selection)
    Question(id: 620, domain: 3, text: "The Access Control (AC) family in SP 800-53 covers which of the following?", options: ["Only the physical lock mechanisms on doors", "Only the configured network firewall rules", "Only the encryption of the data while it is sitting at rest on storage media", "Account management, access enforcement, least privilege, remote access"], answer: 3, explain: "The AC family is broad — covering account management (AC-2), access enforcement (AC-3), information flow (AC-4), separation of duties (AC-5), least privilege (AC-6), remote access (AC-17), and more."),
    Question(id: 621, domain: 3, text: "The Identification and Authentication (IA) family requires:", options: ["Generation, protection, and review of all audit records", "Establishment and change control of secure baselines", "Protection of data in transit and at rest", "Unique ID and authentication of users and devices"], answer: 3, explain: "IA controls ensure every user, device, and process is uniquely identified and authenticated before access — enabling accountability and supporting the principle of least privilege."),
    Question(id: 622, domain: 3, text: "The Audit and Accountability (AU) family requires organizations to:", options: ["Unique identification and authentication of users and devices", "Create, protect, retain, and review audit records", "Controlled maintenance of systems by authorized personnel only", "Restriction of physical access to facilities"], answer: 1, explain: "AU controls cover audit event definition, content, storage capacity, response to processing failures, record review, analysis, reporting, reduction, protection, and retention."),
    Question(id: 623, domain: 3, text: "The Configuration Management (CM) family addresses:", options: ["Generation, protection, and review of system audit records", "Contingency planning, system backup, and recovery operations", "Personnel screening, access agreements, and staff terminations", "Baseline configs, change control, and least function"], answer: 3, explain: "CM controls establish and maintain secure baseline configurations, control changes through CCB processes, analyze security impacts of changes, and enforce least functionality by disabling unnecessary services."),
    Question(id: 624, domain: 3, text: "The Contingency Planning (CP) family requires:", options: ["Only a single disaster-recovery test that is performed once each calendar year", "Only the routine data backup procedures used for the production environment", "Plan development, training, testing, backups, recovery, and reconstitution", "Only emergency backup power systems"], answer: 2, explain: "CP controls cover the full resilience lifecycle: planning (CP-2), training (CP-3), testing (CP-4), backup (CP-9), recovery (CP-10), and reconstitution — ensuring systems can survive and recover from disruptions."),
    Question(id: 625, domain: 3, text: "The Incident Response (IR) family requires organizations to:", options: ["Establishment and maintenance of secure baseline configurations", "Identification and authentication of users and their devices", "An incident-handling capability across the full lifecycle", "Physical access authorization controls"], answer: 2, explain: "IR controls establish the full incident response lifecycle — from planning and training through detection, analysis, containment, eradication, recovery, and lessons learned."),
    Question(id: 626, domain: 3, text: "The Maintenance (MA) family controls address:", options: ["Backup, recovery, and the contingency operations for the system", "Configuration change control and secure baseline management overall", "Sanitization and disposal of media", "Controlled maintenance, personnel, tools, and remote access"], answer: 3, explain: "MA controls ensure that system maintenance is performed by authorized personnel using approved tools, with special protections for remote maintenance sessions that could expose systems to attack."),
    Question(id: 627, domain: 3, text: "The Media Protection (MP) family controls cover:", options: ["Media access, marking, storage, transport, and disposal", "Only the digital media used within the organization's systems", "Only encrypted USB drives", "Only magnetic tape backups"], answer: 0, explain: "MP controls address the full lifecycle of sensitive media: access restrictions, marking/labeling, secure storage, controlled transport, sanitization before reuse, and destruction at end of life."),
    Question(id: 628, domain: 3, text: "The Personnel Security (PS) family addresses:", options: ["Routine employee performance reviews", "Only background investigations and checks for outside contractors", "Screening, agreements, transfers, termination, and sanctions", "Only physical badge access to the facility"], answer: 2, explain: "PS controls address human-side security: position categorization and risk designation, screening, agreements (acceptable use), termination (access revocation), sanctions, and personnel actions."),
    Question(id: 629, domain: 3, text: "The Physical and Environmental Protection (PE) family includes controls for:", options: ["Physical access, monitoring, visitor control, and environmental protection", "Identification and authentication of the users, devices, and the running processes", "Audit record generation, protection, retention, and review", "Incident detection, analysis, containment, and recovery"], answer: 0, explain: "PE covers the full physical security domain — access control, monitoring, visitor management, emergency response, environmental protection, and secure media delivery/removal."),
    Question(id: 630, domain: 3, text: "The Planning (PL) family requires:", options: ["Only the annual project management plans for the system development effort", "Security and privacy plans describing controls, roles, and the boundary", "Only the long-range information technology roadmap and budget projections", "Only the yearly budget planning documents"], answer: 1, explain: "PL controls require the System Security Plan (PL-2) and System Privacy Plan — formal documents describing the security/privacy posture, implemented controls, and rules of behavior."),
    Question(id: 631, domain: 3, text: "The Risk Assessment (RA) family requires:", options: ["Only the initial risk assessment that is performed at the time of authorization", "Only threat modeling for newly built systems", "Only an annual penetration test", "Periodic risk assessments, scanning, privacy and supply-chain assessments"], answer: 3, explain: "RA controls require ongoing risk assessment activities: formal risk assessments (RA-3), vulnerability monitoring and scanning (RA-5), privacy risk assessments (RA-8), and supply chain risk assessments (RA-3(1))."),
    Question(id: 632, domain: 3, text: "The System and Communications Protection (SC) family controls include:", options: ["Personnel screening, access agreements, and terminations", "Boundary protection, crypto, and session security", "Media marking, storage, transport, and sanitization steps", "Contingency planning, full system backup, and reconstitution"], answer: 1, explain: "SC controls address system and network architecture security: boundary protection, separation of system functionality, denial of service protection, cryptography, network disconnect, and communications integrity."),
    Question(id: 633, domain: 3, text: "The System and Information Integrity (SI) family covers:", options: ["Access enforcement, least privilege, and individual account management", "Malware protection, alerts, software integrity, and input validation", "Physical access control and environmental protection", "Security assessment, authorization, and continuous monitoring"], answer: 1, explain: "SI controls address integrity across multiple dimensions: malware protection (SI-3), security alerts (SI-5), software integrity (SI-7), input validation (SI-10), error handling (SI-11), and memory protection (SI-16)."),
    Question(id: 634, domain: 3, text: "The Awareness and Training (AT) family ensures:", options: ["Only annual compliance training is completed", "Only the security staff receive any training", "All users get awareness training plus role-based training as needed", "Security training is optional and entirely self-directed by each user"], answer: 2, explain: "AT controls require organization-wide security/privacy awareness training (AT-2) for all users and role-based training (AT-3) for individuals with specific security responsibilities."),
    Question(id: 635, domain: 3, text: "Control enhancements in SP 800-53 are used to:", options: ["Replace the base control entirely with a different, independent one", "Mark certain controls as optional to implement", "Reduce the overall scope of a base control", "Add functionality, rigor, or assurance beyond the base control"], answer: 3, explain: "Control enhancements augment base controls — adding stronger requirements (e.g., MFA as an enhancement to basic authentication) or expanding coverage for higher-assurance environments."),
    Question(id: 639, domain: 3, text: "When selecting controls, an organization discovers a required control has no commercially available solution. The BEST response is:", options: ["Document the constraint, compensate, and route to the AO", "Lower the system's overall impact level to avoid the control", "Remove the control from the SSP", "Delay the authorization indefinitely"], answer: 0, explain: "When a control is technically infeasible (no commercial solution), document the constraint, implement compensating controls that achieve equivalent protection, and route residual risk to the AO."),
    Question(id: 643, domain: 3, text: "An organization operating a system with significant privacy requirements should supplement the security baseline with:", options: ["Only the PT (Privacy) control family and nothing else at all whatsoever", "No extra controls, since security controls already cover privacy", "A separate and fully parallel privacy control framework entirely", "PT controls plus privacy-relevant controls elsewhere"], answer: 3, explain: "Privacy requires attention across multiple SP 800-53 families — not just PT. Privacy-relevant controls in AC, AU, IA, SI, and SA must be selected based on the privacy risk assessment."),
    Question(id: 644, domain: 3, text: "The SP 800-53 System and Services Acquisition (SA) family includes which critical supply chain control?", options: ["SA-6 (Software Usage Restrictions) within the SA family", "SA-9 (External System Services) controls and nothing else", "SR-family controls for supply chain risk management", "SA-1 (the policy control only)"], answer: 2, explain: "SA-12 and the dedicated SR (Supply Chain Risk Management) family in SP 800-53 Rev. 5 address supplier screening, provenance, acquisition strategies, and protection against tampering in the supply chain."),
    Question(id: 645, domain: 3, text: "A federal agency plans to use open-source software in a MODERATE-impact system. Which control family most directly addresses the risks of this decision?", options: ["PE (Physical and Environmental Protection) controls", "CP (Contingency Planning) for backup and recovery", "AT (Awareness and Training) for the system's users", "SA (acquisition) and SI (information integrity)"], answer: 3, explain: "SA controls address software acquisition decisions including open-source; SI controls (SI-3 malware, SI-7 integrity) ensure open-source software is vetted and integrity-verified before deployment."),
    Question(id: 646, domain: 3, text: "Which control requires organizations to document and manage system interconnections with external systems?", options: ["AC-17 (Remote Access)", "CA-3 (System Interconnections)", "SC-7 (Boundary Protection)", "SA-9 (External System Services)"], answer: 1, explain: "CA-3 (System Interconnections) requires formal documentation (ISA) of connections between organizational and external systems — defining the nature of the connection, data exchanged, and security controls at the interface."),
    Question(id: 647, domain: 3, text: "The 'rules of behavior' (PL-4) required by SP 800-53 serve to:", options: ["Inform users of their responsibilities when accessing systems", "Completely replace the organization's security awareness training program", "Define the technical firewall rules for the network", "Establish the AO's specific authorization conditions"], answer: 0, explain: "PL-4 requires establishing rules of behavior for system users — setting expectations for acceptable use, privacy considerations, and consequences for violations before granting access."),
    Question(id: 648, domain: 3, text: "An organization is implementing a HIGH-impact system. Which baseline should they start from and what tailoring action is most common?", options: ["Start from the LOW baseline and add more controls as the need arises later", "Start from MODERATE and upgrade everything to HIGH", "Start from the HIGH baseline and tailor with overlays or enhancements", "Start from any baseline and simply work upward"], answer: 2, explain: "HIGH-impact systems start from the HIGH baseline in SP 800-53B — typically the most comprehensive baseline. Organizations then apply overlays (e.g., privacy, ICS) and add enhancements for specific risks."),
    Question(id: 649, domain: 3, text: "A system owner wants to share the SSP with a potential contractor to plan implementation. The SSP should be treated as:", options: ["A sensitive document", "A public document freely shareable", "An unclassified document with no restrictions", "A document that can only be viewed by the AO"], answer: 0, explain: "SSPs contain sensitive security information — control implementations, architecture, and vulnerabilities. They should be marked as CUI (or equivalent) and shared only with personnel who need it under appropriate agreements. Mark it appropriately (e.g., Controlled Unclassified Information) and share only with authorized individuals under appropriate agreements."),
    Question(id: 650, domain: 3, text: "Which of the following BEST describes a 'security architecture' in the context of control selection?", options: ["A structured description of how the controls work together", "The physical layout of the server racks within the data room", "Only the system's documented network architecture diagram by itself", "The list of approved software vendors"], answer: 0, explain: "Security architecture describes how controls are layered and integrated — addressing defense in depth, trust zones, data flows, authentication mechanisms, and monitoring — to achieve the system's security objectives."),
    Question(id: 651, domain: 3, text: "When applying the 'scoping guidance' in control tailoring, which of the following is a valid reason to exclude a control?", options: ["The control is judged too expensive to implement within the current budget cycle", "The system lacks the technology or characteristic the control addresses", "The independent assessor has recommended removing it from the selected control set", "The system owner simply prefers to maintain a smaller overall set of controls"], answer: 1, explain: "Scoping removes controls based on applicability — not cost or preference. Valid reasons include: the technology doesn't exist in the system (e.g., no wireless = no wireless controls), the operational environment makes it N/A, etc."),
    Question(id: 652, domain: 3, text: "NIST SP 800-53B provides how many control baselines?", options: ["Two (Low and High)", "Four (Minimal, Low, Moderate, and High)", "One universal baseline", "Three (Low, Moderate, and High)"], answer: 3, explain: "SP 800-53B provides three control baselines: Low, Moderate, and High — corresponding to the three impact levels from FIPS 199. Organizations select the appropriate baseline based on their FIPS 199 categorization."),
    Question(id: 653, domain: 3, text: "Which of the following is an example of an 'organization-defined value' that must be specified in SP 800-53 controls?", options: ["The log-review frequency the organization sets for AU-6", "The FIPS 199 impact level assigned to the information system overall", "The name of the independent assessor conducting the control assessment", "The expiration date attached to the system's authorization to operate"], answer: 0, explain: "Many SP 800-53 controls contain organization-defined parameters (ODPs) — placeholders the organization fills with specific values based on risk tolerance and operational needs (e.g., AU-6 log review frequency)."),
    Question(id: 654, domain: 3, text: "A defense contractor handling Controlled Unclassified Information (CUI) must comply with:", options: ["Only the Federal Information Security Modernization Act requirements", "NIST SP 800-171, plus the applicable contractual requirements", "Only the Payment Card Industry Data Security Standard requirements", "Only the Sarbanes-Oxley Act"], answer: 1, explain: "SP 800-171 provides security requirements for protecting CUI in nonfederal systems — required by DFARS and contractual obligations for contractors handling CUI from federal agencies."),
    Question(id: 655, domain: 3, text: "The purpose of documenting control implementation status (implemented, partially implemented, planned, not applicable) in the SSP is to:", options: ["To satisfy the formal documentation requirements and nothing else at all", "Give assessors and the AO an accurate picture of current posture", "To automatically generate the system's POA&M", "To replace the security assessment report entirely"], answer: 1, explain: "Accurate implementation status in the SSP gives assessors the baseline against which to assess and gives the AO a realistic picture of what is and is not in place — essential for valid risk decisions."),
    Question(id: 656, domain: 3, text: "An organization's SSP is out of date and does not reflect current system architecture. This situation creates:", options: ["No significant issue since the current state is what matters", "Only a minor documentation finding", "An automatic denial of authorization", "A major problem"], answer: 3, explain: "The SSP is the authoritative description of control implementations. An outdated SSP leads to assessments against stale information — misrepresenting the system's actual security posture to the AO. Assessors will assess against inaccurate documentation, leading to invalid findings and a potentially flawed authorization."),
    Question(id: 657, domain: 3, text: "Which control family addresses the protection of information during transmission across networks?", options: ["MP (Media Protection), governing the handling of storage media", "PE (Physical and Environmental Protection)", "AU (Audit and Accountability) for event logs", "SC (System and Communications Protection), specifically SC-8"], answer: 3, explain: "SC-8 requires protecting the confidentiality and integrity of information during transmission — typically through cryptographic mechanisms (TLS, VPN, encrypted channels)."),
    Question(id: 658, domain: 3, text: "A system processes sensitive data that must not comingle with less sensitive data. Which control is MOST relevant?", options: ["AC-2 (Account Management) for all of the user accounts", "AU-9 for the Protection of Audit Information records", "SC-4 (Shared Resources) and AC-4 (Flow Control)", "CP-2 (the Contingency Plan) for the whole system"], answer: 2, explain: "SC-4 prevents unauthorized information transfer through shared system resources, and AC-4 enforces information flow policies — together preventing sensitive data from commingling with or leaking to less-sensitive environments."),
    Question(id: 659, domain: 3, text: "During control selection, the team identifies a risk that no available control directly addresses. The BEST approach is:", options: ["Lower the system's overall impact level to reduce the number of controls required", "Automatically accept the risk without analysis", "Document the risk, assess residual exposure, mitigate, and send to the AO", "Remove the risk from the assessment entirely"], answer: 2, explain: "When no control directly addresses a risk, the gap must be documented, residual risk quantified, any available mitigations applied, and the AO must formally accept the remaining exposure — it cannot be silently ignored."),
    Question(id: 660, domain: 3, text: "A system owner argues that because their system is airgapped (no external connections), many network controls are not applicable. This reasoning:", options: ["Is always correct — airgapped systems need no network controls", "Is incorrect — all controls apply regardless of connectivity", "Is only valid for classified systems", "May be partially correct for some network controls, but must be carefully evaluated"], answer: 3, explain: "Airgapped systems can legitimately scope out some network controls, but they still face threats from removable media (MP controls), insider threats (AC, AU controls), and maintenance activities (MA controls) — careful scoping with documented justification is required. Airgapped systems still need controls for removable media, insider threats, and maintenance connections."),
    Question(id: 661, domain: 3, text: "The 'common control' approach benefits organizations because:", options: ["It lets each individual system implement every control fully independently of others", "It removes common controls from the assessment scope entirely", "It implements a control once at the enterprise level for many systems to inherit", "It eliminates the need for any system-specific controls"], answer: 2, explain: "Common controls create economies of scale — the enterprise implements a control once (e.g., physical security, network infrastructure) and all systems inherit it, reducing cost and standardizing protection."),
    Question(id: 662, domain: 3, text: "Which of the following is a privacy control that addresses an individual's right to access their own PII?", options: ["PT-1 (Privacy Policy), which establishes the organization's privacy program", "PT-2 (Authority to Process the information)", "AU-2 (Event Logging)", "PT-6 and IP-1 individual-participation controls for access and correction"], answer: 3, explain: "Individual participation controls (e.g., IP family in earlier frameworks, now integrated into PT) address access, correction, redress, and participation rights — enabling individuals to view and correct their PII."),
    Question(id: 663, domain: 3, text: "The Supply Chain Risk Management (SR) family in SP 800-53 Rev. 5 includes controls for:", options: ["Only the management of domestic suppliers that are located within the United States borders", "Only the procurement and full lifecycle tracking of physical hardware components and parts", "Only the management of commercial software license entitlements", "Supplier screening, acquisition strategy, component authenticity, and breach notice"], answer: 3, explain: "The SR family (new in Rev. 5) comprehensively addresses supply chain risks: supplier risk assessments (SR-3), acquisition strategies (SR-5), component authenticity (SR-11), and breach notification (SR-8)."),
    Question(id: 664, domain: 3, text: "A control that requires the organization to test contingency plans is found in which family?", options: ["IR (Incident Response)", "CA (Assessment, Authorization, and Monitoring)", "RA (Risk Assessment)", "CP (Contingency Planning) — CP-4 (Contingency Plan Testing)"], answer: 3, explain: "CP-4 (Contingency Plan Testing) requires organizations to test contingency plans at defined frequencies to discover weaknesses and gaps before an actual disruption — using tabletop exercises, functional tests, or full-scale exercises."),
    Question(id: 665, domain: 3, text: "The concept of 'separation of duties' is primarily addressed by which SP 800-53 control?", options: ["AC-5 (Separation of Duties)", "IA-2 (Identification and Authentication)", "AU-2 (Event Logging)", "SA-3 (System Development Life Cycle)"], answer: 0, explain: "AC-5 (Separation of Duties) requires dividing mission functions among multiple individuals — preventing any single person from having all access needed to perform a sensitive or fraudulent action alone."),
    Question(id: 666, domain: 3, text: "An organization is selecting controls for a system used exclusively for internal training purposes with no sensitive data. The MOST appropriate action is:", options: ["Apply the full HIGH baseline to all of the training systems", "Use the LOW baseline, tailored to the minimal set needed", "Apply no controls, since it is not production", "Apply MODERATE as a safe default"], answer: 1, explain: "A training system with no sensitive data would likely categorize as LOW — warranting the LOW baseline from SP 800-53B, then tailored to the system's specific characteristics."),
    Question(id: 667, domain: 3, text: "The control CA-7 (Continuous Monitoring) in SP 800-53 requires:", options: ["Developing a continuous monitoring strategy for ongoing posture awareness", "Performing the comprehensive security control assessments only once each year", "Running automated vulnerability scanning as the only monitoring activity used", "Conducting quarterly penetration tests"], answer: 0, explain: "CA-7 requires developing and implementing a continuous monitoring strategy — defining what to monitor, how often, with what tools, and how findings are reported and acted upon."),
    Question(id: 668, domain: 3, text: "Which control in the IA family specifically addresses the management of authenticator (credential) strength and lifecycle?", options: ["IA-2 (Identification and Authentication)", "IA-8 (Identification and Authentication for Non-Organizational Users)", "IA-1 (Policy and Procedures)", "IA-5 (Authenticator Management)"], answer: 3, explain: "IA-5 manages credentials — requiring minimum strength, expiration, protection, and management of passwords, tokens, certificates, and other authenticators throughout their lifecycle."),
    Question(id: 669, domain: 3, text: "The control SI-2 (Flaw Remediation) requires organizations to:", options: ["Identify, report, and correct information system flaws on defined timelines", "Only report vulnerabilities to the vendor", "Test all patches before applying them to production", "Apply patches only during scheduled maintenance windows"], answer: 0, explain: "SI-2 requires identifying system flaws (from scans, advisories, reports), installing security-relevant updates within organization-defined timeframes, and testing effectiveness of the remediation."),
    Question(id: 670, domain: 3, text: "The principle behind the CP-9 (System Backup) control is:", options: ["Backups are only ever truly needed for the system's databases", "Store the backups on the same system for added convenience", "Back up critical data regularly and test that it restores", "Only the user data ever requires any backup"], answer: 2, explain: "CP-9 requires user-level, system-level, and system documentation backups at defined frequencies; backup storage at separate facilities; and periodic testing to verify backup integrity and recoverability."),
    Question(id: 671, domain: 3, text: "An organization uses a Software as a Service (SaaS) application. Under the shared responsibility model, which SP 800-53 control family most directly governs the relationship with the SaaS provider?", options: ["PE (Physical and Environmental)", "MA (Maintenance)", "SA-9 (External System Services) within the SA family", "CP (Contingency Planning)"], answer: 2, explain: "SA-9 requires organizations to define security requirements for external services, monitor provider compliance, and ensure appropriate agreements are in place — governing SaaS, cloud, and outsourced service relationships."),
    Question(id: 672, domain: 3, text: "A control that requires the system to limit unsuccessful logon attempts and automatically lock accounts is found in which SP 800-53 control?", options: ["AC-2 (Account Management)", "IA-5 (Authenticator Management)", "AU-2 (Event Logging)", "AC-7 (Unsuccessful Logon Attempts)"], answer: 3, explain: "AC-7 specifically addresses unsuccessful logon attempt limits — enforcing lockout after a specified number of failed attempts to protect against brute-force attacks."),
    Question(id: 673, domain: 3, text: "When a system owner cannot implement a required SP 800-53 control enhancement (only the base control), this is:", options: ["A control violation that requires the AO to revoke the system's ATO immediately", "Perfectly acceptable and requires no documentation of any kind", "A tailoring decision to be documented in the SSP with written justification", "Acceptable only when the system is rated LOW impact"], answer: 2, explain: "Control enhancements are additional requirements beyond the base control. Choosing not to implement an enhancement (when not baseline-required) is a tailoring decision — documented in the SSP with the rationale."),
    Question(id: 674, domain: 3, text: "NIST SP 800-53 control families are organized by:", options: ["System impact level: Low, Moderate, or High", "The phase of the system development lifecycle that applies", "Security and privacy topic area, such as AC, AU, and IA", "The category of threat the control addresses"], answer: 2, explain: "SP 800-53 organizes controls into 20 families by topic (abbreviations like AC for Access Control, AU for Audit, etc.) — not by impact level, SDLC phase, or threat category."),
    Question(id: 675, domain: 3, text: "The primary distinction between SP 800-53 (control catalog) and SP 800-53B (baselines) is:", options: ["800-53 is the full catalog; 800-53B sets the impact-level baselines", "They are exactly the same single publication", "800-53B contains new controls not found in 800-53", "800-53 is for classified systems, while 800-53B is for unclassified ones"], answer: 0, explain: "SP 800-53 is the full catalog of ~1,000 controls and enhancements. SP 800-53B is a companion document that specifies which controls from the catalog are required at Low, Moderate, and High impact levels."),
    Question(id: 676, domain: 3, text: "Which of the following best describes a 'control enhancement' in SP 800-53?", options: ["A completely independent control unrelated to any base control in the catalog", "A deprecated earlier version of a control retained for backward compatibility", "An organization-defined parameter value supplied within a base control statement", "Added requirements extending the base control, like AC-2(1)"], answer: 3, explain: "Control enhancements (shown in parentheses, e.g., AC-2(1)) add specific additional requirements to the base control — such as automated account management, which extends the base account management control."),
    Question(id: 677, domain: 3, text: "When an organization inherits physical security controls from a data center provider, the system owner must:", options: ["Independently implement the same physical security controls anyway as backup", "Document the inheritance in the SSP and verify the CCP's authorization", "Trust the provider without any verification", "Document the controls only if a finding arises"], answer: 1, explain: "Documenting inherited controls in the SSP and verifying the CCP's authorization is current is essential — if the common control authorization lapses or doesn't cover the needed controls, the system has a gap."),
    Question(id: 678, domain: 3, text: "The PM (Program Management) family controls operate at which level?", options: ["The individual information system level", "The organization level, governing the whole program", "The underlying network and supporting infrastructure layer level", "The individual application source-code level"], answer: 1, explain: "PM controls (e.g., PM-1 Information Security Program Plan, PM-9 Risk Management Strategy) operate at the organizational level — they apply to the program as a whole, not to individual systems."),
    Question(id: 679, domain: 3, text: "The control CA-8 (Penetration Testing) requires:", options: ["Only annual network vulnerability scans of the whole system", "Only external penetration testing performed by third parties", "Pen testing on a schedule and after big changes", "Only the scanning of the public-facing web applications themselves"], answer: 2, explain: "CA-8 requires penetration testing — simulated attacks to identify exploitable vulnerabilities — at organization-defined frequencies and after significant system changes, to validate the effectiveness of controls."),
    Question(id: 680, domain: 3, text: "An organization's AO has a very low risk tolerance. How does this typically affect control selection?", options: ["Fewer controls are needed simply because the AO is more cautious", "More controls and stronger enhancements to cut risk", "The same baseline is used but with a shorter ATO validity period", "Control selection is entirely unaffected by the AO's tolerance"], answer: 1, explain: "A low risk tolerance drives more conservative control selection — additional enhancements, higher assurance requirements, and more compensating controls to minimize residual risk to levels the AO will accept."),
    Question(id: 681, domain: 3, text: "Which SP 800-53 family addresses the protection of information at rest on storage media and in transit?", options: ["SC for data in transit, MP for media storage, and PE for physical media", "AU (Audit and Accountability), which records and protects system event logs", "IR (Incident Response), which governs detection and handling of incidents", "PL (Planning), covering the security plan"], answer: 0, explain: "Data protection requires multiple families working together: SC-28 for data at rest encryption, SC-8 for in-transit encryption, MP-5 for media transport, and PE controls for physical protection of storage."),
    Question(id: 682, domain: 3, text: "A system owner wants to use a vendor's pre-existing security assessment to satisfy their own assessment requirement. This is BEST accomplished through:", options: ["Accept the vendor's own self-certification with no independent review at all", "Require a full reassessment of the system regardless", "Reciprocity — review the package and issue an ATU if it's current", "Only accept assessments from government-certified assessors"], answer: 2, explain: "Reciprocity leverages existing authorizations through the ATU mechanism — the AO reviews an existing assessment package and accepts it rather than requiring full duplication of effort."),
    Question(id: 683, domain: 3, text: "An overlay for a healthcare information system would typically:", options: ["Remove all controls not strictly required by HIPAA", "Replace SP 800-53 entirely with just the HIPAA Security Rule provisions", "Apply only to hospital systems and nowhere else", "Add or modify controls for healthcare data, HIPAA, and patient safety"], answer: 3, explain: "A healthcare overlay adapts the SP 800-53 baseline for the unique privacy, security, and patient safety requirements of healthcare — potentially adding HIPAA-specific controls while aligning with NIST guidance."),
    Question(id: 684, domain: 3, text: "A system that uses cryptographic modules must comply with which federal standard for cryptographic module validation?", options: ["FIPS 140-2 / FIPS 140-3 for crypto modules", "The ISO 27001 information security standard", "The PCI-DSS cryptographic requirements only", "SP 800-53 SC-28 only"], answer: 0, explain: "FIPS 140-2 (and its successor FIPS 140-3) defines security requirements for cryptographic modules used in federal systems — all cryptography in federal systems must use FIPS-validated modules."),
    Question(id: 685, domain: 3, text: "When must an organization consider privacy in its control selection process?", options: ["Whenever the system processes PII", "Only when GDPR applies", "Only for HIGH-impact systems", "Only when a privacy officer requests it"], answer: 0, explain: "OMB Circular A-130 and SP 800-37 Rev. 2 require privacy to be considered alongside security throughout the RMF — including during control selection when the system processes any PII. Privacy risk must be assessed and privacy controls selected alongside security controls."),
    Question(id: 686, domain: 3, text: "An organization implements two-person integrity (TPI) for access to sensitive cryptographic material. This is an example of:", options: ["Defense in depth across multiple security layers", "Separation of duties and dual authorization", "The principle of least privilege for the users", "Non-repudiation of every action that is taken"], answer: 1, explain: "Two-person integrity requires two authorized individuals to be present for sensitive operations — an implementation of separation of duties and dual authorization that prevents insider-threat manipulation of critical assets."),
    Question(id: 687, domain: 3, text: "The concept of 'defense in depth' in control selection means:", options: ["Selecting only the single strongest available control for each risk", "Relying exclusively on the outer network perimeter controls alone", "Applying one control at several org levels", "Layered, overlapping controls so one failure doesn't expose all"], answer: 3, explain: "Defense in depth layers controls across prevention, detection, response, and recovery — at network, host, application, and data levels — so no single point of failure compromises the entire system."),
    Question(id: 688, domain: 3, text: "A continuous monitoring strategy developed during the Select step should define which of the following?", options: ["Only the recurring schedule for running automated vulnerability scans of the system", "Metrics, monitoring frequency, tools, reporting, roles, and remediation tracking", "Only the expiration date of the authorization to operate", "Only the name of the assigned independent assessor"], answer: 1, explain: "A comprehensive ConMon strategy (CA-7) covers metrics to measure, frequency of monitoring activities, tools used, reporting requirements, responsible parties, and the process for acting on findings."),

    // MARK: – Batch 4: Domain 4 expansion (+84 implementation)
    Question(id: 700, domain: 4, text: "Encryption of data at rest in a federal system is primarily governed by which SP 800-53 control?", options: ["SC-28 (Protection of Information at Rest)", "SC-8 (Transmission Confidentiality)", "MP-5 (Media Transport)", "AC-3 (Access Enforcement)"], answer: 0, explain: "SC-28 requires protecting the confidentiality and integrity of information at rest — typically implemented using FIPS-validated encryption (FIPS 140-2/3) for stored data."),
    Question(id: 701, domain: 4, text: "TLS (Transport Layer Security) is used to implement which type of control?", options: ["Encryption of data at rest on the system's persistent storage media", "Physical security of the facility that houses the network equipment", "Encryption of data in transit across networks", "Access control governing which users may reach the application"], answer: 2, explain: "TLS encrypts communications in transit, implementing SC-8 (Transmission Confidentiality and Integrity) — protecting data from interception and tampering during network transmission."),
    Question(id: 702, domain: 4, text: "A system administrator implements automatic session timeouts after 15 minutes of inactivity. This implements which SP 800-53 control?", options: ["AC-2 (Account Management)", "IA-5 (Authenticator Management)", "AC-11 (Device Lock) and AC-12 (Session Termination)", "AU-2 (Event Logging)"], answer: 2, explain: "AC-11 (Device Lock) and AC-12 (Session Termination) require automatic locking or termination of sessions after inactivity — preventing unauthorized use of unattended sessions."),
    Question(id: 703, domain: 4, text: "During implementation, a developer hardcodes database credentials in source code. This violates which security principle?", options: ["The principle of defense in depth across the layers", "The non-repudiation of every individual user's actions", "Data minimization of records", "Least privilege and secure credential management"], answer: 3, explain: "Hardcoded credentials violate IA-5 (Authenticator Management) principles — credentials in source code are easily discovered, difficult to rotate, and expose the system to unauthorized access if the code is compromised. Credentials should be managed securely, not embedded in code."),
    Question(id: 704, domain: 4, text: "Role-Based Access Control (RBAC) implements which security principle?", options: ["Non-repudiation, ensuring actions cannot later be denied by the actor", "Defense in depth, layering independent and overlapping security controls", "Data minimization of collected records", "Least privilege — users get only the permissions their role requires"], answer: 3, explain: "RBAC assigns permissions to roles rather than individuals — implementing least privilege by ensuring users receive only the access required for their specific job function."),
    Question(id: 705, domain: 4, text: "Attribute-Based Access Control (ABAC) makes access decisions based on:", options: ["Combinations of user, resource, environment, and action attributes", "The specific time of day at which the access request happens to be submitted", "The user's assigned roles and nothing else", "The physical location of the requester only"], answer: 0, explain: "ABAC evaluates multiple attributes simultaneously — user attributes (clearance, role), resource attributes (classification, type), environmental attributes (time, location), and requested action — enabling very granular access decisions."),
    Question(id: 706, domain: 4, text: "A system implements multi-factor authentication (MFA). The 'factors' in MFA refer to:", options: ["Multiple distinct passwords that the user must enter one after another", "Something you know, something you have, and something you are", "Multiple usernames mapped to the same underlying account identity", "Multiple independent systems that each authenticate the same user"], answer: 1, explain: "MFA requires two or more distinct authentication factors: knowledge (password, PIN), possession (token, smart card, phone), and inherence (biometric). Using two factors from the same category (two passwords) is NOT MFA."),
    Question(id: 707, domain: 4, text: "PIV (Personal Identity Verification) cards are required for federal agency systems because:", options: ["They are simply much cheaper than passwords to run", "They remove the need for any other access controls", "Only TOP SECRET systems require them", "HSPD-12 and OMB M-11-11 mandate PIV for access"], answer: 3, explain: "HSPD-12 established the PIV standard; OMB M-11-11 required agencies to use PIV for logical access — providing a standardized, high-assurance, cryptographic authentication mechanism across the federal government."),
    Question(id: 708, domain: 4, text: "Static Application Security Testing (SAST) is performed:", options: ["Against source code or binaries without executing the program", "Against a running application", "Only by external assessors", "Only after deployment to production"], answer: 0, explain: "SAST analyzes source code, bytecode, or binary code without execution — finding vulnerabilities like injection flaws, buffer overflows, and insecure cryptography early in the SDLC (SA-11 Developer Testing). Identifying vulnerabilities in the code before deployment."),
    Question(id: 709, domain: 4, text: "Dynamic Application Security Testing (DAST) differs from SAST in that:", options: ["DAST examines source code; SAST tests running applications", "DAST tests the running application from the outside", "DAST is only performed manually", "DAST requires access to the source code"], answer: 1, explain: "DAST (sometimes called 'black box testing') tests running applications by sending malicious inputs and analyzing responses — finding vulnerabilities like SQL injection and XSS that only manifest at runtime. Simulating attacks against a live instance to find runtime vulnerabilities."),
    Question(id: 710, domain: 4, text: "Software Composition Analysis (SCA) is used to:", options: ["Identify open-source components and their known vulnerabilities", "Test the application's runtime performance under heavy production load", "Analyze source code for logic errors", "Monitor the application's runtime behavior"], answer: 0, explain: "SCA identifies open-source libraries and components used in an application and checks them against vulnerability databases — addressing supply chain risks from third-party code dependencies."),
    Question(id: 711, domain: 4, text: "A web application firewall (WAF) primarily protects against:", options: ["Network-layer distributed denial-of-service flooding attacks against the host", "Physical intrusion into the facility", "Application-layer attacks like SQLi, XSS, and CSRF over HTTP", "Insider threats from staff"], answer: 2, explain: "A WAF sits in front of web applications and filters HTTP/HTTPS traffic — blocking common web application attacks (OWASP Top 10) that pass through network firewalls."),
    Question(id: 712, domain: 4, text: "Implementing database activity monitoring (DAM) supports which SP 800-53 control family?", options: ["PE (Physical and Environmental Protection) for the database servers", "CP (Contingency Planning) for database backup and recovery operations", "AU (Audit and Accountability), logging database activity", "SA (System and Services Acquisition) for the database software supply"], answer: 2, explain: "DAM generates audit records of database access and queries (AU-2, AU-3) and enables detection of unauthorized or anomalous database activity — supporting both accountability and SI-4 (System Monitoring)."),
    Question(id: 713, domain: 4, text: "A system implementing 'privileged access workstations' (PAWs) is implementing which security principle?", options: ["Separating privileged admin from normal user activity", "Defense in depth achieved through physical barriers only", "Non-repudiation of administrative actions", "Data minimization of stored data"], answer: 0, explain: "PAWs provide dedicated, hardened workstations for administrative tasks — separating privileged access from normal internet/email use, reducing the attack surface for credential theft and lateral movement."),
    Question(id: 714, domain: 4, text: "Just-in-time (JIT) privileged access means:", options: ["Grant elevated rights only when needed, then revoke them", "Permanent standing privileged accounts for the administrators", "Automated deployment of software patches across the environment", "Only the use of time-based one-time passwords for authentication"], answer: 0, explain: "JIT access implements least privilege dynamically — no one has standing privileged access. Privileges are granted on-demand for specific tasks with defined scope and duration, then revoked — reducing insider threat exposure."),
    Question(id: 715, domain: 4, text: "Implementing network micro-segmentation is an example of which security principle?", options: ["Data minimization of the personal records that are collected and stored", "Non-repudiation of user actions", "Defense in depth via network isolation that limits lateral movement", "Least functionality of user accounts"], answer: 2, explain: "Micro-segmentation divides the network into small, isolated zones — if an attacker compromises one zone, they cannot freely move laterally. This is a key Zero Trust and defense-in-depth principle."),
    Question(id: 716, domain: 4, text: "A developer implements input validation on a web form. This primarily protects against:", options: ["Distributed denial-of-service attacks that flood the application with traffic", "Man-in-the-middle interception of traffic between the client and server", "Injection attacks like SQL injection, command injection, and XSS", "Physical theft of the application server"], answer: 2, explain: "Input validation (SI-10) is a critical control against injection attacks — by validating that inputs match expected type, length, format, and range, the system rejects malicious payloads before they reach backend systems."),
    Question(id: 717, domain: 4, text: "Security Information and Event Management (SIEM) systems primarily support:", options: ["Central log collection, correlation, and alerting", "Encryption of the system's data while it is at rest", "Physical access control to the data center facility", "Automation of the organization's patch management work"], answer: 0, explain: "SIEMs aggregate logs from multiple sources, correlate events to detect patterns (anomalies, attack sequences), generate alerts, and provide a centralized view for security operations — supporting AU and SI-4 (System Monitoring)."),
    Question(id: 718, domain: 4, text: "Endpoint Detection and Response (EDR) solutions are used to:", options: ["Manage the deployment scheduling of operating system and application patches", "Encrypt the storage volumes attached to each endpoint", "Track and reconcile software license entitlements", "Monitor endpoints, detect threats, investigate, and enable response actions"], answer: 3, explain: "EDR provides continuous endpoint monitoring, behavioral analysis, threat detection, investigation capabilities, and response actions — going beyond traditional antivirus to address advanced threats."),
    Question(id: 719, domain: 4, text: "Implementing 'immutable infrastructure' (replacing rather than patching running instances) supports which security principle?", options: ["Availability through redundancy", "Non-repudiation", "Data minimization", "System integrity"], answer: 3, explain: "Immutable infrastructure replaces instances from a known-good image rather than modifying running systems — eliminating configuration drift, reducing the attack surface, and ensuring integrity of deployed components. Replacing compromised or drifted instances ensures a known-good state rather than patching uncertain environments."),
    Question(id: 720, domain: 4, text: "A security requirement calls for all privileged commands to be logged with the user's identity. This implements which SP 800-53 control?", options: ["AU-2 (Event Logging) and AU-9 (Protection of Audit Information)", "AC-5 (Separation of Duties)", "IA-2 (Identification and Authentication)", "CM-3 (Configuration Change Control)"], answer: 0, explain: "Logging privileged commands with user identity implements AU-2 (defining auditable events including privileged functions) and AU-3 (capturing who performed the action) — enabling accountability for administrative activities."),
    Question(id: 721, domain: 4, text: "A patch management process that tests patches in a staging environment before production deployment implements which principle?", options: ["The patch will always work in production if it works in staging", "Risk management", "Separation of duties only", "It is unnecessary overhead for security patches"], answer: 1, explain: "Testing patches in staging before production deployment balances the need for timely patching (SI-2) against operational risk — ensuring patches don't break functionality or introduce new issues. Validating patches in a non-production environment reduces the risk of patch-induced outages or security issues in production."),
    Question(id: 722, domain: 4, text: "A contractor is performing remote maintenance on a federal system. Which controls MOST apply to this scenario?", options: ["PE-3 (Physical Access Control)", "CP-2 (Contingency Plan)", "MA-4 (Nonlocal Maintenance)", "AC-2 (Account Management) only"], answer: 2, explain: "MA-4 specifically governs nonlocal (remote) maintenance — requiring MFA, encrypted sessions, logging, and approval before remote maintenance activities can occur, protecting the system from unauthorized access during maintenance. Requiring authentication, session encryption, and approval for remote maintenance activities."),
    Question(id: 723, domain: 4, text: "Implementing data loss prevention (DLP) tools addresses which security concern?", options: ["Physical theft of the organization's server and endpoint hardware assets", "Unauthorized exfiltration of sensitive data through many channels", "Encryption of data while it is at rest", "Authentication of the system's users"], answer: 1, explain: "DLP monitors and controls data movement — blocking unauthorized transmission of sensitive information (PII, financial data, intellectual property) via email, web uploads, USB, or other exfiltration channels."),
    Question(id: 724, domain: 4, text: "A developer is told to follow secure coding standards (e.g., OWASP Top 10 mitigations). This is required by which SP 800-53 control family?", options: ["SA (System and Services Acquisition)", "AU (Audit and Accountability)", "IR (Incident Response)", "CM (Configuration Management)"], answer: 0, explain: "SA-11 and SA-15 require developers to use secure coding practices, testing, and tools throughout the SDLC — making secure coding standards a control requirement, not just a best practice. Specifically SA-11 (Developer Testing) and SA-15 (Development Process, Standards, and Tools)."),
    Question(id: 725, domain: 4, text: "An organization implements a bug bounty program. This primarily supports which security objective?", options: ["Demonstrating regulatory compliance with mandated security requirements", "Serving as a complete replacement for traditional penetration testing", "Managing the organization's insider threats", "Finding unknown vulnerabilities via external researchers' testing"], answer: 3, explain: "Bug bounty programs invite external security researchers to find and responsibly disclose vulnerabilities — providing broad, crowd-sourced vulnerability discovery that supplements internal testing and penetration tests."),
    Question(id: 726, domain: 4, text: "During implementation, a system team discovers a third-party library with a critical CVE. The BEST response is:", options: ["Assess impact in context, remediate if high-risk, and track in the POA&M", "Continue using the library and plan to update it at the next scheduled release cycle", "Remove the entire application from production service immediately and without analysis", "Wait for the upstream vendor to release an official patch before taking any action"], answer: 0, explain: "A critical CVE requires immediate risk assessment in context. If the vulnerability is exploitable and high-risk, remediation (update, workaround, or compensating control) is urgent. The POA&M tracks progress if an immediate fix is unavailable."),
    Question(id: 727, domain: 4, text: "Physical access control systems (badge readers, biometrics) at a data center implement which SP 800-53 control?", options: ["AC-2 (Account Management) of the user accounts", "PE-2 and PE-3 (Physical Access controls)", "IA-2 (Identification and Authentication) of users", "SC-7 (Boundary Protection)"], answer: 1, explain: "PE-2 and PE-3 address physical access — authorizing who can enter controlled areas and implementing mechanisms (badge readers, biometrics, guards) to enforce those authorizations."),
    Question(id: 728, domain: 4, text: "A system uses a hardware security module (HSM) for cryptographic key management. This primarily addresses which security requirement?", options: ["Audit logging of every cryptographic key's usage", "Network boundary protection for the whole system", "Physical and environmental monitoring of the site", "Secure key storage in tamper-resistant hardware"], answer: 3, explain: "HSMs provide FIPS 140-2/3 validated, tamper-resistant protection for cryptographic keys — implementing SC-12 (key management) and IA-7 (cryptographic module requirements) with hardware-level assurance."),
    Question(id: 729, domain: 4, text: "A system team is implementing audit logging. Which of the following is a critical attribute that audit records MUST capture?", options: ["The logged-in user's direct manager's full name and title", "Only the system's source IP address", "Only the failed access attempts", "What happened, when, where, who did it, and the outcome"], answer: 3, explain: "AU-3 (Content of Audit Records) requires that audit logs capture sufficient detail: event type, date/time, source, subject (user/process), object (resource), and outcome — enabling reconstruction of events."),
    Question(id: 730, domain: 4, text: "An organization is implementing a zero trust network architecture. The fundamental change from traditional perimeter-based security is:", options: ["Removing all firewalls", "Requiring VPN for all access", "Eliminating implicit trust based on network location", "Using only cloud-based systems"], answer: 2, explain: "Zero Trust removes the concept of a trusted inside vs. untrusted outside. Every access request — from any location, on any device — is authenticated, authorized, and continuously validated before access is granted. Every request is verified regardless of whether it originates inside or outside the perimeter."),
    Question(id: 732, domain: 4, text: "Software integrity verification (e.g., hash comparison before deployment) implements which SP 800-53 control?", options: ["SI-7 (Software, Firmware, and Information Integrity)", "AU-2 (Event Logging)", "CM-3 (Configuration Change Control)", "IA-3 (Device Identification and Authentication)"], answer: 0, explain: "SI-7 requires employing integrity verification tools to detect unauthorized changes to software and firmware — typically using cryptographic hashes compared against known-good values."),
    Question(id: 733, domain: 4, text: "Implementing a demilitarized zone (DMZ) between the internet and internal networks is an example of:", options: ["Defense in depth via network segmentation", "Classification of data according to its sensitivity level", "Least privilege access for individual end users", "Contingency planning for system recovery operations"], answer: 0, explain: "A DMZ is a network architecture pattern implementing SC-7 Boundary Protection — placing public-facing servers in a controlled intermediate zone, limiting direct internet access to internal networks."),
    Question(id: 734, domain: 4, text: "An organization implements mandatory access control (MAC) rather than discretionary access control (DAC). The key difference is:", options: ["In MAC the system enforces access by label; in DAC owners decide", "MAC is entirely software-based, whereas DAC is implemented in hardware", "MAC grants users more access than DAC does", "DAC is more secure than MAC in every case"], answer: 0, explain: "MAC enforces access based on security labels and system-defined policies (used in classified systems) — resource owners cannot override policy. DAC allows resource owners to set permissions at their discretion."),
    Question(id: 735, domain: 4, text: "A system processes payment card data. Which implementation requirement is specific to PCI-DSS (not a standard NIST baseline control)?", options: ["Encrypting the cardholder data while it is in transit over networks", "Implementing role-based access controls", "Quarterly external ASV scans and annual penetration testing", "Logging the security-relevant events"], answer: 2, explain: "While many PCI-DSS requirements overlap with NIST controls, specific requirements like ASV-conducted external quarterly scans and annual penetration tests by a qualified assessor are PCI-DSS-specific mandates."),
    Question(id: 736, domain: 4, text: "Network intrusion detection/prevention systems (IDS/IPS) primarily implement which SP 800-53 control?", options: ["AC-4 (Information Flow Enforcement) between network zones", "CM-7 (Least Functionality) for disabling unused services", "PE-3 (Physical Access Control)", "SI-4 (System Monitoring) of network traffic for threats"], answer: 3, explain: "IDS/IPS implement SI-4 by monitoring network and system activity for signs of attack, anomalies, and unauthorized activity — alerting security staff and (for IPS) actively blocking malicious traffic."),
    Question(id: 737, domain: 4, text: "A security team implements a security orchestration, automation and response (SOAR) platform. This primarily enhances:", options: ["Static analysis of the application's source code during the integration build pipeline", "Incident response speed and consistency via automation and tool orchestration", "Selection of the correct security control baseline during the RMF Select step process", "Physical security of the facility"], answer: 1, explain: "SOAR platforms automate and orchestrate security operations — accelerating incident detection, investigation, and response by automating repetitive tasks and integrating security tools with defined playbooks."),
    Question(id: 738, domain: 4, text: "During system implementation, user acceptance testing (UAT) and security testing should:", options: ["Occur strictly in sequence — UAT first, and then the security testing", "Only ever take place after the system has already been deployed", "Be coordinated, security testing integrated throughout", "Be run by the very same team in order to save on resources"], answer: 2, explain: "Security testing throughout the SDLC (SA-11) — not just at the end — catches vulnerabilities early when they are cheapest to fix. Integrating security into UAT and other test phases improves both security and quality."),
    Question(id: 739, domain: 4, text: "A system implements the principle of 'fail secure.' This means:", options: ["The system deliberately fails often to test out its recovery", "On failure, default to a secure state like denying access", "The system never fails at all thanks to its full redundancy", "The security controls are the last things to fail"], answer: 1, explain: "Fail secure (or fail closed) ensures that system failures default to the most restrictive, secure state — e.g., a firewall that fails should block all traffic, not open all ports."),
    Question(id: 740, domain: 4, text: "Implementing code signing for software updates ensures:", options: ["The update is encrypted while it is in transmission", "It's from a trusted publisher and untampered", "The update has been fully tested for its functionality", "The update installs without any user interaction at all"], answer: 1, explain: "Code signing uses a developer's private key to sign software; users verify the signature with the public key — confirming authenticity (trusted publisher) and integrity (no tampering) per SI-7."),
    Question(id: 741, domain: 4, text: "A system uses a content delivery network (CDN) for serving web content. For authorization boundary purposes, the CDN:", options: ["Is always outside the boundary with no security considerations", "Must be evaluated", "Is automatically covered by the CSP's FedRAMP authorization", "Never requires documentation"], answer: 1, explain: "CDNs that cache or process sensitive data (PII, authentication tokens) must be within the boundary or covered by a formal agreement — their handling of government data creates security and privacy obligations. If the CDN caches or processes sensitive data, it may need to be within the boundary or covered by a formal agreement."),
    Question(id: 742, domain: 4, text: "A system implements 'time-based one-time passwords' (TOTP). This satisfies which authentication requirement?", options: ["Something you know, such as a memorized password, on its own", "Something you are, such as a biometric", "Both something you know and something you are", "Something you have — an app generating time-based codes"], answer: 3, explain: "TOTP generates time-sensitive codes using a shared secret in an authenticator app — representing the 'something you have' authentication factor used in MFA implementations."),
    Question(id: 743, domain: 4, text: "A system has a documented configuration management plan (CMP). The CMP should include:", options: ["Only the recurring patch deployment schedule for the operating systems and applications", "Only the authoritative inventory of installed software packages across all the systems", "Only the documented network topology diagram", "Roles, CM processes, baseline management, change control, and configuration auditing"], answer: 3, explain: "A Configuration Management Plan (CMP) per SP 800-128 documents the roles, processes, and procedures governing configuration baselines, change control, inventory, and auditing throughout the system lifecycle."),
    Question(id: 744, domain: 4, text: "Implementing 'secure boot' on servers ensures:", options: ["Only cryptographically verified firmware and OS components load at startup", "Servers boot faster", "Servers can boot from any media", "Disk encryption keys are automatically generated"], answer: 0, explain: "Secure boot uses firmware signatures to verify each component in the boot chain — from UEFI firmware through the bootloader and OS kernel — preventing malicious code from loading before the OS. Protecting against rootkits and boot-level malware."),
    Question(id: 745, domain: 4, text: "A system uses certificate-based mutual TLS (mTLS) for service-to-service authentication. This implements:", options: ["Single-factor authentication between services", "Mutual authentication", "Data encryption at rest only", "Physical access control"], answer: 1, explain: "mTLS requires both client and server to present valid certificates — providing mutual device authentication (IA-3) and ensuring only authorized services can communicate, a key Zero Trust principle. Both parties verify each other's certificates before establishing a connection, implementing IA-3 (Device Identification and Authentication)."),
    Question(id: 746, domain: 4, text: "Log integrity protection (e.g., write-once storage, cryptographic signatures on logs) implements which control?", options: ["AU-2 (Event Logging), which defines exactly which events the system records", "AU-3 (Content of Audit Records)", "AU-9 (Protection of Audit Information) against tampering or deletion", "AU-6 (Audit Record Review and Analysis)"], answer: 2, explain: "AU-9 requires protecting audit information from unauthorized access and modification — ensuring logs remain trustworthy evidence by using write-once storage, cryptographic signing, or separate log management systems."),
    Question(id: 747, domain: 4, text: "An organization creates a system-specific security engineering checklist aligned with SP 800-160. This supports:", options: ["Informing only the source-selection and the contract-award decisions for the program", "Supporting only the post-deployment assessment of the fielded system", "Integrating security into every engineering phase from initiation through disposal", "Supporting only the initial vendor selection process"], answer: 2, explain: "SP 800-160 Vol. 1 provides a multidisciplinary approach to engineering trustworthy secure systems — integrating security considerations into every system engineering activity across the full lifecycle."),
    Question(id: 749, domain: 4, text: "Which implementation activity ensures that only authorized hardware is connected to the organization's network?", options: ["Software inventory management tracking installed application versions", "Email content filtering that blocks malicious attachments and links", "Security awareness training delivered to all system end users annually", "Network Access Control (NAC) verifying device identity and health"], answer: 3, explain: "NAC enforces device authentication and health checks before network admission — implementing IA-3 (Device Identification and Authentication) and CM-8 (System Component Inventory) by controlling what connects to the network."),
    Question(id: 750, domain: 4, text: "A system implements automated configuration compliance scanning. This supports which RMF activity?", options: ["Initial security control selection performed during the RMF Select step only", "Continuous monitoring — verifying systems keep their approved baseline", "The one-time authorization assessment performed before the ATO is granted", "System decommissioning and the secure disposal of all the system's media"], answer: 1, explain: "Automated configuration compliance scanning (e.g., SCAP-based tools) continuously verifies that deployed systems match their approved secure baseline configurations — a core ConMon activity supporting CA-7 and CM-6."),
    Question(id: 751, domain: 4, text: "Implementing security in a containerized environment (e.g., Docker, Kubernetes) requires attention to:", options: ["Image security, runtime protection, orchestration, network policy, and secrets", "Only the vulnerabilities present in the container base images that are pulled in", "Only the network firewalls that are placed around the Kubernetes cluster perimeter", "Only the security of the underlying host operating system"], answer: 0, explain: "Container security requires a comprehensive approach: securing base images, scanning for vulnerabilities, enforcing runtime policies, securing the orchestration platform, managing secrets, and controlling network communication between containers."),
    Question(id: 752, domain: 4, text: "A system undergoes a major version upgrade. Which action is REQUIRED before going back to production?", options: ["Run a security impact analysis, update the SSP, test, and get CCB approval", "Notify the end users of the change only", "Simply replace the old version in place", "Perform a complete full reassessment of the system before doing any testing"], answer: 0, explain: "Major version upgrades are significant changes requiring security impact analysis (CA-2), SSP updates, testing (SA-11), CCB approval (CM-3), and potentially notifying the AO if the risk posture changes materially."),
    Question(id: 753, domain: 4, text: "A federal system uses a commercial cloud service that is NOT FedRAMP authorized. The agency should:", options: ["Proceed anyway, because FedRAMP authorization is optional", "Use the cloud service only for clearly non-sensitive agency data", "Run an agency assessment or require FedRAMP", "Accept the provider's existing SOC 2 report as fully sufficient"], answer: 2, explain: "OMB guidance requires federal agencies to use FedRAMP-authorized cloud services for federal data. Using non-authorized services requires the agency to conduct its own full assessment — or the CSP must pursue FedRAMP authorization."),
    Question(id: 754, domain: 4, text: "Proper media labeling (e.g., marking removable drives with sensitivity classification) implements which control?", options: ["SC-28 (Protection of Information at Rest)", "PE-16 (Delivery and Removal)", "MP-3 (Media Marking)", "AU-9 (Protection of Audit Information)"], answer: 2, explain: "MP-3 requires marking media with distribution limitations, handling caveats, and applicable security markings — ensuring personnel know how to handle media based on its sensitivity."),
    Question(id: 755, domain: 4, text: "An organization discovers that an employee copied sensitive files to a personal USB drive. This incident indicates a failure of:", options: ["Only physical security controls", "Only awareness training", "Only network controls", "Media protection (MP-7 Media Use"], answer: 3, explain: "Unauthorized use of removable media violates MP-7 (Media Use) — which should restrict or prohibit use of personally owned media on organizational systems. DLP tools and audit logging should have detected the activity. Restricting or prohibiting removable media), DLP controls, and potentially audit logging."),
    Question(id: 756, domain: 4, text: "Implementing a secure software development lifecycle (S-SDLC) means:", options: ["Integrating security activities", "Adding a security review only at the end of development", "Only using approved programming languages", "Only training developers on security policies"], answer: 0, explain: "An S-SDLC embeds security into each development phase: security requirements in planning, threat modeling in design, code review and SAST in development, security testing before deployment, and monitoring post-release."),
    Question(id: 757, domain: 4, text: "Which of the following BEST describes 'privileged account management' (PAM) as a security practice?", options: ["Managing all of the organization's ordinary standard user accounts", "Managing the system administrators' email mailbox accounts", "Controlling, monitoring, and auditing privileged accounts", "Resetting forgotten passwords"], answer: 2, explain: "PAM encompasses discovering privileged accounts, vaulting and rotating credentials, requiring MFA, recording privileged sessions, enforcing JIT access, and providing detailed audit trails — addressing the highest-risk account type."),
    Question(id: 759, domain: 4, text: "A system stores Social Security Numbers in a database. The MINIMUM protection per SP 800-122 guidance would include:", options: ["Encrypt at rest, limit access, and mask SSNs in displays", "Store the SSNs in plain text but with complete audit logging", "Store the SSNs with simple password protection on the file", "Hash the SSNs using the MD5 algorithm for storage"], answer: 0, explain: "SSNs are highly sensitive PII — SP 800-122 calls for strong protections: FIPS-validated encryption at rest, strict access controls, and masking (showing only last 4 digits) in displays and logs."),
    Question(id: 760, domain: 4, text: "Vulnerability remediation timelines (e.g., Critical = 15 days, High = 30 days) should be documented in:", options: ["The system's end-user training handbook and reference guide", "Only the vendor's signed service-level agreement document itself", "Only the most recent penetration test report and nowhere else", "The patch policy, the SSP, and the ConMon strategy"], answer: 3, explain: "Remediation timelines are organization-defined parameters in SI-2 and RA-5. They must appear in policy and the SSP, and be tracked through the POA&M and ConMon program."),
    Question(id: 761, domain: 4, text: "A system owner implements 'micro-frontends' where different parts of the user interface are served by separate teams. From a security perspective, this architecture requires:", options: ["Issuing a completely separate authorization for each micro-frontend component", "Careful handling of CORS, CSP, and authentication across all components", "A single SSP that covers all of the frontends together", "No special attention, since it is only the UI layer"], answer: 1, explain: "Distributed frontend architectures introduce cross-origin security risks — CORS policies, CSP headers, authentication token sharing, and consistent security controls must be deliberately designed across all components."),
    Question(id: 762, domain: 4, text: "When implementing controls for a mobile application accessing federal systems, which security consideration is unique to mobile?", options: ["Encryption of the application's data while it is in transit across the network links", "Authentication of the end user before any access to the application is granted", "Jailbreak/root detection, cert pinning, and secure on-device storage", "Audit logging of all the security-relevant events occurring within the system"], answer: 2, explain: "Mobile environments introduce unique risks: unmanaged devices, app store distribution, OS fragmentation, jailbreaking/rooting, and insecure local storage. Mobile-specific controls address these risks beyond standard system controls."),
    Question(id: 763, domain: 4, text: "A system team implements 'secrets management' (e.g., HashiCorp Vault). This specifically addresses which vulnerability?", options: ["SQL injection flaws in dynamically built database queries", "Distributed denial-of-service attacks that exhaust the application's network capacity", "Hardcoded credentials and secrets exposed in source code or config files", "Physical theft of on-premises server hardware"], answer: 2, explain: "Secrets management centralizes the storage, rotation, and access control of credentials and secrets — preventing hardcoded credentials, implementing automatic rotation, and providing fine-grained access control (IA-5)."),
    Question(id: 764, domain: 4, text: "Implementing security controls for an API (Application Programming Interface) requires attention to:", options: ["Authentication, authorization, rate limiting, validation, and encryption", "Only the network firewall rules that surround the API gateway infrastructure host", "Only server-side encryption of the data that the API persists to its backing store", "Only keeping the published API reference documentation complete and fully current"], answer: 0, explain: "API security requires the same controls as any system boundary: authentication of callers, authorization of permitted operations, rate limiting against abuse, input validation against injection, and encryption in transit."),
    Question(id: 765, domain: 4, text: "A system team discovers that their application uses deprecated SSL/TLS versions (SSL 3.0, TLS 1.0). The correct action is:", options: ["Accept it if no known attacks are currently targeting it", "Disable deprecated protocols and enforce only TLS 1.2 or 1.3", "Document it in the POA&M with a 2-year remediation timeline", "Keep them for backward compatibility with older clients"], answer: 1, explain: "SSL 3.0, TLS 1.0, and TLS 1.1 have critical vulnerabilities (POODLE, BEAST, etc.) and must be disabled per NIST and OMB guidance — only TLS 1.2 and 1.3 are acceptable for federal systems. Deprecated versions have known vulnerabilities exploitable by attackers."),
    Question(id: 766, domain: 4, text: "Which implementation practice supports the 'personnel security' control family (PS)?", options: ["Installing network firewalls at the organization's perimeter", "Encrypting all of the sensitive data while it is sitting at rest", "Run background investigations before granting any access", "Logging all of the network connections"], answer: 2, explain: "PS-3 requires personnel screening appropriate to the position's risk designation before granting access — ensuring individuals with access to sensitive systems have been vetted."),
    Question(id: 767, domain: 4, text: "An organization uses infrastructure-as-code (IaC) to deploy systems. From a security perspective, IaC templates should:", options: ["Be stored in public repositories for full transparency", "Be generated entirely automatically without any human review", "Be version-controlled, security-reviewed, and scanned", "Only be reviewed once per year"], answer: 2, explain: "IaC templates define infrastructure configurations — insecure templates deploy insecure infrastructure at scale. Security reviews, SAST tools for IaC (e.g., Terraform scanners), and version control are essential."),
    Question(id: 768, domain: 4, text: "A system implements a 'data retention and deletion' policy. This primarily supports which requirement?", options: ["Application and database performance optimization across the system only", "Privacy data minimization, legal retention compliance, and security", "Audit logging requirements and nothing else", "Physical storage capacity optimization only"], answer: 1, explain: "Data retention/deletion addresses the Privacy Act, GDPR's storage limitation principle, legal holds, and security — holding data only as long as necessary reduces the privacy and security risk of a breach."),
    Question(id: 770, domain: 4, text: "Which approach BEST describes 'security left shift' in software development?", options: ["Deploying security controls only on the left side of the network", "Assigning security responsibilities to development teams only", "Moving security activities earlier in the SDLC", "Using left-handed security engineers"], answer: 2, explain: "Shifting security left means addressing security requirements and vulnerabilities early in the SDLC — finding and fixing issues in design/development is far cheaper than post-deployment remediation. Integrating threat modeling, code review, and security testing into design and development phases."),
    Question(id: 771, domain: 4, text: "During implementation, the team discovers the vendor-provided system does not meet FIPS 140-2 requirements for cryptographic modules. The BEST action is:", options: ["Proceed anyway, since FIPS 140 is optional", "Accept a written waiver from the vendor", "Document it, assess the risk, seek a validated alternative, and tell the AO", "Just substitute a different encryption algorithm of your own choosing instead"], answer: 2, explain: "FIPS 140-2/3 validated cryptographic modules are mandatory for federal systems protecting sensitive information. Non-compliance is a significant finding requiring formal risk acceptance by the AO or replacement with a validated module."),
    Question(id: 772, domain: 4, text: "A system team implements 'canary deployments' for software releases. From a security perspective, this practice:", options: ["Catch issues in a small slice before full rollout", "It is purely a deployment optimization with no security value", "It removes the need for any kind of security testing", "It only applies to canary token implementations used"], answer: 0, explain: "Canary deployments route a small percentage of traffic to the new version — if security issues or anomalies are detected, the rollout can be stopped before all users are affected, limiting exposure."),
    Question(id: 773, domain: 4, text: "Implementing formal change management (CCB) for security patches balances:", options: ["Compliance vs. vendor preference", "Security speed vs. operational stability", "Developer preference vs. AO authority", "Cost vs. convenience"], answer: 1, explain: "Mature patch management defines both standard change processes (testing, CCB approval) and expedited processes for critical security patches — balancing the need for timely remediation against operational change risk. Urgent patches may need expedited review processes rather than standard change cycles."),
    Question(id: 774, domain: 4, text: "An organization's system uses a shared database with another agency application. The security boundary consideration requires:", options: ["A single shared SSP that jointly covers both of the participating agency applications", "No special consideration, since both are operated as government information systems", "Separate boundaries with an ISA for the shared database, or include it in both", "The database automatically inherits the ATO of both connected systems"], answer: 2, explain: "Shared resources between separately authorized systems require formal documentation — either an ISA governing the interface, or the shared resource included within a common authorization with clear control responsibilities."),
    Question(id: 775, domain: 4, text: "A system team discovers that a previously approved configuration baseline was not actually deployed to all systems. This is best addressed by:", options: ["Audit, log it in the POA&M, remediate to baseline, and monitor for drift", "Create a new baseline that simply matches whatever configuration the systems now have", "Defer reporting until the next annual assessment cycle documents the discrepancy", "Ignore the discrepancy as long as no security incident has yet resulted from it"], answer: 0, explain: "Configuration drift from the approved baseline is a finding — requiring audit to identify affected systems, POA&M documentation, remediation to restore compliance, and enhanced monitoring to prevent recurrence."),
    Question(id: 776, domain: 4, text: "A system implements automatic account lockout after 5 failed authentication attempts. This control primarily protects against:", options: ["Phishing attacks directed against the organization's individual users", "SQL injection against the backend database", "Man-in-the-middle attacks on the traffic", "Brute-force and password-spraying attacks, by limiting guesses"], answer: 3, explain: "Account lockout (AC-7) limits failed authentication attempts — preventing brute force attacks where an attacker tries many passwords against a single account, and password spraying where one password is tried across many accounts."),
    Question(id: 777, domain: 4, text: "During implementation of a financial system, the team is required to ensure all transactions are logged with tamper-evident records. This supports which security objective?", options: ["Availability", "Integrity and non-repudiation", "Confidentiality", "Authentication"], answer: 1, explain: "Tamper-evident transaction logs implement AU controls (audit logging) supporting integrity (detecting unauthorized changes) and non-repudiation (proving who performed each transaction) — critical for financial systems. Tamper-evident logs enable detection of unauthorized transaction modifications and prove who performed each transaction."),
    Question(id: 778, domain: 4, text: "An organization creates a 'software bill of materials' (SBOM) for its applications. An SBOM is primarily used to:", options: ["Document the total acquisition and ongoing maintenance costs of the software", "Track compliance with the terms of every individual software component license", "Serve as a replacement for security assessments", "Identify all software components so vulnerable ones can be found fast"], answer: 3, explain: "SBOMs (required by EO 14028) provide a comprehensive inventory of software components and dependencies — enabling organizations to quickly identify which systems are affected when a vulnerability is disclosed in a specific component."),
    Question(id: 779, domain: 4, text: "The concept of 'privacy by default' (as required by GDPR Art. 25 and aligned with NIST privacy principles) means:", options: ["Users are required to opt in before any of their personal data may be processed at all", "All personal data held by the system is automatically rendered fully anonymous to staff", "By default the system processes only minimum data and the most protective settings", "Privacy-enhancing controls remain optional unless a user turns them on"], answer: 2, explain: "Privacy by default ensures that without any user action, the default setting is the most privacy-protective option — users shouldn't have to take steps to protect their privacy; the system does it automatically."),
    Question(id: 780, domain: 4, text: "When implementing inherited controls from a common control provider, the system owner must:", options: ["Document the inheritance in the SSP and verify the CCP's authorization is current", "Independently reimplement each inherited control locally as a fully redundant backup copy", "Nothing, because inherited controls require no documentation at all", "Only mention the CCP's organization name somewhere in the SSP"], answer: 0, explain: "Proper inheritance requires: documenting which controls are inherited from which CCP, verifying the CCP's authorization is current and covers the system's needs, and understanding how inherited controls contribute to the system's protection."),
    Question(id: 781, domain: 4, text: "A system implementing 'privacy-enhancing technologies' (PETs) such as differential privacy or k-anonymity is primarily addressing:", options: ["Optimization of the overall system's runtime performance levels", "Privacy risk reduction while preserving the data's utility", "Regulatory compliance documentation only", "Data encryption requirements"], answer: 1, explain: "PETs like differential privacy (adding calibrated noise) and k-anonymity (ensuring individuals are indistinguishable among at least k others) provide mathematical privacy guarantees — reducing re-identification risk while preserving data utility."),
    Question(id: 782, domain: 4, text: "A CISO finds that development teams are bypassing the change management process for 'emergency' fixes. The BEST long-term solution is:", options: ["Eliminate the change management process for development", "Accept the bypasses as an entirely unavoidable fact of life", "Force every fix through the standard 30-day change cycle", "A formal expedited path with post-change review"], answer: 3, explain: "Effective change management includes an expedited path for genuine emergencies with lightweight but real oversight — post-change documentation and CCB review maintains accountability while accommodating operational urgency."),
    Question(id: 783, domain: 4, text: "Implementing data masking in non-production environments ensures:", options: ["Production performance is not affected", "Developers cannot test with realistic data", "All non-production systems have the same security posture as production", "Sensitive production data is not exposed in development, testing, or staging environments"], answer: 3, explain: "Data masking replaces sensitive production data (PII, financial data) with realistic but fictitious values in lower environments — preventing breaches in less-secured dev/test environments from exposing real sensitive data. Reducing privacy and security risk from test environment compromises."),

    // MARK: – Batch 5: Domain 5 expansion (+78 assessment)
    Question(id: 800, domain: 5, text: "An assessment plan is derived from the SSP because:", options: ["The SSP defines the implemented controls", "The assessor chooses any controls to test", "The AO creates the assessment plan independently", "The assessment plan replaces the SSP"], answer: 0, explain: "The assessment plan maps each control in the SSP to specific assessment procedures (examine, interview, test) from SP 800-53A — it is a direct derivative of the SSP's documented control implementations. The assessment plan specifies HOW each control will be examined, interviewed, or tested."),
    Question(id: 801, domain: 5, text: "A risk assessment identifies a threat-vulnerability pair with HIGH likelihood and LOW impact. The risk level is:", options: ["Always rated High, simply because the likelihood is High", "Moderate — high likelihood and low impact combine", "Always rated Low, simply because the impact is Low", "Critical — any High makes it Critical"], answer: 1, explain: "Risk level is determined by combining likelihood and impact. HIGH likelihood × LOW impact = Moderate risk under standard 3×3 or 5×5 risk matrices — neither factor alone determines the final risk level."),
    Question(id: 802, domain: 5, text: "CVSS (Common Vulnerability Scoring System) is used to:", options: ["Determine the FIPS 199 impact level", "Replace penetration testing", "Score the severity of software vulnerabilities", "Authorize systems automatically based on vulnerability count"], answer: 2, explain: "CVSS provides a standardized severity score (0-10) for software vulnerabilities based on exploitability, scope, and impact metrics — enabling organizations to prioritize remediation by severity. Providing a standardized, numerical representation of vulnerability characteristics and risk."),
    Question(id: 803, domain: 5, text: "When an assessor classifies a finding as 'other than satisfied,' this means:", options: ["The control is simply not required for this particular system", "The control is satisfied but it could still be improved further", "The assessor did not actually test the control during the assessment", "The control is not fully implemented or not working right"], answer: 3, explain: "SP 800-53A uses 'Satisfied' and 'Other Than Satisfied' as the two finding determination values. 'Other Than Satisfied' indicates any level of non-compliance from partial implementation to complete failure."),
    Question(id: 804, domain: 5, text: "What distinguishes a 'control deficiency' from a 'material weakness'?", options: ["The distinction between these two terms applies only within financial audits", "A material weakness is the distinctly less severe of the two audit findings", "A material weakness is a deficiency severe enough to likely cause failure", "The two terms mean exactly the same thing"], answer: 2, explain: "In audit/assessment frameworks, a material weakness is a significant deficiency severe enough to create a high likelihood of material failure. The concept applies in both financial (SOX) and IT security audit contexts."),
    Question(id: 805, domain: 5, text: "An organization uses the OWASP Testing Guide during a web application assessment. This guide provides:", options: ["General risk management guidance", "Detailed test cases for assessing web application security controls", "Network infrastructure assessment procedures", "Physical security assessment checklists"], answer: 1, explain: "The OWASP Testing Guide provides a comprehensive methodology and test cases for web application security assessments — aligning with SP 800-53A 'test' assessment methods for application-layer controls. Covering authentication, authorization, injection, and other OWASP Top 10 risks."),
    Question(id: 806, domain: 5, text: "A 'red team' exercise differs from a standard penetration test in that:", options: ["Penetration tests are inherently broader and more comprehensive than red-team engagements", "Red-team exercises rely more heavily on automated scanning tools", "Red-team exercises are limited strictly to external network security testing", "Red teams emulate full adversary campaigns across many vectors to test response"], answer: 3, explain: "Red team exercises simulate realistic adversary behavior — using multiple attack vectors, maintaining persistence, and testing whether the organization detects and responds effectively. Penetration tests typically have a narrower technical scope."),
    Question(id: 808, domain: 5, text: "Social engineering testing (e.g., phishing simulations) during an assessment evaluates the effectiveness of:", options: ["Awareness and training controls and the human factor", "The organization's network firewalls and their rule sets", "The encryption implementations in use", "Only the physical access controls"], answer: 0, explain: "Social engineering tests assess whether AT controls (training, awareness) effectively change user behavior. They identify gaps in the human layer of defense — a critical assessment area since humans are frequently the attack vector."),
    Question(id: 809, domain: 5, text: "Threat hunting is BEST described as:", options: ["Automated scanning of the systems for known vulnerabilities", "Proactively hunting threats that evaded detection", "Simply responding to the alerts generated by the SIEM tool", "Conducting the organization's regular annual penetration tests"], answer: 1, explain: "Threat hunting proactively searches for adversary TTPs (Tactics, Techniques, and Procedures) that may have bypassed automated detections — using threat intelligence, behavioral analytics, and investigative techniques."),
    Question(id: 810, domain: 5, text: "The MITRE ATT&CK framework is used in assessments to:", options: ["Map each of the information types to their impact levels", "Replace the SP 800-53A assessment procedures entirely", "Align assessments with real-world adversary TTPs", "Select the control baselines"], answer: 2, explain: "MITRE ATT&CK provides a knowledge base of adversary TTPs — used to structure red team exercises, threat hunting, and security control assessments against real-world attack patterns."),
    Question(id: 811, domain: 5, text: "When assessing the AC-2 (Account Management) control, which evidence would an assessor MOST likely examine?", options: ["Network firewall rule logs showing permitted and denied connection attempts over time", "Account listings, approvals, access reviews, and terminated-user removals", "Physical access badge logs for the data-center facility that houses the servers", "Backup completion logs confirming successful nightly snapshots of the system"], answer: 1, explain: "AC-2 assessment examines: documented account management procedures, evidence of authorization before provisioning, access reviews, and timely removal of terminated accounts — using both examination and interview methods."),
    Question(id: 812, domain: 5, text: "An assessor discovers that audit logs are being automatically deleted after 7 days due to storage constraints. This finding relates to:", options: ["AU-11 (Audit Record Retention)", "SC-8 (Transmission Confidentiality)", "CP-9 (System Backup)", "IA-5 (Authenticator Management)"], answer: 0, explain: "AU-11 requires audit records to be retained for a defined period — OMB and NIST guidance typically require at least 3 years for federal systems. Premature deletion destroys evidence needed for investigations. Logs must be retained for an organization-defined period sufficient to support after-the-fact investigations."),
    Question(id: 813, domain: 5, text: "During an assessment, a tester discovers a SQL injection vulnerability in a web application. This finding should be:", options: ["Documented in the SAR with severity, evidence, and remediation", "Reported only to the application's lead developer and no one else", "Fixed immediately before being documented", "Mentioned only verbally to the system owner"], answer: 0, explain: "All assessment findings, including SQL injection, must be formally documented in the SAR with severity (using CVSS or agency scale), evidence, scope, and remediation recommendations — even if remediated during the assessment."),
    Question(id: 814, domain: 5, text: "The Common Vulnerability Enumeration (CVE) system provides:", options: ["A set of security baselines made for federal systems", "A scoring system for vulnerability severity levels", "An overall access control framework for systems", "A standard dictionary of public vulnerabilities"], answer: 3, explain: "CVE provides unique identifiers for publicly known vulnerabilities — enabling organizations, vendors, and tools to consistently reference the same vulnerability regardless of source or tool used."),
    Question(id: 815, domain: 5, text: "A penetration test report identifies that an attacker could gain administrative access to a system through an unpatched vulnerability. The risk response should be:", options: ["Immediately patch, record it in the POA&M, and notify the AO if risk changed", "Accept the risk outright because the system already holds a currently valid ATO", "Wait until the next scheduled assessment cycle to address it", "Ask the tester to keep the finding confidential"], answer: 0, explain: "Critical penetration test findings require immediate response — patch deployment (SI-2), POA&M update, and AO notification if the finding represents a material change to the authorized risk posture."),
    Question(id: 816, domain: 5, text: "Which SP 800-53A assessment object type involves reviewing system documentation and artifacts?", options: ["Examine", "Interview", "Test", "Authorize"], answer: 0, explain: "The 'examine' assessment method involves reviewing documentation, policies, procedures, plans, configurations, and other artifacts — distinct from interviewing people or technically testing controls."),
    Question(id: 817, domain: 5, text: "An assessor determines that a control is 'not applicable.' The assessor should:", options: ["Skip the control entirely without recording any documentation for it", "Document why it is N/A in the SAR, citing the SSP justification", "Record the control as fully satisfied even though it was not tested", "Escalate the matter to the authorizing official for a final decision"], answer: 1, explain: "N/A determinations must be documented with justification — both in the SSP (as a tailoring decision) and confirmed by the assessor in the SAR. Undocumented N/As are not acceptable."),
    Question(id: 818, domain: 5, text: "The primary purpose of assessor independence is NOT to:", options: ["Produce objective findings", "Ensure findings are credible to the AO", "Guarantee the findings will be unfavorable to the system owner", "Avoid conflicts of interest"], answer: 2, explain: "Independence ensures objectivity and credibility — not to produce negative findings. An independent assessor's results are trusted because they have no incentive to overlook problems; findings can be positive or negative."),
    Question(id: 819, domain: 5, text: "A risk assessment identifies a vulnerability with no known exploit and no threat actor currently targeting it. The residual risk after documenting it is:", options: ["High, because all known vulnerabilities are treated as high risk", "Zero — no exploit means there is no risk", "Automatically accepted by default", "Low but not zero — it could be exploited if a threat emerges"], answer: 3, explain: "Risk exists even without a known exploit — threat actors continuously develop new capabilities and previously unexploited vulnerabilities can become exploited. The risk is low but must be monitored and documented."),
    Question(id: 820, domain: 5, text: "When preparing an assessment report, findings should be presented:", options: ["Only as a simple pass or fail with no further detail given", "Only to the CISO directly, and never to the actual system owner", "Detailed enough to explain the weakness, risk, and the fix", "Without any evidence, to protect sensitive data"], answer: 2, explain: "The SAR must provide actionable findings — clearly explaining what was found, where, what the risk is, and how to fix it. Vague findings are not actionable and do not help the organization improve."),
    Question(id: 821, domain: 5, text: "An assessor identifies a configuration weakness during the assessment that the system team fixes before the final report. Should this be documented?", options: ["Yes — record it in the SAR with a note that it was remediated", "No — once the weakness is fixed it no longer counts as an assessment finding", "Only if the remediation the team applied turns out to have been inadequate", "Only if the authorizing official specifically asks for it to be recorded"], answer: 0, explain: "Assessment integrity requires documenting all findings, including those remediated during the assessment. This provides the AO with a complete picture of the system's security history and the team's responsiveness."),
    Question(id: 822, domain: 5, text: "During a risk assessment, the assessor needs to evaluate the likelihood of a specific threat event. According to SP 800-30, likelihood considers:", options: ["Both the chance a threat initiates and the chance it then succeeds", "Only the historical incident data collected from past security events", "Only the technical capability and resources of the threat actor itself", "Only the overall severity of the underlying exploited vulnerability"], answer: 0, explain: "SP 800-30 defines overall likelihood as a combination of threat event initiation likelihood (based on threat source characteristics) and threat event success likelihood (given the vulnerability and existing controls)."),
    Question(id: 823, domain: 5, text: "A privacy impact assessment conducted during the assessment phase should evaluate:", options: ["Only the complete historical record of data breaches affecting the system", "Only the General Data Protection Regulation compliance status for any EU data", "Whether privacy controls are implemented correctly and manage risk well", "Only the number of PII records the system processes"], answer: 2, explain: "Privacy control assessments evaluate the same criteria as security control assessments: are privacy controls implemented correctly, operating as intended, and producing the desired outcome (managing privacy risks effectively)?"),
    Question(id: 824, domain: 5, text: "Which of the following is NOT a valid assessment approach for a HIGH-impact system?", options: ["Accepting the vendor's word with no independent verification", "Full penetration testing", "Comprehensive examination of all controls with extensive testing", "Detailed interviews with key personnel"], answer: 0, explain: "For HIGH-impact systems, independent verification through testing, examination, and interviews is required. Accepting vendor claims without independent verification is not sufficient assurance — especially for critical systems."),
    Question(id: 825, domain: 5, text: "After an assessment, the ISSO reviews the SAR and disagrees with several findings. The correct process is:", options: ["The ISSO can remove findings they disagree with", "The ISSO provides written comments disputing specific findings", "The findings are automatically accepted if no response within 30 days", "The AO makes the final determination on all disputed findings before the SAR is finalized"], answer: 1, explain: "The dispute process gives the system owner opportunity to provide additional evidence or context. The assessor considers the response and either revises or maintains findings with documented rationale — preserving assessor independence. The assessor reviews and either adjusts or maintains findings in the final SAR."),
    Question(id: 826, domain: 5, text: "Network scanning during an assessment should be coordinated with the system owner because:", options: ["It is only required for classified systems", "It gives the system owner time to fix vulnerabilities before scanning", "Active scanning can cause system disruptions or false alarms", "Only internal staff can conduct network scans"], answer: 2, explain: "Active scanning can trigger IDS alerts, consume bandwidth, or crash unstable systems. Coordinating scan timing, scope, and intensity with system owners prevents unintended outages while maintaining assessment integrity. Coordination ensures scanning is authorized and operational impacts are minimized."),
    Question(id: 827, domain: 5, text: "An assessor finds that a system uses MD5 for password hashing. This is classified as:", options: ["An acceptable control — MD5 is still widely used", "A low finding — hash collisions only affect signatures, not passwords", "Not a finding if passwords are salted", "A high-severity finding"], answer: 3, explain: "MD5 is cryptographically broken — MD5 hashes can be reversed using rainbow tables or GPU-accelerated attacks even with salts. NIST and FIPS guidance require approved cryptographic algorithms; MD5 is not approved for new uses."),
    Question(id: 828, domain: 5, text: "A risk assessment must be updated when:", options: ["Only when an actual security incident occurs against the production system", "Only when the authorization to operate finally expires", "Only once per year, regardless of any changes", "When significant system, environment, or threat changes alter the risk"], answer: 3, explain: "Risk assessments (RA-3) are living documents — they must be updated when there are significant changes to the system, new threats emerge, or the environment changes in ways that could affect the original risk determinations."),
    Question(id: 829, domain: 5, text: "Which type of assessment specifically evaluates whether controls comply with applicable laws, regulations, and policies — not just whether they are technically effective?", options: ["Penetration test", "Compliance audit", "Vulnerability assessment", "Red team exercise"], answer: 1, explain: "A compliance audit verifies that the organization meets the specific requirements of laws, regulations, and policies — it can identify controls that technically work but don't meet specific regulatory requirements."),
    Question(id: 830, domain: 5, text: "An assessor tests AC-17 (Remote Access) by attempting to connect using an unauthorized VPN client. This is an example of which assessment method?", options: ["Examine", "Interview", "Test", "Authorize"], answer: 2, explain: "Attempting to connect using unauthorized methods directly tests whether the control prevents unauthorized remote access — a 'test' method that exercises the control to verify it functions as intended."),
    Question(id: 831, domain: 5, text: "The scope of a FedRAMP assessment is defined by:", options: ["The 3PAO on its own, independent of the provider or program office", "The sponsoring federal agency alone, acting without any input from the cloud provider", "OMB directly, issuing a tailored control set to each individual cloud service provider", "The Security Assessment Plan (SAP), which specifies boundary, controls, and testing"], answer: 3, explain: "The FedRAMP Security Assessment Plan (SAP) — developed collaboratively by the CSP and 3PAO, reviewed by FedRAMP — defines the assessment boundary, test cases, methodologies, and schedule."),
    Question(id: 832, domain: 5, text: "An organization discovers a vulnerability during an internal security review BEFORE the formal assessment. They fix it and don't report it to the assessor. This approach is:", options: ["Acceptable, because any vulnerability that has been fixed need not be reported at all", "Problematic — the assessor should know, to check the fix and find similar issues", "Actually mandated by the current NIST assessment guidance for all internal reviews", "Acceptable only for low-severity findings"], answer: 1, explain: "Hiding fixed vulnerabilities from assessors prevents them from verifying fix completeness, identifying related issues, and providing a full picture to the AO. Transparency about pre-assessment fixes maintains assessment integrity."),
    Question(id: 833, domain: 5, text: "A risk treatment plan differs from a POA&M in that:", options: ["The treatment plan sets the overall risk approach; the POA&M tracks specific findings", "The POA&M defines the overall strategy while the treatment plan tracks individual findings", "The treatment plan applies only to risks the organization has formally accepted", "The POA&M is the more comprehensive of the two enterprise-wide documents"], answer: 0, explain: "The risk treatment plan (from SP 800-39 risk response) is strategic — defining how the organization addresses risk categories. The POA&M is tactical — tracking specific assessment findings, remediation actions, resources, and timelines."),
    Question(id: 834, domain: 5, text: "During an assessment of IR-4 (Incident Handling), which activity provides the strongest evidence?", options: ["Reviewing the plan, testing via exercise, and reviewing past incidents", "Reviewing only the organization's documented incident response plan in detail", "Interviewing only the incident response team lead about their procedures", "Examining only the incident tickets that were opened during the past year"], answer: 0, explain: "Testing IR capability requires multiple assessment methods: examining the plan (examine), interviewing IR personnel (interview), and testing through exercises or reviewing evidence from actual incidents (test) — all three provide the strongest assurance."),
    Question(id: 835, domain: 5, text: "An organization's vulnerability scanner reports 2,000 vulnerabilities across its systems. The BEST approach to managing this is:", options: ["Prioritize by CVSS, exploitability, and criticality", "Attempt to remediate all 2,000 of them right away immediately", "Accept every one of the vulnerabilities as residual risk", "Outsource all remediation to the vendor"], answer: 0, explain: "Risk-based prioritization focuses limited resources on the highest actual risk — considering exploitability in the specific environment, system criticality, attack surface exposure, and compensating controls already in place."),
    Question(id: 836, domain: 5, text: "A system owner wants to use the results of a SOC 2 Type II report from a cloud provider to satisfy the security assessment requirement for inherited controls. This approach:", options: ["May be acceptable through reciprocity", "Is never acceptable for federal systems", "Automatically satisfies all federal requirements", "Requires congressional approval"], answer: 0, explain: "Reciprocity allows organizations to leverage existing assessments (including SOC 2) to avoid duplicative effort — but the AO must review the report's scope, recency, and coverage to ensure it addresses the specific controls needed. The AO reviews the SOC 2 report to determine if it provides sufficient assurance for the specific controls inherited."),
    Question(id: 837, domain: 5, text: "During assessment, an assessor finds an unauthorized device on the network (not in the system inventory). This indicates a potential failure of:", options: ["SC-28 (Protection of Information at Rest)", "CM-8 (System Component Inventory) and network access controls", "AU-9 (Protection of Audit Information)", "CP-9 (System Backup)"], answer: 1, explain: "CM-8 requires maintaining an accurate, up-to-date inventory of system components. An unauthorized device indicates the inventory is incomplete and network access controls (NAC) failed to prevent unauthorized devices from connecting. Unauthorized devices represent a control gap in asset management and network access control."),
    Question(id: 838, domain: 5, text: "Assessing supply chain risks for a system includes evaluating:", options: ["Only the single primary software vendor used by the system", "The trustworthiness of hardware, software, and services", "Only the domestic suppliers that are based in the United States", "Only the open-source software components found in the system"], answer: 1, explain: "Supply chain risk assessment (RA-3(1), SR-3) evaluates the security practices of all significant suppliers, the provenance and integrity of components, and the potential for adversarial manipulation of the supply chain."),
    Question(id: 839, domain: 5, text: "A risk assessor quantifies the impact of a data breach as $5M per incident with an annualized rate of occurrence of 0.1 (once every 10 years). The Annual Loss Expectancy (ALE) is:", options: ["$50,000", "$5,000,000", "$50,000,000", "$500,000"], answer: 3, explain: "ALE = SLE × ARO = $5,000,000 × 0.1 = $500,000. This quantitative risk value helps determine how much to invest in controls — controls costing less than $500,000/year provide positive ROI if they prevent the breach."),
    Question(id: 840, domain: 5, text: "The final SAR is submitted to the AO with the authorization package. The AO uses the SAR to:", options: ["Determine the system's FIPS 199 security categorization and its overall impact levels", "Understand the independent findings, current risk posture, and residual risks", "Author the System Security Plan documenting every one of the implemented controls", "Assign day-to-day security responsibilities to the ISSO"], answer: 1, explain: "The SAR is a critical input to the authorization decision — it provides the AO with independent, objective findings about control effectiveness and identifies the risks that must be formally accepted for the system to operate."),
    Question(id: 841, domain: 5, text: "When an assessment reveals that a control described in the SSP as 'implemented' is actually not functioning, this discrepancy indicates:", options: ["Only a documentation error with no security impact", "A significant finding", "An acceptable gap for legacy systems", "A finding only if the control is in the HIGH baseline"], answer: 1, explain: "When implemented controls don't actually function, it directly impacts the risk posture — the AO authorized the system based on those controls being in place. Both the control gap (SAR/POA&M) and the SSP inaccuracy must be addressed. Controls described as implemented must be operational. The discrepancy affects both the security posture and the SSP's accuracy."),
    Question(id: 842, domain: 5, text: "An assessor notices that audit logs are being generated but no one is reviewing them. Which two SP 800-53 controls are potentially deficient?", options: ["SC-28 and MP-5", "AC-2 and IA-5", "AU-2 (event logging", "CM-6 and SI-2"], answer: 2, explain: "AU-2 (generating logs) may be satisfied, but AU-6 (reviewing and analyzing logs) is deficient. Generating logs without reviewing them provides no security value — the review process is where threats are actually detected. Logs ARE being generated) but AU-6 (Audit Record Review, Analysis, and Reporting) is deficient — nobody is reviewing."),
    Question(id: 843, domain: 5, text: "Privacy control assessments should evaluate whether the organization's data processing activities are:", options: ["Reviewed exclusively by the agency's Privacy Officer rather than the assessment team", "Compliant with applicable laws and regulations and nothing further", "Technically implemented in the production system", "Consistent with privacy notices, limited to stated purposes, and rights-protecting"], answer: 3, explain: "Privacy control assessments go beyond legal compliance — verifying that data processing matches what was stated in privacy notices, is limited to specified purposes (purpose limitation), and that individual rights can be exercised as promised."),
    Question(id: 844, domain: 5, text: "A 'false positive' from a vulnerability scanner means:", options: ["The scanner reported a vulnerability that does not actually exist", "A real vulnerability was discovered", "The scanner missed a real vulnerability", "The scan failed to complete"], answer: 0, explain: "False positives are reported vulnerabilities that are not actually present in the specific environment. Assessors must manually verify scanner findings to avoid documenting false positives as real vulnerabilities in the SAR. Requiring manual verification before documenting as a finding."),
    Question(id: 845, domain: 5, text: "A 'false negative' from a security tool is more dangerous than a false positive because:", options: ["False negatives generate unnecessary work", "False negatives miss real vulnerabilities", "False negatives are easier to detect", "False negatives only affect low-impact systems"], answer: 1, explain: "False negatives are undetected real vulnerabilities — far more dangerous than false positives. They leave genuine risks undiscovered and unmitigated, potentially allowing attackers to exploit vulnerabilities the organization doesn't know exist. Creating a false sense of security and leaving actual risks undetected and unmitigated."),
    Question(id: 846, domain: 5, text: "Which NIST publication provides specific techniques for information security testing including network scanning, vulnerability assessment, and penetration testing?", options: ["SP 800-53A, which provides the security control assessment procedures", "SP 800-30 (risk assessment guidance)", "SP 800-115, the Technical Guide to Information Security Testing", "SP 800-137 (continuous monitoring)"], answer: 2, explain: "SP 800-115 provides detailed technical guidance on information security testing methods: network/port scanning, wireless scanning, application testing, target identification, and penetration testing methodology."),
    Question(id: 847, domain: 5, text: "During an assessment of contingency planning controls, an assessor should MOST critically verify:", options: ["The plan is printed out and stored in a labeled binder in the office", "The plan was tested, backups restore, and RTOs were validated", "The plan was reviewed by legal counsel", "The plan carries an executive signature page"], answer: 1, explain: "An untested contingency plan provides false assurance. CP-4 (Testing) and CP-9 (Backup) require verifying that plans actually work and that RTOs and RPOs are achievable in practice."),
    Question(id: 848, domain: 5, text: "An assessor reviews an organization's POA&M and finds that 15 'high' findings from 2 years ago have no milestones or remediation activity. This indicates:", options: ["A significant risk management failure", "The findings were silently accepted as residual risk", "The AO extended all deadlines", "The findings were automatically downgraded to medium over time"], answer: 0, explain: "Stale high findings in a POA&M — especially with no activity — may mean the AO authorized based on expected remediation that never occurred, invalidating the risk acceptance basis and requiring AO notification. High findings require active remediation. Stale POA&M items may indicate the AO's risk acceptance was based on planned (not actual) remediation."),
    Question(id: 849, domain: 5, text: "The concept of 'assessment reciprocity' allows organizations to:", options: ["Share the total cost of the assessment between the participating agencies", "Reuse existing assessment results instead of duplicating the effort", "Reuse an assessment team across engagements without renewing credentials", "Skip the security assessment entirely"], answer: 1, explain: "Assessment reciprocity leverages existing authoritative assessments to avoid duplicative work — a key efficiency mechanism that enables systems with FedRAMP authorizations to be reused across multiple agencies."),
    Question(id: 850, domain: 5, text: "During a privacy control assessment, an assessor reviews whether the organization's data collection is consistent with its public privacy notice. This implements which privacy principle?", options: ["Data minimization", "Purpose limitation", "Notice and transparency", "Storage limitation"], answer: 2, explain: "Notice and transparency requires that individuals be informed about data collection and processing practices. Assessors verify that actual practices match the privacy notice — a fundamental fair information practice principle. Individuals must be informed about data collection practices, and actual practices must match what is stated."),
    Question(id: 851, domain: 5, text: "A vulnerability assessment differs from a risk assessment in that:", options: ["The two are essentially identical activities that are simply performed at different times", "A risk assessment is the distinctly narrower and less comprehensive of the two activities", "Vulnerability assessments may only ever be performed by external third-party assessors", "Vulnerability assessment finds weaknesses; risk assessment adds threats and impact"], answer: 3, explain: "Vulnerability assessments identify specific technical weaknesses. Risk assessments contextualize those weaknesses by analyzing who might exploit them (threats), how likely that is (likelihood), and what the impact would be — producing a risk level."),
    Question(id: 852, domain: 5, text: "An assessor needs to evaluate whether data encrypted at rest meets federal cryptographic requirements. The evidence examined would include:", options: ["Captured network packet traffic that is exchanged between the application's hosts", "Only the physical security controls of the server room", "FIPS 140-2/3 validation certificates plus config showing approved algorithms", "The product datasheet provided by the vendor"], answer: 2, explain: "Evaluating SC-28 requires examining FIPS validation certificates for the crypto module and configuration evidence that approved algorithms are used in approved modes."),
    Question(id: 853, domain: 5, text: "A 'tabletop exercise' as an assessment method tests:", options: ["The technical effectiveness of the deployed security controls themselves", "The physical recovery of systems at the alternate processing facility", "Decision-making and procedures by walking through a scenario on paper", "Automated network scanning capability"], answer: 2, explain: "Tabletop exercises walk key personnel through a scenario (e.g., ransomware attack) to test decision-making, communication, roles/responsibilities, and procedure quality — without the cost and disruption of a full operational test. Ideal for IR and contingency plan assessment."),
    Question(id: 854, domain: 5, text: "An assessor discovers that system administrators are sharing a single 'root' account rather than using individual privileged accounts. This violates:", options: ["AC-5 (Separation of Duties) only", "Only AU-2 (Audit Logging)", "AC-2 (Account Management", "No controls — shared admin accounts are common practice"], answer: 2, explain: "Shared privileged accounts violate multiple controls: AC-2 (accounts must be uniquely assigned), AC-6 (least privilege), and AU controls (you cannot attribute actions to specific individuals with shared accounts, undermining accountability). Shared accounts prevent individual accountability), AC-6 (Least Privilege), and AU-2/AU-3 (making audit logs unattributable to individuals)."),
    Question(id: 855, domain: 5, text: "During a FedRAMP assessment, if the 3PAO discovers a new critical vulnerability not covered in the original assessment plan, the assessor should:", options: ["Ignore it — only test what's in the plan", "Report it only after the formal assessment concludes", "Leave it for the agency to discover during their review", "Document the finding and expand the assessment scope to cover it"], answer: 3, explain: "Assessment integrity requires investigating critical findings even when outside original scope. Ignoring a critical vulnerability because it wasn't planned would produce an incomplete and misleading SAR. Critical findings discovered during testing must be investigated regardless of original scope."),
    Question(id: 856, domain: 5, text: "An IT audit uses statistical sampling to test a population of 10,000 access rights assignments. Statistical sampling is appropriate when:", options: ["The population is too large to test fully and a representative sample is sufficient", "The auditor lacks the time to review every record in the population before the deadline", "Exactly 100 records in the population require detailed review", "The system owner has formally requested a sampling approach"], answer: 0, explain: "Statistical sampling enables auditors to draw conclusions about a large population by testing a representative subset — if the sample shows consistent compliance, the auditor can infer the population is likely compliant within a defined confidence level."),
    Question(id: 857, domain: 5, text: "During an assessment, an assessor observes that physical security controls are inadequate — servers are accessible in an unlocked room. This should be documented as:", options: ["Not a finding since physical security is operational, not technical", "A finding against PE family controls", "Only a recommendation for improvement", "Only a finding if classified data is present"], answer: 1, explain: "Physical access control (PE-3) is a required baseline control. Servers in unlocked, accessible locations represent a direct control failure — attackers with physical access can bypass virtually all other controls. PE-3 (Physical Access Control) at minimum, potentially with cascading implications for system integrity."),
    Question(id: 858, domain: 5, text: "The NIST Risk Management Framework's assessment step produces which primary output?", options: ["The authorization package assembled for the authorizing official's decision", "The Authorization to Operate (ATO)", "The System Security Plan (SSP)", "The Security Assessment Report (SAR) and the updated POA&M"], answer: 3, explain: "The Assess step (Step 4) produces the SAR — documenting assessment findings, evidence, and recommendations. The SAR and updated POA&M then feed into the Authorize step to support the AO's risk acceptance decision."),

    // MARK: – Batch 6: Domain 6 expansion (+52 authorization)
    Question(id: 871, domain: 6, text: "Which of the following best describes 'risk tolerance' in the context of authorization decisions?", options: ["The maximum number of open POA&M items that are allowed to exist at one time", "The number of years the ATO remains valid", "The minimum number of controls required", "The residual risk level the AO will formally accept for the mission"], answer: 3, explain: "Risk tolerance defines the AO's threshold — residual risks below this threshold can be accepted and the ATO granted; risks above it require additional mitigation or result in denial. It is specific to the AO, system, and organizational context."),
    Question(id: 873, domain: 6, text: "An AO signs an ATO for a system with three open HIGH findings in the POA&M with 90-day remediation timelines. This represents:", options: ["An invalid authorization — HIGH findings preclude ATO", "Negligence by the AO", "A risk-based authorization decision", "An ATO with conditions that automatically converts to DATO in 90 days"], answer: 2, explain: "Formal risk acceptance of open findings is a valid AO decision — it means the AO has reviewed the findings, assessed the risk, and accepted it as tolerable given mission requirements, contingent on POA&M compliance. The AO formally accepts the risk of the open findings given mission need, contingent on timely remediation."),
    Question(id: 875, domain: 6, text: "A system authorization is not a one-time event because:", options: ["Risk postures change", "ATOs never expire", "FISMA requires monthly reauthorizations", "Authorization decisions are made by committee and require ongoing consensus"], answer: 0, explain: "Authorization is based on a point-in-time risk assessment. As systems change and threats evolve, the original risk acceptance may no longer be valid — requiring either continuous monitoring or periodic reauthorization. New vulnerabilities, system changes, and evolving threats may invalidate the original risk acceptance."),
    Question(id: 876, domain: 6, text: "Under SP 800-37 Rev. 2, what is the significance of 'shared responsibility' in authorization?", options: ["Multiple AOs all share one single authorization decision", "Agencies share the cost of the assessment between them", "Shared authorization removes the need for system ATOs", "Several parties share implementation responsibility"], answer: 3, explain: "Modern systems rely on shared infrastructure, common controls, and cloud platforms. SP 800-37 Rev. 2 acknowledges that multiple parties share implementation responsibility — each authorizes their portion, and the system AO accepts risk from all components."),
    Question(id: 878, domain: 6, text: "Which of the following is the MOST important consideration for an AO when evaluating authorization for a mission-critical system with significant residual risk?", options: ["Balancing mission need against the risk of operating", "The total cost of implementing the additional controls", "Whether the system has ever been formally assessed before", "The number of findings listed in the SAR"], answer: 0, explain: "AO authorization decisions are inherently about risk tradeoffs — the risk of NOT having the mission capability versus the risk of operating the system with known vulnerabilities. Mission criticality is a key factor in this balance."),
    Question(id: 879, domain: 6, text: "An AO discovers after granting an ATO that the assessor had a conflict of interest. The AO should:", options: ["Investigate, consider a reassessment, and possibly modify the ATO", "Accept the ATO as granted because all the paperwork is already complete", "Simply note the conflict of interest in the next scheduled review cycle", "Require the same assessor to redo the assessment from the beginning"], answer: 0, explain: "Assessor independence is fundamental to authorization credibility. A discovered conflict of interest calls all findings into question — the AO must decide whether the authorization can stand or requires independent reassessment."),
    Question(id: 881, domain: 6, text: "Which of the following would be an appropriate condition to attach to an ATO?", options: ["All future employees must complete the security training", "All of the system's source code must be reviewed by the NSA", "The system must use only domestic hardware", "Fix high finding X within 60 days, evidence to the AO"], answer: 3, explain: "ATO conditions are specific, measurable requirements the system owner must meet post-authorization — such as remediating a specific high finding within a defined timeframe with evidence reported back to the AO."),
    Question(id: 883, domain: 6, text: "Which federal requirement establishes that the head of an agency is ultimately responsible for accepting information security risk?", options: ["NIST SP 800-37, which describes the Risk Management Framework steps", "OMB Circular A-11, governing the federal budget preparation process", "FIPS 199, which standardizes security categorization of systems", "FISMA — the agency head is ultimately accountable"], answer: 3, explain: "FISMA establishes the agency head (Secretary, Administrator, Director) as ultimately responsible for the agency's information security program. The AO accepts risk for specific systems within that overall framework."),
    Question(id: 884, domain: 6, text: "When a system AO changes (new person assumes the AO role), the BEST practice is to:", options: ["The ATO remains fully valid — AO identity doesn't matter", "Brief the new AO on the current authorization, risk posture, and open POA&M items", "Immediately issue a new ATO", "Suspend operations until a full reassessment is complete"], answer: 1, explain: "ATO transitions require the incoming AO to be briefed on the system's risk posture. The new AO must consciously accept inherited risk — they should review the authorization package and make an informed decision rather than defaulting to the previous AO's acceptance. The new AO may choose to reaffirm or modify the existing authorization."),
    Question(id: 885, domain: 6, text: "The Privacy Officer's role in the authorization process is to:", options: ["Make the final authorization decision for the system", "Conduct the entire privacy control assessment completely independently", "Review the privacy plan and assessment results before authorization", "Sign the ATO on behalf of the Privacy Office"], answer: 2, explain: "The Senior Agency Official for Privacy (SAOP) or Privacy Officer reviews privacy-related authorization materials and concurs (or raises concerns) before the AO makes the authorization decision — a required reviewer for systems processing PII."),
    Question(id: 887, domain: 6, text: "A DATO (Denial of Authorization to Operate) means the AO has determined:", options: ["The residual risk is unacceptably high", "The system needs more documentation", "The system is authorized with minor conditions", "The assessment is incomplete"], answer: 0, explain: "A DATO is a formal denial — the AO has determined that operating the system would expose the organization to unacceptable risk. The system cannot be used until risks are remediated and the AO reconsiders. The system must NOT operate until risks are addressed to a level the AO can accept."),
    Question(id: 889, domain: 6, text: "When an AO authorizes use of a FedRAMP-authorized SaaS application by issuing an agency ATO, the agency AO is accepting responsibility for:", options: ["All security controls including those managed by the CSP", "Only the network connection to the SaaS", "The agency-specific configuration, data, and users within the SaaS", "Nothing additional — FedRAMP covers everything"], answer: 2, explain: "When agencies leverage FedRAMP, the CSP's authorization covers the cloud infrastructure. The agency AO accepts responsibility for the agency's use layer — configurations, data, user access, and any agency-specific risks not covered by the CSP's package. While the CSP remains responsible for the underlying infrastructure per the FedRAMP authorization."),
    Question(id: 890, domain: 6, text: "A system that connects to a national security system (NSS) requires which additional authorization consideration?", options: ["Obtain a wholly separate ATO issued directly by the Secretary of Defense for it", "Secure formal Congressional approval before the system interconnection is allowed", "Only a standard FISMA authorization to operate is required", "Comply with CNSS policy (CNSSI 1253) and NSS-specific authorization processes"], answer: 3, explain: "Connections to NSS trigger CNSS requirements — systems must comply with CNSSI 1253 security categorization and controls, and the connection itself must be authorized under NSS-specific processes."),
    Question(id: 891, domain: 6, text: "An organization is authorizing a system that will support a critical, time-sensitive mission (e.g., emergency response). The AO's authorization decision should:", options: ["Consider mission criticality", "Apply the same standard risk tolerance used for all systems", "Automatically grant a full ATO for all critical systems", "Require zero residual risk before authorizing critical systems"], answer: 0, explain: "Mission criticality is a key factor in risk acceptance — the AO must weigh the risk of operating (residual security risk) against the risk of not operating (mission failure). Critical systems may warrant accepting higher residual risk with compensating measures. Higher operational need may justify accepting greater residual risk than for non-critical systems, with compensating controls and enhanced monitoring."),
    Question(id: 892, domain: 6, text: "The concept of 'security authorization' in the RMF is fundamentally about:", options: ["A senior official formally accepting the risk of operating the system", "Verifying that each technical security control functions as configured", "Obtaining a vendor's certification that the delivered system is secure", "Completing the required compliance paperwork"], answer: 0, explain: "Authorization is a management decision — a senior official consciously accepts organizational risk. It is not about completing paperwork but about formal, accountable risk acceptance aligned with mission requirements."),
    Question(id: 893, domain: 6, text: "Which of the following would cause an AO to consider rescinding an existing ATO?", options: ["A routine rotation of the ISSO assigned to the system to a new staff member", "An actively exploited critical zero-day directly affecting the system", "A single minor configuration change to the system", "A few minor POA&M milestone delays"], answer: 1, explain: "An ATO is based on the assessed risk at a point in time. Active exploitation of a critical vulnerability in the authorized system materially changes that risk — potentially invalidating the original risk acceptance."),
    Question(id: 894, domain: 6, text: "An organization has 50 systems all using the same enterprise email platform. The MOST efficient authorization approach for the email platform is:", options: ["50 separate authorizations, one per consuming system", "No authorization required for shared platforms", "Authorize it once and never review it again", "Authorize the email platform as a common control"], answer: 3, explain: "Common control authorization is the most efficient approach for shared platforms — the platform is authorized once, maintaining its own authorization package, and all consuming systems inherit the controls without duplicative assessment. All 50 systems inherit the authorization rather than each system independently assessing it."),
    Question(id: 895, domain: 6, text: "Risk acceptance by the AO is different from risk ignorance because:", options: ["If an AO never mentions a particular risk, they have effectively accepted it", "Acceptance is a conscious documented decision; ignorance means unknown risk", "Risk acceptance requires formal Congressional approval, while ignorance does not", "Only risk acceptance is ever legally actionable"], answer: 1, explain: "Valid risk acceptance requires the AO to know about the risks (fully documented SAR/POA&M), understand them, and make a conscious, documented decision. Unknown or undisclosed risks cannot be formally accepted — they are simply unmanaged."),
    Question(id: 896, domain: 6, text: "An interagency system with two AOs requires:", options: ["Only one AO to sign — the other just observes", "Coordination between AOs to ensure both accept the shared risks", "The higher-ranking AO to override the other", "Congressional approval for multi-AO systems"], answer: 1, explain: "Multi-agency systems require coordination between AOs — both must understand and accept their respective portions of risk. The arrangement (which AO is primary, how decisions are coordinated) should be formally documented. Potentially a bilateral authorization or a leading agency arrangement."),
    Question(id: 897, domain: 6, text: "A system owner submits an authorization package without completing all required documentation. The AO should:", options: ["Make the authorization decision with available information", "Grant a provisional ATO while the remaining documentation is prepared", "Return the package and require completion before making a decision", "Accept the package and note the deficiency in the ATO"], answer: 2, explain: "An incomplete authorization package means the AO cannot make a fully informed risk decision. Granting authorization based on incomplete information invalidates the risk acceptance foundation — complete documentation is a prerequisite. Incomplete packages prevent informed risk acceptance."),
    Question(id: 898, domain: 6, text: "The 'principle of least privilege' applies to authorization decisions in that:", options: ["Systems should request as few authorizations as they can", "AOs should grant as few ATOs as they possibly can", "Authorize only the minimum the mission needs", "Authorization packages should be kept as short as possible"], answer: 2, explain: "Authorization scope should match mission need — systems should not be authorized for capabilities or data access beyond what their mission requires. Minimal authorization reduces attack surface and limits the damage from a compromise."),
    Question(id: 899, domain: 6, text: "The primary reason the Authorize step must precede the Monitor step in the RMF is:", options: ["The AO must formally accept risk before the system is allowed to operate", "Monitoring is more expensive than authorization", "Authorization generates the ConMon plan", "Monitoring cannot occur before the system is fully operational"], answer: 0, explain: "The ATO is the formal permission for the system to operate. Continuous monitoring maintains and validates that authorization — but you cannot monitor an operating system that was never formally authorized to operate in the first place. Monitoring maintains the authorization but cannot replace it."),
    Question(id: 900, domain: 6, text: "When reviewing an authorization package for a cloud system, the AO must understand the shared responsibility model because:", options: ["It shows which controls the CSP versus agency owns", "Cloud systems do not require any authorization at all", "FedRAMP handles all of the risk for every cloud system", "Cloud uses different risk scales"], answer: 0, explain: "Cloud shared responsibility means risks are distributed between the CSP and customer. The AO must understand this division — the agency ATO covers the customer portion, while the CSP's FedRAMP authorization covers the infrastructure portion."),
    Question(id: 902, domain: 6, text: "A system is authorized but a new law changes data retention requirements. The impact on the authorization is:", options: ["No impact at all, since laws do not affect individual system authorizations", "The ATO is automatically voided until the new law is fully implemented", "Update the SSP, adjust controls as needed, and inform the AO", "Only the organization's legal team needs to be made aware of the change"], answer: 2, explain: "Regulatory changes that affect a system's required controls or data handling practices may change the authorized risk posture — the system owner must update documentation and notify the AO of the changed compliance landscape."),
    Question(id: 904, domain: 6, text: "An organization implements a 'security portfolio review' process where the CISO presents system risk postures to the AO quarterly. This supports:", options: ["Replacing the authorization process", "Maintaining AO situational awareness across the portfolio", "Only documentation compliance", "Reducing the assessment frequency"], answer: 1, explain: "Regular portfolio reviews provide the AO with aggregate visibility into the organization's risk posture — enabling timely identification of systems where risk has changed and ensuring ongoing authorization decisions are informed. Supporting ongoing authorization decisions and identifying systems requiring reauthorization."),
    Question(id: 907, domain: 6, text: "The authorization boundary approved in the ATO covers:", options: ["The entire internet, since the system is internet-facing", "Only the components named in the package", "Every single system that the AO currently manages", "Any system the ISSO decides needs the coverage"], answer: 1, explain: "The ATO authorizes the specific system as defined by its authorization boundary in the SSP. Components outside that boundary are not covered — they either need their own authorization or must be included in the boundary through a formal amendment."),
    Question(id: 910, domain: 6, text: "After authorization, the system owner discovers a significant change was implemented without going through the change management process. The FIRST action should be:", options: ["Retroactively document the change in the system records and then carry on as normal", "Immediately terminate the employee who implemented the change outside the process", "Run an immediate security impact analysis and notify the AO if risk changed", "Wait until the next scheduled assessment cycle to evaluate and address the change"], answer: 2, explain: "Unauthorized significant changes must be immediately assessed for security impact. If risk has materially changed, the AO must be notified — the authorized risk posture may no longer reflect reality."),

    // MARK: – Batch 7: Domain 7 expansion (+82 ConMon)
    Question(id: 932, domain: 7, text: "An organization's threat intelligence program feeds into ConMon by:", options: ["Supplying current adversary TTPs and indicators that focus monitoring and detection", "Replacing routine vulnerability scanning with curated external threat feed subscriptions", "Serving solely as an input to the organization's once-a-year enterprise risk assessment", "Removing the need to operate a security operations center"], answer: 0, explain: "Threat intelligence enriches ConMon by providing context about who is targeting the organization, how, and with what tools — enabling prioritized monitoring, faster detection, and more informed risk decisions."),
    Question(id: 933, domain: 7, text: "Establishing a 'baseline' for normal network behavior supports ConMon by:", options: ["Replacing access controls", "Enabling anomaly detection", "Eliminating the need for audit logs", "Replacing user authentication"], answer: 1, explain: "Behavioral baselines enable anomaly-based detection — unusual traffic patterns, data volumes, login times, or access patterns that deviate from baseline can indicate compromise even when no specific signature matches. Deviations from baseline behavior may indicate attacks, unauthorized access, or data exfiltration."),
    Question(id: 934, domain: 7, text: "The principle of 'situational awareness' in ISCM means:", options: ["Awareness of the physical surroundings of the organization's data center", "Awareness of how many users are on the system", "A current, accurate understanding of the security and risk posture", "Physical security patrol awareness"], answer: 2, explain: "Situational awareness — knowing your current security state, active threats, and emerging risks — is the core goal of ISCM. It enables timely, informed risk decisions rather than reacting to incidents after the fact."),
    Question(id: 935, domain: 7, text: "An organization uses automated SCAP (Security Content Automation Protocol) tools in its ConMon program. SCAP primarily supports:", options: ["The collection of external cyber threat intelligence feeds", "Physical security monitoring across the data center site", "Social engineering detection", "Automated config checks against security baselines"], answer: 3, explain: "SCAP provides standardized protocols (XCCDF, OVAL, etc.) for automated compliance checking — tools can scan systems against SCAP-expressed security benchmarks and baselines, providing consistent, efficient configuration compliance monitoring."),
    Question(id: 936, domain: 7, text: "How does ConMon differ from periodic assessments?", options: ["Periodic assessments give truly continuous coverage that ConMon can only sample occasionally", "ConMon gives ongoing, near-real-time visibility, while assessments are point-in-time", "ConMon and periodic assessments are the same activity under two different names", "ConMon is required only for HIGH-impact systems, while assessments cover the rest"], answer: 1, explain: "ConMon addresses the gap between formal assessments — providing ongoing awareness rather than relying on annual snapshots. Threats don't respect assessment schedules; ConMon enables detection and response throughout the year."),
    Question(id: 937, domain: 7, text: "An organization's ConMon program identifies a rapid increase in failed authentication attempts targeting privileged accounts. The FIRST response should be:", options: ["Wait and see if the attempts succeed", "Investigate immediately", "Increase the lockout threshold", "Document it in the next monthly report"], answer: 1, explain: "Anomalous failed authentication patterns require immediate investigation — they may indicate an active attack. The ConMon detection triggers an incident response process to contain, eradicate, and recover before compromise occurs. This pattern may indicate a credential stuffing or brute force attack in progress. Escalate to incident response if an active attack is confirmed."),
    Question(id: 938, domain: 7, text: "After a significant incident, updating the ConMon strategy based on lessons learned is important because:", options: ["It satisfies documentation requirements only", "It is required within 24 hours of any incident", "Incidents reveal gaps in detection, response, or controls", "It replaces the need for a post-incident review"], answer: 2, explain: "Lessons learned from incidents provide direct evidence of ConMon gaps — what wasn't detected, why, and what would have helped. Updating the strategy improves future detection capability. Updating the ConMon strategy closes those gaps to prevent similar incidents."),
    Question(id: 939, domain: 7, text: "Data collected during ConMon must be:", options: ["Retained per legal and organizational requirements", "Kept for exactly one year, no more and no fewer than that", "Deleted right after each assessment cycle completes", "Shared publicly for the sake of complete transparency"], answer: 0, explain: "ConMon data (logs, scan results, configuration records) must be retained per applicable requirements — AU-11 requires audit records for a defined period. Retained data enables after-the-fact investigation of incidents discovered later."),
    Question(id: 940, domain: 7, text: "A system undergoes emergency maintenance that requires briefly disabling a security control. The ISSO should:", options: ["Disable the control and proceed with no notification to anyone", "Document the disablement, add compensating controls, then restore it and notify the AO", "Permanently remove the affected control from the SSP to reflect the new system configuration", "Request a denial of authorization to operate for the maintenance window"], answer: 1, explain: "Temporary control disablements must be documented, accompanied by compensating controls (e.g., taking systems offline, restricting access), and restored promptly — with the AO notified of any extended periods or material risk increase."),
    Question(id: 941, domain: 7, text: "Which type of risk must be monitored in a cloud environment that differs from traditional on-premise monitoring?", options: ["Multi-tenancy, shared-infrastructure, CSP misconfiguration, and API risks", "Only the physical security risks that are present at the data hosting facility", "Only the user authentication risks", "Only the network perimeter risks"], answer: 0, explain: "Cloud environments introduce unique monitoring requirements: CSP shared infrastructure incidents (affecting multiple tenants), cloud-specific misconfigurations (exposed S3 buckets), API vulnerabilities, and the need to monitor the CSP's own security posture."),
    Question(id: 942, domain: 7, text: "An organization monitors its SaaS provider's FedRAMP continuous monitoring deliverables. These deliverables include:", options: ["Only the cloud provider's most recent annual SOC 2 Type II attestation report", "Only the provider's original FedRAMP Security Assessment Report from authorization", "Only the provider's published information security policy and procedure documents", "Monthly scan results, change notices, annual assessments, and incidents"], answer: 3, explain: "FedRAMP CSPs must provide ongoing ConMon deliverables to the FedRAMP PMO and authorizing agencies: monthly scan results, annual assessments, significant change requests, and incident reports — enabling agencies to maintain awareness of the CSP's risk posture."),
    Question(id: 943, domain: 7, text: "The decommissioning of a system must include which privacy-specific activity?", options: ["Only transferring the data to another system", "Dispose of PII per retention schedules, law, and media sanitization", "Only notifying all of the affected users that the system is being shut down", "Only shredding the printed paper documents"], answer: 1, explain: "System decommissioning triggers privacy obligations: conducting a final data inventory, transferring data per retention requirements, securely sanitizing all PII-containing media (SP 800-88), and ensuring no PII remains accessible on decommissioned equipment."),
    Question(id: 944, domain: 7, text: "After a system is decommissioned, the authorization package (SSP, SAR, POA&M) should be:", options: ["Retained per organizational records retention requirements", "Destroyed immediately along with the system", "Transferred to the vendor", "Classified automatically"], answer: 0, explain: "Authorization packages are organizational records — they must be retained per applicable retention schedules even after system decommissioning. They may be needed for audits, litigation, incident investigations, or historical reference. For historical evidence, audit purposes, and potential legal needs."),
    Question(id: 945, domain: 7, text: "An organization's ConMon program uses automated tools to check configuration compliance every 24 hours. A new vulnerability is announced that is exploitable in minutes. The 24-hour cycle:", options: ["Is always sufficient for all risk levels", "Is insufficient for critical vulnerabilities", "Should be extended to reduce system load", "Is satisfactory since monitoring is automated"], answer: 1, explain: "Monitoring frequency must be calibrated to threat velocity. When actively exploited vulnerabilities emerge, the organization cannot wait 24 hours — emergency patch deployment or isolation must occur immediately, supplemented by real-time monitoring. The monitoring frequency must be accelerated or compensating controls implemented immediately when high-speed exploitation is possible."),
    Question(id: 946, domain: 7, text: "Which of the following ConMon activities directly supports the 'Monitor' step of the RMF?", options: ["Selecting the appropriate initial security control baselines for the system", "Developing the initial System Security Plan before implementation begins", "Categorizing the information system", "Ongoing control assessments and security status reporting to the AO"], answer: 3, explain: "The RMF Monitor step (Step 6) encompasses all ConMon activities: ongoing assessments, security status reporting, implementing response actions, and updating authorization documentation — maintaining the authorization through continuous awareness."),
    Question(id: 947, domain: 7, text: "A 'Plan of Action and Milestones' (POA&M) during the Monitor phase should be:", options: ["Finalized after authorization and never updated", "Only updated annually", "Replaced by the ConMon dashboard", "Actively maintained"], answer: 3, explain: "The POA&M is a living document throughout the system's lifecycle — ConMon continuously identifies new findings (added to POA&M) and verifies remediation (items closed). It provides the AO ongoing visibility into the system's risk trajectory. Updated as new vulnerabilities are discovered, old ones are remediated, and risk levels change throughout the system's operational life."),
    Question(id: 948, domain: 7, text: "Supply chain monitoring activities during the Monitor phase include:", options: ["Monitoring only the shipping manifests for inbound hardware components and their spares", "Auditing the vendor's master service contracts on a strictly annual recurring basis", "Monitoring only the single primary software vendor that supplies the core platform", "Reviewing threat intel, advisories, and vendor notices for compromise indicators"], answer: 3, explain: "RMF guidance (SP 800-37 Monitor step and SP 800-161 supply chain risk management) requires actively monitoring supply chain risks through multiple intelligence sources — new vulnerabilities in components, vendor compromises, and third-party service provider security incidents all affect the system's risk posture."),
    Question(id: 949, domain: 7, text: "Which activity demonstrates that a ConMon program is 'risk-based' rather than 'compliance-based'?", options: ["Prioritizing monitoring by each control's criticality and failure impact", "Monitoring every single control at exactly the same fixed monitoring frequency", "Reporting only what is specifically required by the governing regulation", "Checking every box on the compliance checklist"], answer: 0, explain: "A risk-based ConMon program allocates monitoring resources where risk is highest — not treating all controls equally. High-impact controls in high-threat environments get more frequent monitoring than stable, low-risk controls."),
    Question(id: 950, domain: 7, text: "A system's ConMon strategy defines that vulnerability scans will occur weekly and results reported to the AO monthly. If a CRITICAL vulnerability is discovered in a weekly scan, reporting should:", options: ["Occur in 30 days, per the system's normal monthly reporting schedule", "Happen immediately — critical findings are escalated without delay", "Wait for the next scheduled monthly report", "Only occur if exploitation is confirmed"], answer: 1, explain: "Reporting schedules define routine status reporting — they are not meant to delay critical findings. CRITICAL vulnerabilities, especially if actively exploited, require immediate escalation outside the normal reporting cycle."),
    Question(id: 951, domain: 7, text: "NIST SP 800-137 identifies three tiers for implementing ISCM. Tier 3 (information system level) focuses on:", options: ["Organization-wide risk management strategy", "Mission/business process risk visibility", "Enterprise-wide security metrics aggregation", "System-level monitoring activities"], answer: 3, explain: "Tier 3 ISCM operates at the system level: collecting and analyzing system-specific security data, reporting status, and taking corrective actions. This data rolls up to Tier 2 and Tier 1 for organizational risk visibility. Configuration compliance, vulnerability scanning, log analysis, and status reporting for individual systems."),
    Question(id: 952, domain: 7, text: "An organization must report major cybersecurity incidents to the appropriate federal authority. Under FISMA and related OMB guidance, major incidents affecting federal systems must be reported to:", options: ["CISA and OMB, within the required reporting timeframes", "Only the agency's internal legal counsel and review team", "Only the agency's Office of the Inspector General staff", "Only the commercial vendor that originally supplied the system"], answer: 0, explain: "FISMA and OMB M-20-04 require federal agencies to report major cybersecurity incidents to CISA within defined timeframes and to notify OMB and Congress for incidents meeting the 'major incident' threshold."),
    Question(id: 953, domain: 7, text: "The 'respond' component of the ISCM process involves:", options: ["Only patching vulnerabilities", "Taking action based on ConMon findings", "Only reporting to the AO", "Only updating the SSP"], answer: 1, explain: "ISCM response encompasses all actions taken based on monitoring findings: technical remediation, configuration changes, security control adjustments, escalation to incident response, AO notification, and POA&M updates. Patching, configuration changes, rule updates, escalation, incident response, and POA&M updates."),
    Question(id: 954, domain: 7, text: "Reviewing system logs as part of ConMon most directly supports which SP 800-53 control?", options: ["CM-6 (Configuration Settings)", "PE-3 (Physical Access Control)", "AU-6 (Audit Record Review, Analysis, and Reporting)", "CP-9 (System Backup)"], answer: 2, explain: "AU-6 requires reviewing and analyzing audit records for inappropriate or unusual activity and reporting findings — the ConMon activity of log review directly implements this control."),
    Question(id: 955, domain: 7, text: "A system supporting a critical mission has 24/7 operational requirements. Scheduled maintenance that takes the system offline requires:", options: ["Notifying CISA well in advance of any planned outage affecting the mission system", "Coordinating with mission owners, a contingency plan, and CCB-reviewed windows", "Approval from the internal IT operations team alone", "No special planning; just schedule it whenever convenient"], answer: 1, explain: "Taking mission-critical systems offline requires advance coordination with mission owners, contingency procedures to maintain mission capability during downtime, and change management approval — not just IT scheduling."),
    Question(id: 956, domain: 7, text: "Which ConMon activity specifically supports detecting insider threats?", options: ["Routine external penetration testing of the organization's systems", "Only the network perimeter vulnerability scanning activities done", "Physical security guard patrols", "User behavior analytics, privileged-access monitoring, and DLP"], answer: 3, explain: "Insider threats operate with legitimate access — detecting them requires behavioral analytics, privileged access monitoring, and DLP that can identify anomalous patterns (unusual data access, downloads, or communications) by authorized users."),
    Question(id: 957, domain: 7, text: "A system's license for a critical security tool (vulnerability scanner) expires. The ISSO should:", options: ["Continue using the expired license", "Immediately renew the license or identify an alternative", "Temporarily remove that control from the SSP", "Only address it at the next annual review"], answer: 1, explain: "Security tool licenses are operational requirements — an expired license creating a monitoring gap is a risk management issue. The gap must be addressed immediately, and if it persists, documented in the POA&M and reported to the AO. An operational gap in monitoring capability must be addressed and documented."),
    Question(id: 958, domain: 7, text: "An organization implements Privacy Continuous Monitoring (PrivCM) alongside security ConMon. PrivCM focuses on:", options: ["Tracking only the organization's GDPR-specific compliance metrics reported over time", "Ongoing monitoring of privacy controls, PII flows, and consent validity", "Fully replacing the security monitoring for any system that processes PII data records", "Performing a single privacy impact assessment during each annual review cycle only"], answer: 1, explain: "PrivCM extends ConMon to privacy — monitoring privacy control effectiveness, data flow changes affecting PII, consent management, and privacy risk indicators. SP 800-37 Rev. 2 integrates privacy monitoring into the overall ConMon program."),
    Question(id: 959, domain: 7, text: "The risk register maintained during ConMon should be updated to reflect:", options: ["Only new high-risk findings", "Only risks added after authorization", "Only risks identified by external assessors", "All changes to identified risks"], answer: 3, explain: "The risk register is a living document reflecting the current risk landscape — it must capture all risk changes (new risks, changed risks, mitigated risks, accepted risks) to provide accurate situational awareness for risk decisions. New risks identified, risks that have changed in likelihood or impact, risks that have been mitigated, and risks that are being accepted."),
    Question(id: 960, domain: 7, text: "Network flow analysis (NetFlow) as a ConMon tool helps detect:", options: ["Only previously catalogued malware signatures observed in inbound file transfers", "Anomalous traffic, data exfiltration, lateral movement, and C2 communications", "Physical intrusion attempts against the facility's perimeter and server rooms", "The relative strength of individual user account passwords"], answer: 1, explain: "NetFlow analysis enables detection of network behavior anomalies that signature-based tools miss — identifying data exfiltration (large unusual outbound flows), lateral movement (east-west traffic between segments), and C2 communications."),
    Question(id: 961, domain: 7, text: "An organization's ConMon program reports security status to the AO through a formal status report. This report should include:", options: ["Posture summary, significant changes, POA&M status, metrics, and risk changes", "A complete line-by-line listing of every single patch deployed during the period", "Only the current count of open POA&M items", "Only the results of the latest vulnerability scan"], answer: 0, explain: "AO status reports must provide enough information for ongoing risk awareness: overall posture trends, material changes, remediation progress, monitoring metrics, and emerging risks — enabling the AO to maintain informed authorization."),
    Question(id: 962, domain: 7, text: "A decommissioned system's hardware (servers, workstations) must be sanitized before disposal according to:", options: ["IT department preference", "Vendor return policies", "SP 800-88 Guidelines for Media Sanitization", "EPA regulations only"], answer: 2, explain: "SP 800-88 provides the authoritative guidance for media sanitization — the appropriate method (Clear for low-risk, Purge for moderate/high, Destroy for high-risk situations) depends on the sensitivity of the data previously processed. Using appropriate methods (Clear, Purge, or Destroy) based on the sensitivity of data previously stored."),
    Question(id: 963, domain: 7, text: "An organization maintains a 'continuous authorization' rather than periodic reauthorization. The key enabling requirement is:", options: ["The system must be categorized as LOW impact under the FIPS 199 standard", "A robust ISCM program giving the AO ongoing risk assurance", "The approach is applicable only to cloud-hosted information systems", "The system's operations must be made fully automated from end to end"], answer: 1, explain: "Ongoing/continuous authorization requires a mature ISCM program that gives the AO real-time confidence in the system's risk posture — without robust ConMon, the AO cannot make continuous risk acceptance decisions."),
    Question(id: 964, domain: 7, text: "Which of the following demonstrates effective 'close the loop' in a ConMon program?", options: ["Collect the monitoring data and simply store it for an annual review later", "Generate alerts that then go ignored by the team", "Detect, investigate, fix, verify, update the POA&M, and report", "Complete every step on a compliance checklist"], answer: 2, explain: "'Closing the loop' means the full cycle works: detect, analyze, respond, verify, and report. A ConMon program that detects issues but doesn't follow through to verified remediation and reporting provides only partial value."),
    Question(id: 965, domain: 7, text: "When an organization transitions from a legacy system to a new system, the ConMon strategy must:", options: ["Apply the old system's ConMon strategy entirely unchanged", "Be built for the new system's architecture and risks", "Only cover the migration period itself", "Only update if the impact level changes"], answer: 1, explain: "New systems have different architectures, attack surfaces, and risks than legacy systems. The ConMon strategy must be tailored to the new system's characteristics — a copy-paste approach from legacy to new is insufficient."),
    Question(id: 966, domain: 7, text: "A vulnerability is discovered in software used by the organization but is classified as 'low' severity. Should it be monitored and addressed?", options: ["Yes — low-severity issues must be tracked, since they can chain into higher impact", "No — low-severity findings fall below the threshold that requires any tracking", "Only after the vendor releases a patch that raises the finding's assigned severity rating", "Only when the vulnerability is confirmed to be under active exploitation today"], answer: 0, explain: "Low severity vulnerabilities must still be tracked and addressed — they can be chained with other vulnerabilities to achieve higher-impact attacks. Risk prioritization determines urgency, but elimination from tracking is inappropriate. Vulnerability chaining."),
    Question(id: 967, domain: 7, text: "Which of the following is an example of ConMon data that directly informs AO risk decisions?", options: ["Aggregate employee job-satisfaction survey scores collected each quarter", "The total volume of help-desk support tickets that were opened during the month", "A dashboard showing critical patches overdue beyond the required window", "Security-awareness training completion rates measured across the workforce only"], answer: 2, explain: "Aggregate security posture data — especially trends and systemic gaps (like overdue patch compliance) — is exactly the information AOs need for ongoing risk decisions. It may trigger expedited remediation requirements or authorization review."),
    Question(id: 968, domain: 7, text: "The 'review and update' phase of the ISCM process requires organizations to:", options: ["Conducting a single comprehensive third-party security audit on a fixed annual schedule", "Updating only the monitoring tool's software to the latest vendor release", "Adding new controls to monitoring solely when explicitly directed to", "Regularly assessing ISCM effectiveness and updating metrics, tools, and frequencies"], answer: 3, explain: "ISCM is not static — the program itself must be continuously improved. Regularly reviewing whether metrics are meaningful, frequencies are appropriate, and tools are effective ensures the program remains relevant and capable."),
    Question(id: 969, domain: 7, text: "An organization discovers that a cloud service provider used by one of its systems has been compromised in a data breach. The FIRST action under the RMF Monitor step should be:", options: ["Immediately cancel the cloud service provider contract without further review", "Wait for the provider to deliver its full report before taking any action at all", "Activate IR, assess impact on agency data, notify the AO, and coordinate", "Immediately revoke the system's authorization to operate"], answer: 2, explain: "CSP breaches affecting agency data require immediate incident response: contain impact where possible, assess agency data exposure, notify the AO (whose risk acceptance may be invalidated), and coordinate with CISA per federal incident reporting requirements."),
    Question(id: 970, domain: 7, text: "The ISSO's primary role in continuous monitoring is:", options: ["Making the final risk acceptance decision", "Conducting independent assessments", "Day-to-day execution of the ConMon program", "Authorizing changes to the system"], answer: 2, explain: "The ISSO is the ConMon operational lead — responsible for the ongoing security of the system, managing monitoring activities, tracking POA&M progress, and serving as the primary point of contact between the system and the AO/CISO. Collecting and reviewing security status, managing the POA&M, coordinating remediation, and keeping the AO informed."),
    Question(id: 971, domain: 7, text: "When decommissioning a system with external interconnections, the FIRST step should be:", options: ["Simply shutting down the system", "Archiving all data", "Submitting a new ATO for the remaining systems", "Formally terminating ISAs and notifying interconnected system owners"], answer: 3, explain: "Decommissioning with interconnections requires notifying dependent system owners and formally terminating ISAs — abrupt disconnection could break dependent systems and violates the agreements governing those connections. Unexpectedly severing connections can impact dependent systems and violate formal agreements."),
    Question(id: 972, domain: 7, text: "A ConMon program that provides HIGH coverage of LOW-impact controls and LOW coverage of HIGH-impact controls is:", options: ["Optimally balanced, since every control receives proportionate monitoring attention", "Acceptable for large organizations that operate many low-impact systems at once", "Miscalibrated — the highest-risk controls deserve the most monitoring", "Fully compliant with the monitoring approach described in NIST SP 800-137"], answer: 2, explain: "Risk-based ConMon allocates the most monitoring resources to the highest-risk controls. Inverting this priority — monitoring low-risk controls intensively while neglecting high-risk ones — misallocates resources and leaves the highest risks least monitored."),
    Question(id: 973, domain: 7, text: "An organization's ConMon program identifies that a critical system has been running 6 months past its scheduled reauthorization date with no reauthorization initiated. This situation requires:", options: ["No action — ATOs don't expire if ConMon is in place", "Immediate escalation", "A 6-month extension automatically", "Only a documentation update"], answer: 1, explain: "Operating past an authorization expiration without reauthorization or a documented ongoing authorization is a FISMA compliance gap. The AO must be notified immediately and a reauthorization initiated — the system may be operating without legal authorization to do so. Operating beyond the authorized period without formal reauthorization or continuous authorization constitutes a compliance gap requiring immediate AO attention."),
    Question(id: 974, domain: 7, text: "Automated patch management systems improve ConMon effectiveness by:", options: ["Shrinking patch deployment time and giving real-time compliance and finding closure", "Completely replacing human oversight across the entire patch and remediation lifecycle", "Eliminating the organization's ongoing need to perform any vulnerability scanning at all", "Managing only the operating system patches, not application updates"], answer: 0, explain: "Automated patch management implements SI-2 at scale and speed — reducing the window of vulnerability exposure, providing real-time compliance visibility for ConMon dashboards, and automatically closing POA&M items when patches are confirmed deployed."),
    Question(id: 975, domain: 7, text: "Which approach BEST describes mature, risk-based continuous monitoring?", options: ["Monitor absolutely everything equally at the maximum possible frequency", "Monitor only what the regulation specifically requires", "Automate all monitoring with no human review at all", "Monitor the right things, at the right rate, and act by risk"], answer: 3, explain: "Mature ISCM is characterized by risk-aligned monitoring depth and frequency, meaningful metrics, effective tools, timely human analysis, proportional response, and continuous program improvement — not checkbox compliance."),
    Question(id: 976, domain: 7, text: "An ISSO notices that the same vulnerabilities keep reappearing in monthly scans despite being marked as 'remediated' in the POA&M. This indicates:", options: ["A systemic remediation failure", "Normal behavior — vulnerabilities frequently reappear", "The scanner is malfunctioning", "The vulnerabilities are false positives"], answer: 0, explain: "Recurring vulnerabilities indicate ineffective remediation — the fix doesn't persist (configuration drift), doesn't address the root cause (symptom treatment), or isn't being applied to all affected systems. Root cause analysis and process improvement are needed. Patches are not being properly applied, configurations revert, or the root cause is not being addressed."),
    Question(id: 977, domain: 7, text: "Documentation that must be updated during system decommissioning includes:", options: ["Only the organizational chart for the office that previously operated the system", "Only the authorization to operate memorandum", "Only the active vendor support contracts", "System inventory, network docs, interconnection agreements, and final SSP/POA&M"], answer: 3, explain: "Decommissioning requires comprehensive documentation updates: removing the system from inventories, terminating formal interconnection agreements, documenting final disposition of data and media, and updating organizational records to reflect that the system no longer exists."),
    Question(id: 978, domain: 7, text: "A system's ConMon program detects that user accounts belonging to terminated employees remain active 30 days after their departure. This indicates a failure of:", options: ["SC-28 (Protection of Information at Rest)", "CP-9 (System Backup)", "PS-4 (Personnel Termination) and AC-2 (Account Management)", "AU-6 (Audit Record Review)"], answer: 2, explain: "Active accounts for terminated personnel are a significant insider threat risk. PS-4 requires prompt access revocation upon termination; AC-2 requires account disable/removal procedures. ConMon detecting this gap drives immediate remediation. Terminated accounts must be disabled promptly, not left active for weeks."),
    Question(id: 979, domain: 7, text: "The primary purpose of the 'Security Status Report' delivered to the AO under SP 800-137 is:", options: ["To satisfy the program's formal documentation requirements only", "To serve as a replacement for the SAR", "Give the AO current info for ongoing authorization decisions", "To document completed staff training"], answer: 2, explain: "Security Status Reports are the primary communication channel between the system and the AO during ConMon — they provide the AO with the ongoing situational awareness needed to determine whether their original risk acceptance remains valid."),
    Question(id: 980, domain: 7, text: "An organization's ConMon identifies that 25% of systems have open CRITICAL vulnerability findings older than the required 15-day remediation window. The APPROPRIATE escalation path is:", options: ["Escalate to CISO and AOs immediately", "Document it in the annual report", "Extend all remediation windows to 60 days", "Report only to system owners"], answer: 0, explain: "Systemic failure to meet remediation timelines is an organization-level risk management failure — it indicates inadequate resources, processes, or priorities. CISO and AO escalation is required to drive corrective action at the appropriate level. Systemic non-compliance with remediation timelines represents a significant, organization-wide risk management failure requiring senior attention and resource allocation."),
    Question(id: 981, domain: 7, text: "NIST SP 800-128 (Configuration Management) guidance integrates with ConMon by:", options: ["Replacing vulnerability scanning", "Providing the processes and procedures to maintain secure configurations", "Replacing change management", "Only applying during initial system deployment"], answer: 1, explain: "SP 800-128 establishes the configuration management processes that ConMon verifies are working — CM baselines, change control, and configuration auditing together ensure that deployed configurations remain authorized and secure. The authorized baseline that ConMon verifies is maintained throughout the system's operational life."),
    Question(id: 982, domain: 7, text: "After incorporating lessons learned from a security incident into the ConMon strategy, the organization should:", options: ["Keep the changes internal and not inform the AO", "Only update the ISCM tools", "Brief the AO on the changes", "Wait 1 year to assess if the changes were effective"], answer: 2, explain: "AOs rely on ConMon to maintain authorization awareness. When the ConMon strategy changes significantly based on lessons learned, the AO should be briefed — especially if the changes reveal previous monitoring gaps that affected their risk understanding. The AO should understand what was learned, what gaps were identified, and how the ConMon strategy has improved."),
    Question(id: 983, domain: 7, text: "Which of the following best exemplifies 'automation' in a mature ConMon program?", options: ["Automated metric collection, continuous scanning, and real-time compliance alerting", "Scheduling automated penetration tests to run just once per year against the whole environment", "Tracking all POA&M items in a shared manual spreadsheet", "Reviewing system logs by hand every single day"], answer: 0, explain: "Automation in ConMon maximizes efficiency — computers handle repetitive data collection, compliance checking, and alerting while human analysts focus on the higher-value work of investigation, contextual analysis, and risk decision-making."),
    Question(id: 984, domain: 7, text: "The concept of 'defense in depth' applies to ConMon by:", options: ["Running a single, highly tuned monitoring tool at its maximum sustainable sampling rate", "Applying identical monitoring depth uniformly across every system layer", "Layering complementary monitors (network, endpoint, app, cloud) so no gap is total", "Maximizing total alert volume so that analysts never miss a security event"], answer: 2, explain: "Defense in depth in ConMon means layering monitoring capabilities — network monitoring catches what endpoint monitoring misses, application logging catches what network monitoring misses. No single monitoring tool provides complete visibility."),
    Question(id: 985, domain: 7, text: "Which of the following is the MOST important output of an effective ConMon program?", options: ["A comprehensive bound binder of compliance documentation prepared for the auditors", "Timely, accurate situational awareness for near-real-time risk decisions", "The maximum possible number of security metrics collected across the whole system", "Evidence of current tool licenses and active subscription renewals kept on file"], answer: 1, explain: "The purpose of ConMon is decision support — providing the AO, security team, and leadership with accurate, current information to make informed risk decisions. Documentation and metrics are means to this end, not the end itself."),

    // MARK: – Final batch: reaching 750 (mixed domains)
    Question(id: 990, domain: 5, text: "An organization conducts annual penetration tests. Between tests, a major architectural change is made. When should a supplemental pen test occur?", options: ["Only at the next annual test", "Never — annual tests are sufficient", "After the significant change", "Only if the architecture change adds new users"], answer: 2, explain: "CA-8 requires penetration testing at defined frequencies AND when significant changes occur. A major architectural change may introduce new attack vectors that weren't present during the last annual test. CA-8 (Penetration Testing) calls for testing after significant changes that could affect security posture."),
    Question(id: 991, domain: 5, text: "The 'examine' assessment method is MOST appropriate for verifying:", options: ["Whether a network firewall actually blocks the traffic it should", "Whether a policy exists, is current, and is approved", "Whether the staff can correctly respond to a phishing attempt", "Whether the system's backups actually restore successfully"], answer: 1, explain: "Examining policies, procedures, and documentation verifies their existence and adequacy — it cannot verify that technical controls actually function (which requires 'test') or that people understand procedures (which requires 'interview')."),
    Question(id: 992, domain: 5, text: "When assessing a cloud system, an assessor cannot directly access the underlying infrastructure managed by the CSP. The assessor should:", options: ["Accept the CSP's assurances without any verification", "Use the CSP's FedRAMP, 3PAO, and SOC 2 evidence", "Mark all CSP-managed controls as 'other than satisfied'", "Skip infrastructure-level testing"], answer: 1, explain: "Cloud assessments require creative evidence collection — leveraging the CSP's authorization artifacts for the infrastructure layer while directly testing the customer-accessible application, configuration, and data layers."),
    Question(id: 993, domain: 5, text: "A risk matrix that plots likelihood vs. impact into a 5×5 grid produces how many risk levels?", options: ["5", "25", "10", "Unlimited"], answer: 1, explain: "A 5×5 risk matrix has 25 cells (5 likelihood levels × 5 impact levels). Cells are then grouped into risk levels (e.g., Critical, High, Moderate, Low) based on the combined score in each cell."),
    Question(id: 995, domain: 5, text: "Which standard provides guidance specifically for IT audit methodology, including evidence collection and audit reporting?", options: ["NIST SP 800-53A, which defines the security control assessment procedures used", "NIST SP 800-37, which describes the full Risk Management Framework lifecycle steps", "ISACA's IT Audit Framework (ITAF) and its related professional standards", "FIPS 199, for security categorization"], answer: 2, explain: "ISACA's ITAF and related standards (COBIT audit guidance, IS audit standards) provide the professional framework for IT audit — covering evidence standards, audit reporting, professional independence, and audit methodology."),
    Question(id: 996, domain: 5, text: "An assessor testing SI-3 (Malware Protection) would MOST likely examine:", options: ["Antivirus deployment, signature update logs, scan reports, and incident records", "User security-awareness training completion records and printed certificates only", "The physical locks securing the server room doors", "The current network routing and switching tables"], answer: 0, explain: "SI-3 assessment examines and tests: antivirus deployment breadth, signature currency (update frequency), scan schedules and completion, and evidence that malware is detected and responded to appropriately."),
    Question(id: 997, domain: 5, text: "During an assessment of IA-5 (Authenticator Management), the assessor finds passwords shorter than the organization's defined minimum length. This is a deficiency in:", options: ["AC-2 (Account Management), which governs provisioning of user accounts", "CM-6 (Configuration Settings), which governs secure baseline settings", "AU-2 (Event Logging)", "IA-5, which requires the organization's minimum password length"], answer: 3, explain: "IA-5 defines authenticator requirements including minimum password length and complexity. Passwords below the minimum represent a direct control deficiency — documented as 'other than satisfied' in the SAR."),
    Question(id: 998, domain: 5, text: "A risk assessor determines that a high-impact, high-likelihood risk has no associated mitigating controls. This represents:", options: ["An accepted risk", "A low-priority finding", "An unmitigated risk gap requiring immediate attention", "Normal for operational systems"], answer: 2, explain: "High-impact, high-likelihood risks with no controls represent the most critical risk gaps. They require immediate action — either deploying controls to reduce the risk or, if controls aren't feasible, formal AO risk acceptance with documentation. Either implement controls or formally accept and document the risk through the AO."),
    Question(id: 999, domain: 5, text: "An assessor uses the NIST SP 800-53A 'assessment procedures' for AC-2. These procedures define:", options: ["Precisely how the authorizing official reaches the final authorization decision", "The exact number of individual user accounts that the assessor must review", "The maximum amount of time that is allowed for completing the assessment", "The objects to examine, people to interview, and functions to test"], answer: 3, explain: "SP 800-53A provides assessment procedures for each control — specifying what to examine (policies, records, configurations), who to interview (responsible roles), and what to test (mechanisms, procedures) to determine if the control is satisfied."),
    Question(id: 1000, domain: 5, text: "During assessment, an assessor finds that the organization's incident response plan has not been updated in 3 years and does not reflect current system architecture. This is a deficiency in:", options: ["IR-8 (Incident Response Plan)", "AU-6 (Audit Record Review)", "CP-9 (System Backup)", "AT-2 (Literacy Training)"], answer: 0, explain: "IR-8 requires keeping the incident response plan current — reflecting changes to the organization, system architecture, and threat landscape. An outdated plan is a control deficiency even if it technically exists. Plans must be kept current to be effective; an outdated plan may guide responders to take incorrect actions based on obsolete architecture."),
    Question(id: 1004, domain: 6, text: "An organization is considering whether to grant an ATO to a system with a known HIGH vulnerability that cannot be patched for 60 days due to operational constraints. The MOST appropriate action is:", options: ["Grant an ATO with conditions: compensating controls now and required resolution", "Deny the authorization outright until the outstanding vendor patch can finally be applied", "Grant a full, unrestricted ATO since the vulnerability will be fixed later anyway", "Wait the full 60 days before even beginning the authorization process"], answer: 0, explain: "An ATO with conditions is appropriate — the mission need may justify temporary operation, but the AO must attach conditions requiring the HIGH finding to be resolved within the defined timeframe with compensating controls reducing risk in the interim."),
    Question(id: 1005, domain: 6, text: "The concept of 'inherent authority' for AOs means:", options: ["AOs can authorize any system across the government", "AOs can freely override published OMB guidance", "AOs are able to accept truly unlimited risk", "Authority within their designated scope"], answer: 3, explain: "AO authority is scoped — an AO is designated for specific systems or mission areas within the organizational hierarchy. They cannot authorize systems outside their designated authority or accept risks that exceed organizational boundaries."),
    Question(id: 1006, domain: 6, text: "When documenting the risk posture for an authorization decision, which factor is the MOST important to include?", options: ["The number of controls assessed", "The assessment team's qualifications", "The specific residual risks the AO is accepting", "The system's budget"], answer: 2, explain: "The authorization decision document must clearly identify what risks are being accepted — not just that the AO approved the system. Without specific risk identification, the acceptance is meaningless and the AO cannot be held accountable. Quantified or described sufficiently to demonstrate the AO made an informed, conscious decision."),
    Question(id: 1007, domain: 6, text: "A system's authorization is terminated (not merely expired). What typically triggers termination before the ATO expiration?", options: ["Reductions in the organization's overall yearly budget", "The arrival of the regular annual authorization review cycles", "An unacceptable risk that can't be fixed fast", "A routine change in the assigned ISSO personnel member"], answer: 2, explain: "ATO termination (effectively a DATO mid-cycle) is triggered by discovery of a risk that the AO determines is unacceptably high — typically a critical vulnerability being actively exploited or a major control failure discovered post-authorization. The AO revokes authorization until the risk is addressed."),
    Question(id: 1008, domain: 6, text: "An agency CIO reviews all authorization decisions to ensure consistency with the organization's risk management strategy. This oversight function is consistent with:", options: ["The Tier 1 risk management function", "ISSO responsibilities", "Assessor independence requirements", "Continuous monitoring tooling requirements alone"], answer: 0, explain: "CIO oversight of authorization decisions implements the Tier 1 risk management function from SP 800-39 — ensuring that individual system risk acceptances stay consistent with the organization's established risk tolerance and strategy."),
    Question(id: 1011, domain: 7, text: "An organization implements 'DevSecOps' practices. From a ConMon perspective, DevSecOps contributes by:", options: ["Eliminating the entire need for continuous monitoring", "Serving as a replacement for manual security reviews", "Building security tests into the CI/CD pipeline", "Only used during initial development"], answer: 2, explain: "DevSecOps embeds security into every stage of the development and deployment pipeline — automated SAST/DAST, configuration scanning, and compliance checks in CI/CD create continuous security validation that supports ConMon goals."),
    Question(id: 1012, domain: 7, text: "A major hurricane causes a federal agency's primary data center to flood. Under the RMF, the FIRST ConMon/continuity action should be:", options: ["Activate the contingency plan", "Conduct a security assessment", "Submit a new ATO for the backup site", "Notify OMB before taking any action"], answer: 0, explain: "A major disruption triggers contingency plan activation (CP-2, CP-10) — the immediate priority is operational continuity. Security assessment and AO notifications follow once immediate recovery actions are underway. Initiating system recovery at the alternate site while beginning disaster impact assessment."),
    Question(id: 1013, domain: 7, text: "Reviewing and updating SLAs and contracts with service providers during ConMon is important because:", options: ["Provider duties directly affect the security posture", "Contracts are only ever reviewed at their renewal time", "Only the legal team is allowed to manage the contracts", "SLAs have no bearing at all on any of the security controls"], answer: 0, explain: "Service provider SLAs define security obligations (incident notification, availability, patching timelines) that are part of the system's overall control set. ConMon must verify providers are meeting these obligations and update agreements when requirements change."),
    Question(id: 1014, domain: 7, text: "A ConMon program that relies solely on automated tools without human analysis is:", options: ["Sufficient, because modern tools already automate triage and incident response end to end", "Insufficient — humans must interpret context, investigate anomalies, drive response", "Acceptable for LOW-impact systems, where analyst review adds little real value", "Preferred, since removing analysts cuts cost without reducing coverage"], answer: 1, explain: "Automation provides scale and speed in data collection — but humans are needed to interpret context, distinguish true positives from false positives, make risk judgments, and drive appropriate responses. Human + machine is more effective than either alone."),
    Question(id: 1015, domain: 7, text: "An organization's ISCM program generates a monthly 'Security Status Report' for the AO. This report's primary purpose is to:", options: ["Let the AO keep current risk awareness for ongoing authorization", "Serve as a full replacement for the system's annual security assessment", "Document merely that the continuous monitoring activities took place", "Satisfy only the FISMA annual reporting requirements and nothing more"], answer: 0, explain: "Security Status Reports close the loop between ConMon operations and AO risk decision-making — providing the current posture snapshot needed for the AO to determine whether the original authorization remains valid."),
    Question(id: 1016, domain: 1, text: "An organization's risk management program treats cyber risk as isolated from other enterprise risks. The BEST improvement is:", options: ["Integrating cyber risk into the enterprise risk management (ERM) framework", "No change needed — cyber risk is unique and should be separate", "Creating a separate cybersecurity ERM framework", "Delegating all cyber risk to the IT department"], answer: 0, explain: "Cyber risk doesn't exist in isolation — it must compete for resources alongside operational, financial, and strategic risks. ERM integration enables leadership to make holistic risk tradeoffs and allocate resources to the highest organizational risks. Enabling consistent risk evaluation, prioritization, and resource allocation across all risk types."),
    Question(id: 1017, domain: 1, text: "The concept of 'risk communication' in risk management involves:", options: ["Publishing internal risks on the organization's website", "Sharing risk information in formats appropriate to the audience", "Keeping risk information classified at all times", "Only reporting risks after incidents"], answer: 1, explain: "Effective risk communication translates risk information into formats that enable action at each level — tactical details for those implementing controls, strategic risk summaries for decision-makers, and trend data for governance bodies. Technical details for security teams, strategic summaries for leadership — to enable informed decisions at all levels."),
    Question(id: 1018, domain: 2, text: "A system that processes data across multiple classification levels (e.g., both SECRET and TOP SECRET) requires:", options: ["A single FIPS 199 categorization set at the lowest level", "Only the standard FISMA authorization process applied", "Only TOP SECRET controls applied uniformly", "Specialized accreditation for cross-domain operation"], answer: 3, explain: "Cross-domain or multi-level security systems face unique challenges — they require specialized controls to prevent data from one classification level contaminating another, and are typically subject to rigorous, specialized authorization processes."),
    Question(id: 1019, domain: 2, text: "A privacy threshold analysis (PTA) finds that a system does NOT process PII. The organization should:", options: ["Skip all privacy controls", "Conduct a full PIA anyway as a precaution", "Classify the system as LOW impact automatically", "Document the finding"], answer: 3, explain: "A negative PTA finding means no full PIA is required for PII processing, but some privacy obligations may still apply depending on how the system interacts with individuals. The finding should be documented and revisited if the system's scope changes. No PIA is required, but the system should still apply applicable privacy controls (notice, transparency) if it interacts with individuals."),
    Question(id: 1020, domain: 3, text: "Which SP 800-53 control family directly addresses the protection of systems from unauthorized software installation?", options: ["CM-7 (Least Functionality) and CM-11 (User-Installed Software)", "AC (Access Control), governing who may reach the system's resources", "IR (Incident Response)", "AU (Audit and Accountability)"], answer: 0, explain: "CM-7 (Least Functionality) requires configuring systems to provide only authorized functions, and CM-11 specifically governs user-installed software — requiring policy, monitoring, and enforcement to prevent unauthorized software."),
    Question(id: 1021, domain: 3, text: "A security engineer recommends implementing a 'deny all, permit by exception' firewall rule set. This recommendation implements:", options: ["The broad principle of defense in depth and nothing else at all", "CM-2 (Baseline Configuration) management of the system alone only", "AC-17 (Remote Access) controls only", "SC-7 boundary protection and least privilege for the network"], answer: 3, explain: "Default deny (deny all except explicitly permitted traffic) is a core boundary protection principle per SC-7 — it means only explicitly authorized traffic flows, minimizing attack surface compared to 'permit all, deny by exception.'"),
    Question(id: 1022, domain: 4, text: "A system processes biometric data for physical access control. From a privacy perspective, biometric data requires:", options: ["No special protection since it is used for security purposes", "The same protections as any other PII", "Enhanced protection", "Only HIPAA protections if the data includes health information"], answer: 2, explain: "Biometric data (fingerprints, iris scans) is irreversible PII — if compromised, individuals cannot change their biometrics as they would change a password. This unique sensitivity requires enhanced protections and careful handling. Biometric data is irreplaceable and uniquely sensitive. Compromise of biometric data cannot be remedied by issuing a new identifier as with passwords."),
    Question(id: 1023, domain: 4, text: "Implementing 'network access control' (NAC) for BYOD (Bring Your Own Device) environments addresses which specific risk?", options: ["Only the endpoint malware infections found on those devices", "Unauthorized or non-compliant devices on the network", "Only the authentication weaknesses within the whole system", "Physical theft of the devices"], answer: 1, explain: "NAC in BYOD environments ensures that only devices meeting security requirements (patched OS, AV installed, compliant configuration) can connect — preventing unmanaged, potentially compromised personal devices from introducing risk."),
    Question(id: 1024, domain: 5, text: "An assessor reviewing CM-2 (Baseline Configuration) finds that no approved baseline configuration exists for the system. This is:", options: ["A HIGH finding — with no baseline, drift is undetectable and the state is unknown", "Acceptable provided the system is demonstrably secure by other independent measures", "Only a minor documentation finding that carries essentially no security impact at all", "Acceptable whenever the vendor supplies a default configuration"], answer: 0, explain: "A missing baseline configuration is a fundamental control failure for CM-2 — without it, the organization cannot detect unauthorized changes, manage configurations systematically, or demonstrate that systems are in an authorized secure state."),
    Question(id: 1025, domain: 6, text: "An organization's AO refuses to authorize a system because it lacks a documented SSP. The AO's position is:", options: ["Too strict, because an ATO can in practice be granted without a formal written SSP", "Correct — the SSP is mandatory; without it the AO cannot judge the risk", "Incorrect, since a verbal description of the system will suffice", "Applicable only to HIGH-impact systems, not moderate ones"], answer: 1, explain: "The SSP is not optional — it is the foundational document describing the system's security posture, implemented controls, and authorization boundary. An AO cannot make an informed risk acceptance decision without it."),
    Question(id: 1026, domain: 7, text: "A system's POA&M has been unchanged for 6 months, with all items still marked 'in progress' and no milestones updated. The AO's concern should be:", options: ["Nothing — POA&Ms are formally reviewed and updated only on an annual cycle", "That the assessor is generating far more findings than the team can reasonably close out", "That milestones were set too aggressively and should simply be extended", "The POA&M isn't being managed — stalled remediation means accepted risk may be growing"], answer: 3, explain: "An unchanged POA&M for 6 months raises a red flag — remediation should show progress with updated milestones and status. A stale POA&M may mean the organization accepted risk based on planned remediation that isn't actually occurring."),
    Question(id: 1027, domain: 7, text: "Which NIST publication provides guidance on security-focused configuration management (CM) for information systems?", options: ["SP 800-137", "SP 800-30", "SP 800-39", "SP 800-128"], answer: 3, explain: "SP 800-128 provides comprehensive guidance on security-focused configuration management: CM planning, CM processes, secure configurations, change management, and configuration auditing throughout the system lifecycle."),
    Question(id: 1028, domain: 1, text: "The principle of 'accountability' in information security means:", options: ["Actions can be traced to those responsible for them", "The encryption of all of the system's communications", "Limiting access to the sensitive data", "Only technical controls enforce security"], answer: 0, explain: "Accountability requires that actions be attributable to specific individuals or entities (through audit logging, identification/authentication) — enabling investigation of incidents and deterring insider threats through the knowledge that actions are recorded."),
    Question(id: 1029, domain: 5, text: "During an assessment of AT-2 (Literacy Training and Awareness), which evidence would MOST effectively demonstrate the control is operating?", options: ["Completion records, curriculum content, and proof untrained users lost access", "The approved training policy together with the program's annual funding authorization memo", "A roster of security topics scheduled for delivery in the next fiscal year", "Photographs of the awareness posters displayed throughout the office space"], answer: 0, explain: "AT-2 assessment requires evidence of: who was trained (completion records), what they were trained on (curriculum), when (dates within required period), and consequences for non-completion — all three assessment methods (examine, interview, test) may be used."),
    Question(id: 1031, domain: 2, text: "A system's authorization boundary excludes the physical server hardware managed by a contracted data center. The system team should:", options: ["Expand the boundary to absorb the data center's entire hardware inventory", "Treat the physical controls as not-applicable since the servers are off-site", "Document the exclusion in the SSP and inherit the physical controls via an ISA", "Defer entirely to the data center's ATO without any written hosting agreement in place"], answer: 2, explain: "Excluding physical infrastructure requires documenting the exclusion, ensuring the data center has an authorization covering its physical controls, and formally documenting the hosting relationship — the system's ATO relies on the data center's physical protections."),
    Question(id: 1032, domain: 3, text: "The PT-5 (Privacy Notice) control requires organizations to:", options: ["Merely posting a privacy policy on the website only", "Clear notice of what PII is collected and why", "Notifying individuals only when a data breach occurs", "Notifying individuals only under explicit opt-in rules"], answer: 1, explain: "PT-5 implements the fair information practice principle of notice — individuals must receive meaningful information about data collection and processing practices at or before the point of collection."),
    Question(id: 1033, domain: 4, text: "A system's security architecture shows a 'flat' network with no segmentation between user workstations and critical servers. The PRIMARY security concern is:", options: ["Higher network speed", "Unrestricted lateral movement", "Reduced monitoring complexity", "Easier administration"], answer: 1, explain: "A flat network eliminates the security benefits of segmentation — a compromised user workstation provides direct access to critical servers. Network segmentation implements defense in depth by requiring attackers to traverse additional controls. If any workstation is compromised, attackers can directly access critical servers without traversing additional security controls."),
    Question(id: 1034, domain: 5, text: "An assessor discovers that the system's privacy notice describes data practices that don't match actual data processing activities. This is:", options: ["Only a documentation issue", "Acceptable if the gap is minor", "A privacy control finding", "Only relevant if individuals complain"], answer: 2, explain: "Mismatched privacy notices and actual practices are a serious finding — individuals made decisions based on false representations, creating legal exposure and violating core privacy principles (transparency, notice). The notice violation of PT-5 may also violate applicable privacy laws (GDPR Art. 13/14, Privacy Act) and indicates actual data practices differ from what individuals were told."),
    Question(id: 1035, domain: 7, text: "An organization's threat intelligence team identifies that a nation-state actor is actively targeting systems in the same sector using a specific attack chain. ConMon response should:", options: ["Wait for an official government advisory to be published before taking any action", "Act only after CISA issues a formal binding emergency directive covering the sector", "Immediately assess exposure, hunt for the indicators, and apply mitigations", "Increase only the perimeter network monitoring and leave internal sensors unchanged"], answer: 2, explain: "Timely threat intelligence requires timely action — when sector-specific threats are identified, organizations should immediately assess exposure, hunt for indicators of compromise, and implement targeted mitigations without waiting for formal directives."),
    Question(id: 1036, domain: 7, text: "A ConMon program produces weekly reports but they are never shared with the AO. This gap:", options: ["Represents a failure in the ConMon reporting process", "Is acceptable — AOs don't need weekly reports", "Is fine if reports are available on request", "Only matters for HIGH-impact systems"], answer: 0, explain: "ConMon reports must reach the AO — they are the mechanism for keeping the AO informed about whether their risk acceptance remains valid. Reports that stay within the security team don't serve the authorization maintenance purpose. The AO cannot maintain ongoing authorization awareness without receiving ConMon outputs."),
    Question(id: 1037, domain: 1, text: "The term 'risk posture' describes:", options: ["The physical security configuration of data centers", "An organization's or system's overall security risk profile", "Only the open POA&M item count", "The system's FIPS 199 category"], answer: 1, explain: "Risk posture is a holistic view of an organization's or system's current risk state — encompassing all identified risks, their current likelihood and impact, and the effectiveness of existing controls. It informs authorization and investment decisions. The aggregate of threats, vulnerabilities, likelihood, and impact at a point in time."),
    Question(id: 1038, domain: 3, text: "Which SP 800-53 control requires organizations to conduct security assessments of external service providers?", options: ["SA-3 (System Development Life Cycle)", "SC-8 (Transmission Confidentiality)", "SA-9 (External System Services)", "CA-2 (Control Assessments)"], answer: 2, explain: "SA-9 requires that contracts with external service providers include security requirements, and that providers' compliance with those requirements is monitored — extending the organization's risk management to its service supply chain. Requiring contracts and monitoring to ensure external providers meet organizational security requirements."),
    Question(id: 1039, domain: 4, text: "A developer argues that security controls should not be applied to the development environment since 'no real data' is processed there. The correct response is:", options: ["Agree — development environments need no security controls", "Only apply controls if customers request it", "Only apply controls after a breach occurs", "Development environments must have appropriate controls"], answer: 3, explain: "Development environments are high-value targets — they contain source code, architecture knowledge, credentials, and potentially sanitized but still sensitive data. A compromised dev environment can lead directly to production system compromise. They often contain sensitive code, architecture details, and credentials that could enable attacks on production systems."),
    Question(id: 1041, domain: 5, text: "Which type of assessment is MOST useful for determining if security controls are sufficient to protect against a sophisticated nation-state adversary?", options: ["Checklist-based compliance review", "Red team exercise simulating nation-state TTPs", "Automated vulnerability scanning only", "Annual control review against the SSP"], answer: 1, explain: "Nation-state adversaries use advanced, multi-stage attack chains that standard compliance assessments don't test. Red team exercises simulating APT TTPs provide the most realistic assessment of whether controls withstand sophisticated attacks. Testing the full depth of detection and response capability against advanced persistent threats."),
    Question(id: 1042, domain: 7, text: "An organization implements a 'risk dashboard' for the CISO and AO showing real-time security metrics. The PRIMARY risk to this capability is:", options: ["Dashboard complexity", "Dashboard visual design", "Dashboard data quality", "Too many users having access to the dashboard"], answer: 2, explain: "A risk dashboard is only as good as its underlying data. Poor data quality (false positives, incomplete coverage, stale data) creates false confidence and can lead decision-makers to believe risks are lower than they actually are. If the underlying monitoring data is inaccurate or incomplete, the dashboard provides misleading situational awareness and may drive bad risk decisions."),
    Question(id: 1043, domain: 2, text: "A system owner is documenting a system that processes both financial management data (moderate impact) and personally identifiable information (high confidentiality impact). The final FIPS 199 categorization is:", options: ["HIGH — the PII's high confidentiality drives the high-water mark", "Moderate, because the financial management data is the primary type", "Moderate overall, but HIGH only for privacy controls", "Determined solely by the primary data type present"], answer: 0, explain: "Per FIPS 199 high-water mark, the system's confidentiality category is HIGH (driven by the PII). The system categorization becomes HIGH overall, requiring the HIGH control baseline as the starting point."),
    Question(id: 1044, domain: 3, text: "When an overlay increases the rigor of controls beyond the standard baseline, this is called:", options: ["Scoping the baseline down by removing the controls that do not apply to the system", "Implementing a compensating control where the primary control cannot be met directly", "Tailoring up — applying more stringent requirements than the standard baseline", "A baseline reduction approved by the authorizing official"], answer: 2, explain: "Overlays can go in either direction — reducing controls for non-applicable areas (scoping) or increasing them for higher-risk environments (tailoring up). Healthcare or ICS overlays often add more stringent requirements than the standard NIST baseline."),
    Question(id: 1045, domain: 5, text: "An organization has a policy of conducting annual security assessments. Mid-year, a zero-day affecting a critical component is disclosed. The organization should:", options: ["Wait for the annual assessment to formally assess the vulnerability", "Conduct an immediate out-of-cycle assessment or targeted review of the affected component", "Patch it without further assessment", "Only assess if the zero-day is actively exploited"], answer: 1, explain: "Significant security events like zero-days require out-of-cycle assessment activities — RMF guidance calls for assessments when significant changes occur, and a critical zero-day constitutes a significant change to the risk posture. Zero-days cannot wait for scheduled assessments."),
    Question(id: 1046, domain: 1, text: "The 'Information Security Management System' (ISMS) concept in ISO 27001 is closest to which NIST concept?", options: ["A single individual system's System Security Plan document", "The control baseline for a single system", "The organization-wide program, like SP 800-39's Tier 1", "The continuous monitoring program for systems"], answer: 2, explain: "An ISMS (ISO 27001) is an organization-wide management system for information security — most analogous to NIST's Tier 1 organization-level security program under SP 800-39, though with different terminology and approach."),
    Question(id: 1047, domain: 4, text: "A system team implements 'runtime application self-protection' (RASP). RASP protects applications by:", options: ["Scanning source code before deployment", "Applying network-level filtering", "Encrypting application data at rest", "Monitoring and protecting application execution in real-time"], answer: 3, explain: "RASP integrates security into the application runtime — monitoring execution context and blocking attacks (injection, authentication bypass) in real-time from within the application, complementing perimeter and SAST/DAST approaches. Detecting and blocking attacks from within the running application."),
    Question(id: 1049, domain: 7, text: "After completing system decommissioning, which final action ensures organizational knowledge is preserved?", options: ["An after-action review capturing lessons learned, with records archived per schedule", "Immediately purging all system records and backups once the hardware is decommissioned", "Reassigning the entire system team to a new project right away", "Notifying only the immediate system stakeholders of closure"], answer: 0, explain: "Decommissioning should conclude with an after-action review — capturing lessons learned about system operations and security that inform future systems, with required records archived for audit, legal, and historical reference purposes."),
    // MARK: – D6 expansion: 27 additional Authorization questions (ids 1050–1076)
    Question(id: 1050, domain: 6, text: "An Inspector General audits a system and finds the ATO was granted without a completed SAR. The MOST significant implication is:", options: ["The ATO must be immediately revoked by law", "The authorization was made without independent assessment evidence", "Only a documentation penalty applies", "The ISSO is personally liable"], answer: 1, explain: "An ATO granted without a completed SAR means the AO had no independent assessment data. The authorization decision lacked its foundational evidence — risk acceptance made without that evidence is uninformed and potentially invalid. The AO accepted risk without knowing actual control effectiveness, invalidating the risk basis."),
    Question(id: 1051, domain: 6, text: "A system owner requests emergency authorization because the system must go live in 48 hours but the assessment is incomplete. The AO's BEST response is:", options: ["Grant a full ATO based only on the owner's word for it", "Tell the system owner to just proceed without authorization", "Issue an IATT with strict conditions, not a full ATO", "Deny all emergency requests, no exceptions"], answer: 2, explain: "When operational urgency prevents full assessment, an IATT allows limited, time-bounded operation under strict conditions — not a shortcut to a full ATO. The AO accepts defined risk for a specific period while the full authorization process completes."),
    Question(id: 1053, domain: 6, text: "When authorizing a DevOps environment where code is continuously deployed, the authorization approach should:", options: ["Issue a brand-new authorization to operate for each individual deployment", "Ongoing authorization with automated security gates in the CI/CD pipeline", "Require a full manual security assessment before every single code deployment", "Exclude all DevOps environments from the organization's authorization scope"], answer: 1, explain: "Continuous deployment environments require authorization approaches that match their velocity — ongoing authorization with automated security testing in CI/CD pipelines ensures each deployment meets security standards without requiring manual reauthorization."),
    Question(id: 1054, domain: 6, text: "An authorization package review reveals the SSP describes controls never actually implemented. The assessor labeled them satisfied based on SSP documentation alone without testing. This represents:", options: ["Both an SSP inaccuracy and an assessor independence failure", "An acceptable shortcut for low-risk controls", "Only an assessor error with no authorization impact", "Standard practice for inherited controls"], answer: 0, explain: "This is a compound failure: (1) the SSP inaccurately described unimplemented controls, and (2) the assessor failed to verify implementation through testing. The AO authorized based on a false picture of the system's security posture."),
    Question(id: 1055, domain: 6, text: "An organization has 200 information systems. To manage authorization efficiently, the BEST approach is:", options: ["Authorize every single one of the systems individually with no coordination", "Use common controls, inheritance, reciprocity, and impact-tiered rigor", "Authorize all 200 systems under one enterprise ATO", "Outsource all of the authorizations to a third party"], answer: 1, explain: "Authorization at scale requires efficiency mechanisms: common control inheritance, portfolio-level risk management, impact-tiered assessment rigor, and reciprocity — ensuring resources are applied proportionally to risk rather than treating all systems identically."),
    Question(id: 1057, domain: 6, text: "A system supporting classified operations requires authorization under CNSS policies. How does this differ from standard FISMA authorization?", options: ["There is no difference, because FISMA applies uniformly to all federal systems", "NSS use CNSSI 1253 and DoD/IC authorization processes that differ from RMF", "Classified systems require no formal authorization to operate at all", "Only FIPS 199 applies differently; all other steps are identical"], answer: 1, explain: "NSS are governed by CNSS (not FIPS 199/SP 800-53 directly) — CNSSI 1253 provides categorization and control selection. Authorization processes for NSS may follow IC or DoD-specific procedures beyond the standard NIST RMF."),
    Question(id: 1058, domain: 6, text: "A system owner discovers a vulnerability 2 days before a scheduled ATO expiration. The BEST action is:", options: ["Rush the reauthorization without addressing the vulnerability", "Wait until after reauthorization to disclose", "Fix it quietly without notifying the AO", "Disclose the vulnerability to the AO immediately"], answer: 3, explain: "Newly discovered vulnerabilities must always be disclosed to the AO — especially during authorization decisions. Concealing material security information from the AO invalidates any authorization granted based on incomplete information. The AO needs this for the reauthorization decision; concealing it would invalidate the new authorization."),
    Question(id: 1059, domain: 6, text: "A small federal agency lacks dedicated AO staff. The BEST acceptable solution is:", options: ["Skip the authorization process — small agencies are exempt", "Have the system owner self-authorize", "Use a contractor as the AO", "Designate a sufficiently senior official as AO and provide adequate support"], answer: 3, explain: "FISMA applies to all federal agencies regardless of size. Small agencies must designate an appropriately senior official as AO and can leverage shared services, common controls, and support staff — but cannot skip authorization. FISMA requires authorization regardless of agency size."),
    Question(id: 1061, domain: 6, text: "An AO who is also the system owner of the system they are authorizing presents which problem?", options: ["No problem — combined roles are more efficient", "Only an issue for HIGH-impact systems", "A fundamental conflict of interest", "Acceptable if approved by the CIO"], answer: 2, explain: "AO and system owner must be separate roles — the system owner advocates for their system, while the AO must objectively evaluate risk. Self-authorization removes this check and balance, undermining the RMF's accountability structure. The AO must be independent enough to objectively assess and accept risk; self-authorization undermines accountability."),
    Question(id: 1062, domain: 6, text: "When an agency plans to interconnect two separately authorized systems, authorization implications include:", options: ["No authorization impact — both systems already have ATOs", "Only the higher-impact system's AO needs to approve", "A single combined ATO is required for interconnected systems", "Both AOs must be notified and approve the interconnection"], answer: 3, explain: "Interconnections change each system's attack surface and risk posture. Both AOs must review and approve the connection through ISA/MOU — the new interface may introduce risks not contemplated in either system's original authorization. The new interface may change each system's risk posture beyond what was originally authorized."),
    Question(id: 1063, domain: 6, text: "A system undergoes a technology refresh replacing all hardware while keeping the same software and data. The authorization impact is:", options: ["No impact — only software matters for authorization", "Automatic re-authorization at the same level", "Only PE controls need to be reassessed", "Potentially significant"], answer: 3, explain: "Hardware replacement can affect physical controls (PE), configuration baselines (CM), boot security, and firmware integrity (SI-7). A security impact analysis determines whether the change warrants AO notification or reauthorization. New hardware may change control implementations and risk posture; a security impact analysis and AO notification are required."),
    Question(id: 1064, domain: 6, text: "The authorization boundary approved in the ATO must be maintained because:", options: ["It is only a planning artifact with no real significance", "It can be freely expanded without the AO's approval", "Only the ISSO needs to track any boundary changes", "Components outside the boundary are unauthorized"], answer: 3, explain: "The ATO specifically authorizes the system as bounded by its documented boundary. Any component operating outside that boundary is effectively unauthorized — creating unmanaged risk and potentially violating FISMA requirements."),
    Question(id: 1065, domain: 6, text: "A system receives its initial ATO with a 1-year period rather than the standard 3 years. This typically indicates:", options: ["The system is low impact and simpler to authorize", "A clerical error in the authorization letter", "Congressional oversight requirements", "The AO has concerns about residual risk or system maturity"], answer: 3, explain: "AOs can specify shorter authorization periods when they want earlier visibility into risk posture — often for new systems with immature security programs, high-risk environments, or significant open findings requiring close tracking. The shorter period provides an earlier opportunity to reassess whether risks have been adequately addressed."),
    Question(id: 1066, domain: 6, text: "When an AO grants authorization for a system, which stakeholders MUST receive formal notification of the decision?", options: ["Only the system owner of the newly authorized system", "Only the agency's Chief Information Officer, the CIO", "Only the agency's Chief Information Security Officer", "The system owner, ISSO, and security parties"], answer: 3, explain: "SP 800-37 requires formal communication of the authorization decision to all responsible parties — the system owner, ISSO, and other stakeholders who need to know the authorization status to fulfill their security responsibilities."),
    Question(id: 1067, domain: 6, text: "The key difference between modern 'authorization' and older 'accreditation' terminology is:", options: ["They are identical — just two different terms", "Accreditation applies to people while authorization applies to systems", "Authorization is federal; accreditation is private sector", "Authorization is continuous and risk-based, not a point-in-time cert"], answer: 3, explain: "The shift from accreditation (C&A under DITSCAP/DIACAP) to authorization (RMF) reflects a philosophical change — from periodic compliance snapshots to ongoing, risk-based security management integrated with continuous monitoring."),
    Question(id: 1068, domain: 6, text: "An AO reviews a system's authorization package and notices the privacy plan is missing entirely. The AO should:", options: ["Proceed — privacy plans are optional for most systems", "Accept verbal assurances from the Privacy Officer", "Add the privacy plan to the next reauthorization cycle", "Return the package"], answer: 3, explain: "OMB Circular A-130 explicitly requires a privacy plan as a component of the authorization package for systems processing PII. Its absence means the AO cannot evaluate privacy risks — the package is incomplete. Per OMB Circular A-130, the privacy plan is a required element of the authorization package for systems processing PII."),
    Question(id: 1069, domain: 6, text: "An organization's AO inherits responsibility for a system authorized 2 years ago by a predecessor. The incoming AO should:", options: ["Accept the predecessor's prior authorization as-is without any further review", "Issue an entirely new ATO immediately for the appearance of due diligence", "Delegate the authorization decision responsibility down to the system's ISSO", "Review the package, posture, and open POA&Ms, then reaffirm or modify"], answer: 3, explain: "AO transitions require the incoming official to consciously accept inherited risk — the prior AO's acceptance doesn't bind the new AO. A thorough review ensures the new AO makes an informed, affirmative decision."),
    Question(id: 1070, domain: 6, text: "A system processing AI/ML model training data requires which additional authorization consideration?", options: ["No additional considerations are needed, since AI/ML is just ordinary software", "Only that the trained model is independently tested for its predictive accuracy", "Only that the model's outputs are encrypted before they are returned to users", "Data quality and provenance risks like poisoning, inversion, and bias"], answer: 3, explain: "AI/ML systems introduce novel risks: adversarial training data, model inversion attacks, bias in outputs, and lack of explainability. Authorization must address these through tailored controls and risk acceptance, as standard baselines may not fully cover them."),
    Question(id: 1072, domain: 6, text: "When assessing risk posture for authorization, the AO considers 'mission impact' because:", options: ["Harm from failure is weighed against harm from denial", "Higher mission impact automatically lowers risk tolerance", "Mission impact is irrelevant — only technical risk counts", "Risk tolerance is set by the vendor"], answer: 0, explain: "Authorization is a risk-tradeoff decision: the AO weighs the risk of operating (security vulnerabilities) against the risk of NOT operating (mission failure). High mission impact may justify accepting greater residual security risk."),
    Question(id: 1073, domain: 6, text: "FedRAMP's continuous monitoring requirements for authorized CSPs include submitting which deliverable monthly?", options: ["A complete, full new security assessment report each month", "Monthly vulnerability scan results and an updated POA&M", "A brand-new SSP revision each month", "An updated POA&M only, nothing else"], answer: 1, explain: "FedRAMP ConMon requirements include monthly vulnerability scan results and POA&M updates from CSPs — providing agencies and the FedRAMP PMO with ongoing visibility into the CSP's security posture between annual assessments."),
    Question(id: 1074, domain: 6, text: "An AO approves a system's authorization based partly on the CSP's FedRAMP authorization for the infrastructure. If that FedRAMP authorization is later revoked, the agency ATO:", options: ["Remains fully valid — agency ATO is independent", "Is automatically extended by CISA", "Must be immediately renewed without additional review", "Must be re-evaluated"], answer: 3, explain: "Agency ATOs that rely on a CSP's FedRAMP authorization are partly dependent on it remaining valid. If that authorization is revoked, the agency AO must reassess whether the system's risk posture is still acceptable."),

    // ===== Blueprint rebalance: authored replacements (D2+4, D3+12, D7+26) =====
    // Domain 2 (Scope)
    Question(id: 1100, domain: 2, text: "A system owner is defining the boundary for a system that shares a database with a separately authorized system. The shared database should be:", options: ["Automatically included in both boundaries with no documentation", "Excluded from both systems simply because it is shared", "Governed by a documented ISA of responsibilities", "Assigned to whichever of the systems was authorized first"], answer: 2, explain: "Shared resources between separately authorized systems must be governed by a formal ISA/MOU defining control responsibilities, or be included within a common authorization."),
    Question(id: 1101, domain: 2, text: "An agency is categorizing a system that aggregates data from several sources. To determine the information types, the system owner should FIRST:", options: ["Simply ask the system's vendor which information types apply here", "Default every single information type to MODERATE for safety", "Identify each info type and map impacts via SP 800-60", "Use the single highest impact level available for all the data"], answer: 2, explain: "FIPS 199 categorization begins by identifying the information types the system handles, then mapping each to provisional impact values via SP 800-60 before applying the high-water mark."),
    Question(id: 1102, domain: 2, text: "A cloud-hosted system's authorization boundary documentation should explicitly capture:", options: ["All in-scope components and the responsibility split", "Only the customer-facing web interface part of the system", "Only the components physically located inside the US", "Nothing, since FedRAMP defines it"], answer: 0, explain: "For cloud systems the boundary must document all in-scope components and clearly delineate customer versus CSP responsibilities under the shared responsibility model."),
    Question(id: 1103, domain: 2, text: "During the RMF Prepare step, conducting a system-level risk assessment helps the organization:", options: ["Issue the system's authorization to operate considerably earlier than usual", "Skip the Categorize step of the RMF entirely", "Surface early risks that inform categorization and control selection", "Avoid having to document the authorization boundary"], answer: 2, explain: "The Prepare step's system-level risk assessment surfaces early risk context that informs categorization, control selection, and tailoring decisions throughout the RMF."),
    // Domain 3 (Selection and Approval of Controls)
    Question(id: 1110, domain: 3, text: "An organization selecting controls for a moderate-impact system wants to address a threat not covered by the baseline. The appropriate action is to:", options: ["Lower the system's categorization to avoid the gap", "Add controls or enhancements, noted in the SSP", "Ignore the threat because it is outside the baseline", "Wait until the assessment to deal with the new threat"], answer: 1, explain: "Baselines are a starting point. Organizations supplement them with additional controls or enhancements to address system-specific threats, documenting the rationale in the SSP."),
    Question(id: 1111, domain: 3, text: "A control in the moderate baseline contains an organization-defined parameter for minimum password length. The organization should:", options: ["Assign a specific value consistent with its risk tolerance and policy", "Leave it blank for the assessor to complete", "Use the vendor's default without review", "Copy another agency's value without analysis"], answer: 0, explain: "Organization-defined parameters (ODPs) require the organization to assign specific values consistent with its risk tolerance, policy, and operational environment."),
    Question(id: 1112, domain: 3, text: "A system inherits its audit-logging controls from an enterprise SIEM platform. In the SSP these controls should be documented as:", options: ["These are the system's own dedicated system-specific controls", "Compensating controls that substitute for other controls", "Not applicable", "Common (inherited) controls, naming the provider"], answer: 3, explain: "Controls provided by another entity and relied upon by the system are documented as common (inherited) controls, identifying the common control provider."),
    Question(id: 1113, domain: 3, text: "When tailoring a baseline for a system with no wireless capability, removing the wireless-specific controls is an example of:", options: ["Supplementing the baseline", "Adding an overlay", "Adding a compensating control", "Scoping based on applicability"], answer: 3, explain: "Scoping removes controls that are not applicable to the system's technology or environment, such as wireless controls on a system with no wireless capability."),
    Question(id: 1114, domain: 3, text: "An organization adopts the FedRAMP baseline for a cloud system. Relative to the standard SP 800-53B baseline, the FedRAMP baseline:", options: ["Removes all of the privacy controls from the baseline", "Replaces all the NIST controls with ISO controls instead", "Tailors the baseline for cloud, with new parameters", "Eliminates the need for a System Security Plan entirely"], answer: 2, explain: "The FedRAMP baseline is a tailored SP 800-53 baseline that adds and adjusts controls and parameters to address the unique risks of cloud environments serving federal agencies."),
    Question(id: 1115, domain: 3, text: "A privacy risk assessment during control selection finds that a system collects more PII than its function requires. The BEST control response aligns with which principle?", options: ["Data minimization — collect only the PII actually needed", "The broad security principle of layered defense in depth overall", "The principle of separation of duties among the staff roles involved", "The principle of non-repudiation"], answer: 0, explain: "Data minimization requires collecting and retaining only the PII necessary for the specified purpose, reducing privacy risk and the impact of any breach."),
    Question(id: 1116, domain: 3, text: "Which SP 800-53 control family would an organization select to embed security requirements into contracts with external software developers?", options: ["AC (Access Control)", "AU (Audit and Accountability)", "SA (System and Services Acquisition)", "PE (Physical and Environmental Protection)"], answer: 2, explain: "The SA family addresses incorporating security and privacy requirements into acquisitions, contracts, and the development life cycle, including developer security requirements."),
    Question(id: 1117, domain: 3, text: "A nonfederal contractor system processes Controlled Unclassified Information (CUI). Which publication primarily drives its security control requirements?", options: ["FIPS 199", "SP 800-137", "SP 800-88", "SP 800-171"], answer: 3, explain: "SP 800-171 specifies security requirements for protecting CUI in nonfederal systems and is invoked through DFARS and contractual obligations."),
    Question(id: 1118, domain: 3, text: "Reviewing and approving the security plan before assessment is important primarily because it:", options: ["It formally issues the system's authorization to operate directly to the system owner", "It confirms the selected controls are appropriate before implementation begins", "It serves as a complete and final replacement for the Security Assessment Report", "It eliminates the need for any POA&M"], answer: 1, explain: "Security plan review ensures stakeholders agree the selected controls are appropriate and complete before implementation effort begins, catching gaps early and reducing rework."),
    Question(id: 1119, domain: 3, text: "An organization wants higher-than-baseline assurance for a system facing advanced persistent threats. During control selection it should:", options: ["Apply control enhancements and a suitable overlay", "Lower the system's overall impact level to simplify it", "Remove baseline controls to simplify the operations", "Defer all decisions to the vendor"], answer: 0, explain: "Higher-assurance needs are met by applying control enhancements and overlays that strengthen the baseline, consistent with the organization's risk tolerance."),
    Question(id: 1120, domain: 3, text: "Allocating a control as 'hybrid' means:", options: ["It is fully inherited from a common control provider", "It is fully implemented by the system", "Part is provided as a common control and part is implemented by the system", "It is optional and need not be assessed"], answer: 2, explain: "A hybrid control has a common (inherited) portion and a system-specific portion; both parts must be documented and assessed."),
    Question(id: 1121, domain: 3, text: "Defining the continuous monitoring approach for each control during selection supports:", options: ["Skipping the formal independent security assessment of the system entirely", "Eliminating the system's POA&M", "Issuing a permanent, non-expiring ATO", "Sustaining control effectiveness and informing ongoing authorization"], answer: 3, explain: "Establishing how each control will be monitored during selection ensures controls remain effective over time and provides data to support ongoing authorization decisions."),
    // Domain 7 (Continuous Monitoring)
    Question(id: 1130, domain: 7, text: "An ISCM program collects vulnerability data daily but the team reviews it only monthly. For a system exposed to actively exploited vulnerabilities, this cadence is:", options: ["Perfectly appropriate for every system in the inventory", "Excessive, and the cadence should really be reduced further", "Irrelevant, because the scanning is automated", "Insufficient — review must match the threat velocity"], answer: 3, explain: "SP 800-137 requires monitoring and review frequencies calibrated to risk. Actively exploited vulnerabilities demand near-real-time review and response, not a monthly cycle."),
    Question(id: 1131, domain: 7, text: "According to SP 800-137, the FIRST step in establishing an ISCM capability is to:", options: ["Purchase a commercial SIEM platform for the program", "Define the ISCM strategy tied to risk tolerance", "Begin scanning every one of the systems immediately", "Issue the information system its authorization to operate"], answer: 1, explain: "The SP 800-137 process begins with defining an ISCM strategy that establishes metrics, frequencies, and governance aligned to organizational risk tolerance before implementation."),
    Question(id: 1132, domain: 7, text: "A significant change is proposed to an authorized system. Before implementation the organization should:", options: ["Deploy it first and then document it afterward", "Automatically request a full system reassessment", "Notify only the vendor", "Run a security impact analysis on the change"], answer: 3, explain: "Significant changes require a security impact analysis through the change management process to determine whether the change affects the authorized risk posture."),
    Question(id: 1133, domain: 7, text: "A ConMon dashboard shows 30% of systems with critical patches overdue beyond the remediation window. This finding should be:", options: ["Escalated to the CISO and AOs as a systemic gap", "Ignored as long as no actual incidents have occurred yet", "Logged without any escalation at all", "Resolved quietly by the IT team"], answer: 0, explain: "Systemic failure to meet remediation timelines is an organization-level risk issue requiring CISO and AO escalation to drive resources and corrective action."),
    Question(id: 1134, domain: 7, text: "Ongoing authorization is enabled primarily by:", options: ["Completely eliminating the entire authorizing official role", "A mature ConMon program keeping AO awareness fresh", "Reducing the number of implemented security controls", "Performing only an annual reauthorization of the system"], answer: 1, explain: "Ongoing authorization replaces fixed reauthorization cycles with continuous monitoring that supplies the AO timely risk information for near-real-time decisions."),
    Question(id: 1135, domain: 7, text: "During decommissioning, media that stored MODERATE-impact data should be sanitized using which SP 800-88 method as a minimum?", options: ["Clear only", "Purge, or Destroy for higher-assurance situations", "No sanitization is required", "A single quick reformat"], answer: 1, explain: "SP 800-88 generally recommends Purge (or Destroy) for moderate and high impact data so that recovery is infeasible even with laboratory techniques."),
    Question(id: 1136, domain: 7, text: "Configuration drift causes a control previously assessed as 'satisfied' to fail. The BEST response is to:", options: ["Simply wait until the next regularly scheduled assessment", "Remove the affected control from the System Security Plan", "Log it in the POA&M, fix it, and notify the AO if needed", "Disable the continuous monitoring for that particular control"], answer: 2, explain: "Control failures found during ConMon must be documented in the POA&M, remediated, and reported to the AO when they materially affect the authorized risk posture."),
    Question(id: 1137, domain: 7, text: "A cloud service provider used by an agency suffers a data breach. Under the RMF Monitor step the agency should FIRST:", options: ["Immediately cancel the cloud service provider's contract outright", "Activate IR, assess agency data impact, and notify the AO/CISA", "Wait for the provider's complete final report before taking any action", "Revoke the system's ATO with no analysis"], answer: 1, explain: "A CSP breach affecting agency data triggers incident response: assess agency data exposure, notify the AO whose risk acceptance may be affected, and report per federal requirements."),
    Question(id: 1138, domain: 7, text: "Key Risk Indicators (KRIs) are valuable in a ConMon program because they:", options: ["Forward-looking signals of rising risk", "They replace the need for vulnerability scanning entirely", "They are completely identical to the POA&M entries", "They measure only the past incidents that occurred"], answer: 0, explain: "KRIs are predictive metrics — such as rising unpatched critical vulnerabilities — that warn of growing risk before it materializes into an incident."),
    Question(id: 1139, domain: 7, text: "An organization automates configuration compliance scanning using SCAP-based tools. This primarily supports:", options: ["Issuing the information system's authorization to operate", "Continuous checks that systems match the baseline", "Serving as a full replacement for the SSP document", "Eliminating the change control board"], answer: 1, explain: "SCAP-based scanning continuously checks deployed configurations against approved secure baselines, a core ConMon activity supporting CM-6 and CA-7."),
    Question(id: 1140, domain: 7, text: "When a new regulation changes a system's data-handling requirements, the ConMon strategy should be:", options: ["Left unchanged until the next ATO", "Deleted and restarted", "Reviewed and updated to incorporate the new requirements", "Ignored unless an incident occurs"], answer: 2, explain: "Legal and regulatory changes drive updates to the monitoring strategy, control set, and documentation; ignoring them creates compliance and authorization gaps."),
    Question(id: 1141, domain: 7, text: "The 'respond' component of the SP 800-137 ISCM process includes:", options: ["Remediation, configuration changes, escalation, and POA&M updates", "Only applying the necessary software and firmware patches to systems", "Only reporting the findings to the AO", "Only updating the System Security Plan"], answer: 0, explain: "ISCM response encompasses all actions taken on findings — technical remediation, configuration changes, escalation to incident response, AO notification, and POA&M updates."),
    Question(id: 1142, domain: 7, text: "A system's ATO is nearing expiration and no reauthorization or ongoing-authorization process is in place. The system owner should:", options: ["Continue operating the system indefinitely without any action", "Assume that the authorization simply renews itself automatically", "Shut the entire system down immediately without any notice", "Begin reauthorization well before the ATO expires"], answer: 3, explain: "Operating past an authorization expiration without reauthorization or a documented ongoing authorization is a FISMA compliance gap; reauthorization must begin in advance."),
    Question(id: 1143, domain: 7, text: "Reviewing audit logs for anomalies during continuous monitoring most directly implements which control?", options: ["CM-2 (Baseline Configuration)", "AU-6 (Audit Record Review, Analysis, and Reporting)", "PE-3 (Physical Access Control)", "CP-9 (System Backup)"], answer: 1, explain: "AU-6 requires reviewing and analyzing audit records for unusual activity and reporting findings; log review during ConMon directly implements it."),
    Question(id: 1144, domain: 7, text: "An organization runs an annual tabletop exercise of its incident response plan. This ConMon activity primarily validates:", options: ["The cryptographic strength of the system's chosen encryption algorithm", "The raw network throughput across the entire production environment", "Response procedures, roles, and decisions before a real incident", "The system's FIPS 199 categorization"], answer: 2, explain: "Tabletop exercises walk personnel through a scenario to test procedures, roles, and decision-making, revealing gaps before an actual incident occurs."),
    Question(id: 1145, domain: 7, text: "Decommissioning a system that has external interconnections requires FIRST:", options: ["Shut the entire system down abruptly without warning", "Publicly archive all of the system's data for reuse", "Issue a brand-new ATO for the remaining systems", "Notify connected owners and terminate the ISAs"], answer: 3, explain: "Abruptly severing interconnections can break dependent systems and violate formal agreements; decommissioning must begin by notifying partners and terminating ISAs."),
    Question(id: 1146, domain: 7, text: "A SIEM correlating logs across the enterprise supports continuous monitoring by:", options: ["Making the AO's risk decision fully automatically for them", "Eliminating the need for security policies", "Timely detection of anomalies for situational awareness", "Automating all remediation with no review"], answer: 2, explain: "A SIEM aggregates and correlates logs to detect anomalies and attacks in near real time, sustaining the situational awareness that ISCM exists to provide."),
    Question(id: 1147, domain: 7, text: "An ISCM strategy should calibrate each control's monitoring frequency based on:", options: ["A single fixed interval applied to all controls", "Control volatility and the potential impact if the control fails", "The vendor's recommendation alone", "The calendar year only"], answer: 1, explain: "SP 800-137 calibrates monitoring frequency to risk: more volatile and higher-impact controls warrant more frequent monitoring than stable, low-impact controls."),
    Question(id: 1148, domain: 7, text: "During continuous monitoring, who determines whether a proposed system change is significant enough to require a security impact analysis?", options: ["The vendor that supplied the changed component", "The system owner, in coordination with the ISSO", "Any end user who first notices the change", "The external assessor, acting on their own"], answer: 1, explain: "In the Monitor step (SP 800-37 Rev 2), the system owner with the ISSO evaluates proposed changes through configuration management and performs a security impact analysis to decide whether reassessment or re-authorization is warranted."),
    Question(id: 1149, domain: 7, text: "The risk register should be updated during continuous monitoring when:", options: ["Only during the formally scheduled annual program review meetings each year", "New risks emerge or existing risks change from incidents or changes", "Only when the AO specifically requests it", "Only at the time of reauthorization"], answer: 1, explain: "The risk register is a living document that must reflect new and changed risks as they arise to maintain accurate situational awareness for risk decisions."),
    Question(id: 1150, domain: 7, text: "An organization adopts DevSecOps with automated security gates in its CI/CD pipeline. This supports continuous monitoring by:", options: ["Eliminating the entire need for any monitoring whatsoever", "Serving as a full replacement for the System Security Plan", "Validating each deployment's security before release", "Removing the change control board"], answer: 2, explain: "Automated security gates (SAST, DAST, configuration and compliance checks) in CI/CD provide near-continuous security validation that complements ISCM goals."),
    Question(id: 1151, domain: 7, text: "A vulnerability scan flags a finding the team confirms does not exist in their environment. This is a:", options: ["A false positive to verify before recording", "A false negative that hides a real underlying risk", "A critical finding that requires an immediate shutdown", "A good reason to discontinue all scanning entirely"], answer: 0, explain: "A false positive is a reported vulnerability that is not actually present; assessors verify scanner output before recording it as a real finding."),
    Question(id: 1152, domain: 7, text: "The Security Status Report delivered to the AO during continuous monitoring primarily serves to:", options: ["Serve as a replacement for the Security Assessment Report", "Keep the AO's risk awareness current for decisions", "Document all of the completed end-user security training", "Satisfy the system vendor"], answer: 1, explain: "Security Status Reports give the AO current posture information so the original risk acceptance can be confirmed or revisited under ongoing authorization."),
    Question(id: 1153, domain: 7, text: "Media sanitization during system disposal is governed primarily by which publication?", options: ["FIPS 199", "SP 800-30", "SP 800-60", "SP 800-88"], answer: 3, explain: "SP 800-88 (Guidelines for Media Sanitization) defines the Clear, Purge, and Destroy methods used to sanitize media before disposal or reuse."),
    Question(id: 1154, domain: 7, text: "After incorporating lessons learned from a security incident, the organization should:", options: ["Brief the AO and update procedures, strategy, and documents", "Keep all of the resulting changes internal to the security team", "Update only the next annual training plan", "Wait a year before assessing the changes"], answer: 0, explain: "Lessons learned close the feedback loop; the AO should be briefed and procedures, strategy, and documentation updated to prevent recurrence."),
    Question(id: 1155, domain: 7, text: "The most important output of an effective continuous monitoring program is:", options: ["The largest possible number of collected metrics", "Timely, accurate situational awareness that enables risk-based decisions", "A comprehensive compliance binder", "Documentation of tool licenses and subscriptions"], answer: 1, explain: "ConMon exists to support decisions; its key output is current, accurate situational awareness enabling the AO and security team to act on risk in near real time."),

